function prepareSourceSelection($context, $sources_by_group, $accessible_sources, $selected_organism = '', $assembly_param = '', $organisms_param = []) {
    // Initialize result with defaults
    $result = [
        'filter_organisms' => [],
        'selected_source' => '',
        'selected_organism' => $selected_organism,
        'selected_assembly_accession' => '',
        'selected_assembly_name' => '',
        'should_auto_select' => true,
        'context_group' => $context['group'] ?? ''
    ];

    // Initialize filter_organisms from multi-organism parameter (if present)
    $filter_organisms = [];
    if (is_array($organisms_param) && !empty($organisms_param)) {
        $filter_organisms = array_filter($organisms_param);
    }

    // Process assembly parameter - match by directory, genome_name, or accession
    $selected_assembly_accession = '';
    $selected_assembly_name = '';
    if (!empty($assembly_param)) {
        foreach ($accessible_sources as $source) {
            if (empty($selected_organism) || $source['organism'] === $selected_organism) {
                // Match by assembly directory, genome_name, or genome_accession
                $matches = false;
                if ($source['assembly'] === $assembly_param) {
                    $matches = true;
                } elseif ($source['genome_name'] === $assembly_param) {
                    $matches = true;
                } elseif ($source['genome_accession'] === $assembly_param) {
                    $matches = true;
                }

                if ($matches) {
                    $selected_assembly_accession = $source['assembly'];
                    // Always use genome_name for display (use assembly as fallback)
                    $selected_assembly_name = $source['genome_name'] ?? $source['assembly'];
                    if (empty($selected_organism)) {
                        $selected_organism = $source['organism'];
                    }
                    break;
                }
            }
        }
    }

    // Build filter_organisms list based on priority (assembly > organism > group > multi-organism)
    if (!empty($selected_assembly_name)) {
        // Case 1: Filter by assembly (only show organism containing this assembly)
        $filter_organisms = [];
        foreach ($accessible_sources as $source) {
            if (($source['genome_name'] === $selected_assembly_name || $source['assembly'] === $selected_assembly_accession) && 
                !in_array($source['organism'], $filter_organisms)) {
                $filter_organisms[] = $source['organism'];
            }
        }
    } elseif (!empty($selected_organism)) {
        // Case 2: Filter by organism if no assembly specified
        if (empty($filter_organisms)) {
            $filter_organisms = [$selected_organism];
        }
    } elseif (!empty($context['group'])) {
        // Case 3: Filter by group if only group specified
        $filter_organisms = [];
        if (isset($sources_by_group[$context['group']])) {
            foreach ($sources_by_group[$context['group']] as $organism => $assemblies) {
                $filter_organisms[] = $organism;
            }
        }
        // Don't auto-select when only group is specified - let user choose
        $result['should_auto_select'] = false;
    }
    // else: Case 4 - multi-organism list from ?organisms[] is preserved if no assembly/organism/group specified

    // Determine selected source
    $only_group_specified = !empty($context['group']) && empty($selected_organism) && empty($assembly_param);
    $only_multi_organism_specified = !empty($organisms_param) && empty($selected_organism) && empty($assembly_param) && empty($context['group']);

    if ($only_group_specified) {
        // Case 3: Group specified only - don't auto-select, let user choose from filtered group
        $result['selected_source'] = '';
        $result['selected_organism'] = '';
        $result['selected_assembly_accession'] = '';
        $result['selected_assembly_name'] = '';
        $result['should_auto_select'] = false;
    } elseif ($only_multi_organism_specified) {
        // Case 4: Multiple organisms specified - don't auto-select, let user choose from filtered list
        $result['selected_source'] = '';
        $result['selected_organism'] = '';
        $result['selected_assembly_accession'] = '';
        $result['selected_assembly_name'] = '';
        $result['should_auto_select'] = false;
    } else {
        // Cases 1 & 2: Assembly or single organism specified - use existing logic to auto-select
        $selection_result = determineSelectedSource(
            $context,
            $filter_organisms,
            $accessible_sources,
            $selected_organism,
            $selected_assembly_accession
        );
        $result['selected_source'] = $selection_result['selected_source'];
        $result['selected_organism'] = $selection_result['selected_organism'];
        $result['selected_assembly_accession'] = $selection_result['selected_assembly_accession'];

        // Determine which name to use for filter display
        if (!empty($assembly_param)) {
            // Case 1: Assembly specified - always use the assembly_name (genome_name)
            // It was already set on lines 55-76 when we looked up the assembly
            $result['selected_assembly_name'] = $selected_assembly_name;
        } elseif (!empty($selected_organism)) {
            // Case 2: Organism specified without assembly - show organism name
            $result['selected_assembly_name'] = '';
        } else {
            // Fallback: use what determineSelectedSource returned
            $result['selected_assembly_name'] = $selection_result['selected_assembly_name'];
        }
    }

    $result['filter_organisms'] = $filter_organisms;
    return $result;
}

function indexTraverseTree(array $node, array $chain = []): array {
    $path = array_merge($chain, [$node['name']]);
    $out  = [];
    if (isset($node['organism'])) {
        $out[] = [
            'organism'    => $node['organism'],
            'display_name'=> $node['name'],
            'common_name' => $node['common_name'] ?? '',
            'taxon_chain' => array_slice($path, 0, -1), // ancestors only, not the leaf
        ];
    }
    foreach ($node['children'] ?? [] as $child) {
        $out = array_merge($out, indexTraverseTree($child, $path));
    }
    return $out;
}

function getBlastDatabases($assembly_path) {
    $databases = [];

    if (!is_dir($assembly_path)) {
        return $databases;
    }

    $sequence_types = ConfigManager::getInstance()->getArray('sequence_types');

    // Map sequence types to database info
    $type_mapping = [
        'protein' => ['name' => 'Protein', 'blast_type' => 'protein'],
        'cds' => ['name' => 'CDS', 'blast_type' => 'nucleotide'],
        'transcript' => ['name' => 'Transcript', 'blast_type' => 'nucleotide'],
    ];

    // Check for each configured sequence type
    if (!empty($sequence_types)) {
        foreach ($sequence_types as $seq_type => $config) {
            $pattern = $config['pattern'] ?? '';
            if (empty($pattern)) {
                continue;
            }

            $file_path = "$assembly_path/$pattern";
            $type_info = $type_mapping[$seq_type] ?? ['name' => ucfirst($seq_type), 'blast_type' => 'nucleotide'];

            // Accept if FASTA exists OR if a BLAST index exists (FASTA may have been removed after indexing)
            $idx_ext = $type_info['blast_type'] === 'protein' ? '.pin' : '.nin';
            if (!file_exists($file_path) && !file_exists($file_path . $idx_ext)) {
                // Gene sets live one level below the assembly dir — check parent for assembly-level files (e.g. genome.fa)
                $parent_path = dirname($assembly_path) . "/$pattern";
                if (file_exists($parent_path) || file_exists($parent_path . $idx_ext)) {
                    $file_path = $parent_path;
                }
            }
            if (file_exists($file_path) || file_exists($file_path . $idx_ext)) {
                $databases[] = [
                    'name'     => $type_info['name'],
                    'path'     => $file_path,
                    'type'     => $type_info['blast_type'],
                    'seq_type' => $seq_type,
                ];
            }
        }
    }

    return $databases;
}

function filterDatabasesByProgram($databases, $blast_program) {
    $filtered = [];

    // Determine which database types are compatible with the program
    $compatible_types = [];
    switch ($blast_program) {
        case 'blastn':
        case 'blastn-short':
        case 'tblastn':
        case 'tblastx':
            $compatible_types = ['nucleotide'];
            break;
        case 'blastp':
        case 'blastx':
            $compatible_types = ['protein'];
            break;
        default:
            return $databases; // Unknown program, return all
    }

    foreach ($databases as $db) {
        if (in_array($db['type'], $compatible_types)) {
            $filtered[] = $db;
        }
    }

    return $filtered;
}

function executeBlastSearch($query_seq, $blast_db, $program, $options = []) {
    $result = [
        'success' => false,
        'output' => '',
        'error' => '',
        'stderr' => ''
    ];

    // Validate inputs
    if (empty($query_seq) || empty($blast_db) || empty($program)) {
        $result['error'] = 'Missing required parameters for BLAST search';
        return $result;
    }

    // Verify database exists - check for any of the BLAST index files
    $has_index = false;
    if (file_exists("$blast_db.nhr") || file_exists("$blast_db.phr") || 
        file_exists("$blast_db.ndb") || file_exists("$blast_db.pdb")) {
        $has_index = true;
    }

    if (!$has_index) {
        $result['error'] = 'BLAST database not found: ' . basename($blast_db);
        return $result;
    }

    // Set default options
    $evalue = $options['evalue'] ?? '1e-3';
    $max_hits = (int)($options['max_hits'] ?? 10);
    $matrix = $options['matrix'] ?? 'BLOSUM62';
    $filter = $options['filter'] ? 'yes' : 'no';
    $task = $options['task'] ?? '';

    // Create temporary directory for ASN.1 archive output
    $temp_dir = sys_get_temp_dir();
    $archive_file = tempnam($temp_dir, 'blast_');

    if ($archive_file === false) {
        $result['error'] = 'Failed to create temporary file for BLAST output';
        return $result;
    }

    // Build BLAST command with outfmt 11 (ASN.1)
    // Get configured BLAST tool path
    $config = ConfigManager::getInstance();
    $blast_tools = $config->getArray('blast_tools', []);
    $program_path = $blast_tools[$program] ?? $program;
    $num_threads = (int)$config->getString('blast_num_threads', '2');
    if ($num_threads < 1) $num_threads = 1;

    $cmd = [];
    $cmd[] = $program_path;
    // Use absolute path for database
    // For BLAST databases, we pass the base name and BLAST appends the extensions
    $db_dir = dirname($blast_db);
    $db_base = basename($blast_db);
    $db_path = realpath($db_dir);
    if (!$db_path) {
        unlink($archive_file);
        $result['error'] = 'Cannot resolve database path: ' . $blast_db;
        return $result;
    }
    $full_db_path = $db_path . '/' . $db_base;
    $cmd[] = '-db ' . escapeshellarg($full_db_path);
    $cmd[] = '-evalue ' . escapeshellarg($evalue);
    $cmd[] = '-num_descriptions ' . escapeshellarg($max_hits);
    $cmd[] = '-num_alignments ' . escapeshellarg($max_hits);
    $cmd[] = '-num_threads ' . $num_threads;
    $cmd[] = '-outfmt 11';
    $cmd[] = '-out ' . escapeshellarg($archive_file);

    // Add program-specific options
    if ($program === 'blastn') {
        $cmd[] = '-dust ' . escapeshellarg($filter);
    } elseif ($program === 'tblastn') {
        $cmd[] = '-seg ' . escapeshellarg($filter);
    } elseif (in_array($program, ['blastp', 'blastx', 'tblastx'])) {
        $cmd[] = '-seg ' . escapeshellarg($filter);
        $cmd[] = '-matrix ' . escapeshellarg($matrix);
    }

    // Add task if specified
    if (!empty($task)) {
        $cmd[] = '-task ' . escapeshellarg($task);
    }

    $command = 'printf ' . escapeshellarg($query_seq) . ' | ' . implode(' ', $cmd);

    // Execute BLAST with proc_open for better control
    $descriptors = [
        0 => ["pipe", "r"],
        1 => ["pipe", "w"],
        2 => ["pipe", "w"],
    ];

    $process = proc_open($command, $descriptors, $pipes);
    if (!is_resource($process)) {
        unlink($archive_file);
        $result['error'] = 'Failed to execute BLAST command';
        return $result;
    }

    fclose($pipes[0]);
    $blast_stdout = stream_get_contents($pipes[1]);
    fclose($pipes[1]);
    $blast_stderr = stream_get_contents($pipes[2]);
    fclose($pipes[2]);
    $return_code = proc_close($process);

    if ($return_code !== 0) {
        unlink($archive_file);
        $result['error'] = 'BLAST execution failed with code ' . $return_code;
        $result['stderr'] = $blast_stderr;
        return $result;
    }

    // Convert ASN.1 archive to outfmt 5 (XML) using blast_formatter
    $xml_file = tempnam($temp_dir, 'blast_xml_');
    $blast_formatter_path = $blast_tools['blast_formatter'] ?? 'blast_formatter';
    $formatter_cmd = $blast_formatter_path . ' -archive ' . escapeshellarg($archive_file) . 
                     ' -outfmt 5 -out ' . escapeshellarg($xml_file);

    $process = proc_open($formatter_cmd, $descriptors, $pipes);
    if (!is_resource($process)) {
        unlink($archive_file);
        $result['error'] = 'Failed to execute blast_formatter for XML';
        return $result;
    }

    fclose($pipes[0]);
    fclose($pipes[1]);
    fclose($pipes[2]);
    $return_code = proc_close($process);

    if ($return_code !== 0) {
        unlink($archive_file);
        unlink($xml_file);
        $result['error'] = 'blast_formatter XML conversion failed with code ' . $return_code;
        return $result;
    }

    // Read the XML output
    $output = file_get_contents($xml_file);

    // Now convert ASN.1 archive to outfmt 0 (Pairwise text) for download
    $pairwise_file = tempnam($temp_dir, 'blast_pairwise_');
    $formatter_cmd = $blast_formatter_path . ' -archive ' . escapeshellarg($archive_file) . 
                     ' -outfmt 0 -out ' . escapeshellarg($pairwise_file);

    $process = proc_open($formatter_cmd, $descriptors, $pipes);
    if (!is_resource($process)) {
        unlink($archive_file);
        unlink($xml_file);
        unlink($pairwise_file);
        $result['error'] = 'Failed to execute blast_formatter for pairwise';
        return $result;
    }

    fclose($pipes[0]);
    fclose($pipes[1]);
    fclose($pipes[2]);
    $return_code = proc_close($process);

    if ($return_code !== 0) {
        unlink($archive_file);
        unlink($xml_file);
        unlink($pairwise_file);
        $result['error'] = 'blast_formatter pairwise conversion failed with code ' . $return_code;
        return $result;
    }

    // Read the pairwise output
    $pairwise_output = file_get_contents($pairwise_file);
    unlink($pairwise_file);

    // Convert ASN.1 archive to outfmt 6 (tabular) with stitle for TSV download
    $tabular_output = '';
    $tabular_file = tempnam($temp_dir, 'blast_tabular_');
    $tabular_fmt = '6 qseqid sseqid pident length mismatch gapopen qstart qend sstart send evalue bitscore stitle';
    $formatter_cmd = $blast_formatter_path . ' -archive ' . escapeshellarg($archive_file) .
                     ' -outfmt ' . escapeshellarg($tabular_fmt) . ' -out ' . escapeshellarg($tabular_file);
    $process = proc_open($formatter_cmd, $descriptors, $pipes);
    if (is_resource($process)) {
        fclose($pipes[0]);
        fclose($pipes[1]);
        fclose($pipes[2]);
        $return_code = proc_close($process);
        if ($return_code === 0) {
            $header = "# qseqid\tsseqid\tpident\tlength\tmismatch\tgapopen\tqstart\tqend\tsstart\tsend\tevalue\tbitscore\tstitle\n";
            $tabular_output = $header . file_get_contents($tabular_file);
        }
    }
    unlink($tabular_file);

    // Clean up temporary files
    unlink($archive_file);
    unlink($xml_file);

    $result['success'] = true;
    $result['output']   = $output;
    $result['pairwise'] = $pairwise_output;
    $result['tabular']  = $tabular_output;
    $result['stderr']   = $blast_stderr;

    return $result;
}

function extractSequencesFromBlastDb($blast_db, $sequence_ids, $organism = '', $assembly = '', $ranges = [], $original_input_ids = [], $parent_to_children = []) {
    $result = [
        'success' => false,
        'content' => '',
        'error' => ''
    ];

    if (empty($sequence_ids) || !is_array($sequence_ids)) {
        $result['error'] = 'No sequence IDs provided';
        return $result;
    }

    if (!file_exists($blast_db . '.nhr') && !file_exists($blast_db . '.phr')) {
        $result['error'] = 'BLAST database not found';
        return $result;
    }

    // Check if $ranges is provided and not empty
    if (!empty($ranges)) {
        // Use batch mode with range file
        // Convert ranges from "ID:start-end" format to "ID start-end" format for blastdbcmd
        $batch_ranges = array_map(function($range) {
            // Convert "ID:start-end" or "ID:start-end" to "ID start-end"
            return preg_replace('/^([^:]+):(\d+-\d+)$/', '$1 $2', $range);
        }, $ranges);

        // Build batch entries: converted ranges + regular IDs as full sequences
        // Ranges apply to parent AND all children
        $ids_with_ranges = array_map(function($range) {
            return explode(':', $range)[0];
        }, $ranges);

        // For each ranged ID, find and add all its children with the same range
        $expanded_ranges = [];
        foreach ($batch_ranges as $range_entry) {
            $expanded_ranges[] = $range_entry; // Add the original range

            // Extract the ID and range portion from "ID start-end"
            if (preg_match('/^(.+?)\s+(\d+-\d+)$/', $range_entry, $matches)) {
                $parent_id = $matches[1];
                $range_portion = $matches[2];

                // Find all children of this parent in sequence_ids and add with same range
                foreach ($sequence_ids as $id) {
                    // Check if this ID is a child of parent_id (e.g., "ID.1", "ID.2")
                    if (preg_match('/^' . preg_quote($parent_id) . '\.\d+$/', $id)) {
                        $expanded_ranges[] = "$id $range_portion";
                    }
                }
            }
        }

        // Build batch file following the 4-step plan:
        // 1. Add all no-range input IDs (as full sequences)
        // 2. Add all children of input IDs with no ranges (as full sequences)
        // 3. Add all input IDs with ranges (with range formatting)
        // 4. Add all children of input IDs with ranges (with same ranges as parent)

        $batch_entries = [];

        // Separate original input IDs into those with and without ranges
        $input_ids_with_ranges = [];
        $input_ids_no_ranges = [];

        foreach ($original_input_ids as $id) {
            $has_range = false;
            foreach ($ranges as $range_entry) {
                $range_id = explode(':', $range_entry)[0];
                $range_id = explode(' ', $range_id)[0];
                if ($range_id === $id) {
                    $has_range = true;
                    break;
                }
            }
            if ($has_range) {
                $input_ids_with_ranges[] = $id;
            } else {
                $input_ids_no_ranges[] = $id;
            }
        }

        // Step 1: Add all no-range input IDs (full sequences)
        foreach ($input_ids_no_ranges as $id) {
            if (in_array($id, $sequence_ids)) {
                $batch_entries[] = $id;
            }
        }

        // Step 2: Add all children of input IDs with no ranges (full sequences)
        foreach ($input_ids_no_ranges as $parent_id) {
            if (isset($parent_to_children[$parent_id])) {
                foreach ($parent_to_children[$parent_id] as $child_id) {
                    if (in_array($child_id, $sequence_ids)) {
                        $batch_entries[] = $child_id;
                    }
                }
            }
        }

        // Step 3: Add all input IDs with ranges (formatted as "ID range")
        foreach ($input_ids_with_ranges as $id) {
            // Find the corresponding converted range in $batch_ranges
            foreach (array_keys($ranges) as $idx) {
                $range_id = explode(':', $ranges[$idx])[0];
                $range_id = explode(' ', $range_id)[0];
                if ($range_id === $id) {
                    // Use the converted batch_ranges entry (with space, not colon)
                    $batch_entries[] = $batch_ranges[$idx];
                    break;
                }
            }
        }

        // Step 4: Add all children of input IDs with ranges (with same ranges as parent)
        foreach ($input_ids_with_ranges as $parent_id) {
            if (isset($parent_to_children[$parent_id])) {
                // Find the range for this parent
                $parent_range = '';
                foreach ($ranges as $range_entry) {
                    $range_id = explode(':', $range_entry)[0];
                    $range_id = explode(' ', $range_id)[0];
                    if ($range_id === $parent_id) {
                        // Extract range portion
                        $parent_range = strpos($range_entry, ':') !== false ? 
                            explode(':', $range_entry)[1] : 
                            explode(' ', $range_entry)[1];
                        break;
                    }
                }

                // Add each child with same range
                if (!empty($parent_range)) {
                    foreach ($parent_to_children[$parent_id] as $child_id) {
                        if (in_array($child_id, $sequence_ids)) {
                            $batch_entries[] = "$child_id $parent_range";
                        }
                    }
                }
            }
        }

        $temp_file = tempnam(sys_get_temp_dir(), 'blastdb_');
        if ($temp_file === false) {
            $result['error'] = 'Failed to create temporary file for batch processing';
            return $result;
        }

        // Write batch entries to temporary file
        if (file_put_contents($temp_file, implode("\n", $batch_entries)) === false) {
            @unlink($temp_file);
            $result['error'] = 'Failed to write batch file for range extraction';
            return $result;
        }

        // Execute: blastdbcmd -db ... -entry_batch temp_file
        $config = ConfigManager::getInstance();
        $blast_tools = $config->getArray('blast_tools', []);
        $blastdbcmd_path = $blast_tools['blastdbcmd'] ?? 'blastdbcmd';
        $cmd = $blastdbcmd_path . " -db " . escapeshellarg($blast_db) . " -entry_batch " . escapeshellarg($temp_file) . " 2>&1";

        $output = [];
        $return_var = 0;
        @exec($cmd, $output, $return_var);

        // Delete temp file after execution
        @unlink($temp_file);

        // Filter out blastdbcmd error messages (lines starting with "Error:")
        // BUT keep track of them for better error reporting
        $error_lines = array_filter($output, function($line) {
            return strpos(trim($line), 'Error:') === 0;
        });

        $output = array_filter($output, function($line) {
            return strpos(trim($line), 'Error:') !== 0;
        });

        // Check if blastdbcmd executed
        if ($return_var > 1) {
            $result['error'] = "Error extracting sequences (exit code: $return_var). Ensure blastdbcmd is installed and FASTA files are formatted correctly.";
            return $result;
        }

        // Check if we got any output
        if (empty($output)) {
            // If there were error messages about entries not found, it's likely an out-of-range coordinate
            if (!empty($error_lines)) {
                $result['error'] = 'One or more requested sequences or ranges were not found. This may be due to: (1) invalid sequence ID, (2) out-of-range coordinates, or (3) incorrectly formatted FASTA database. Please verify your input.';
            } else {
                $result['error'] = 'No sequences found for the requested IDs and ranges';
            }
            return $result;
        }
    } else {
        // No ranges - use current logic: Execute: blastdbcmd -db ... -entry IDs
        $config = ConfigManager::getInstance();
        $blast_tools = $config->getArray('blast_tools', []);
        $blastdbcmd_path = $blast_tools['blastdbcmd'] ?? 'blastdbcmd';
        $ids_string = implode(',', $sequence_ids);
        $cmd = $blastdbcmd_path . " -db " . escapeshellarg($blast_db) . " -entry " . escapeshellarg($ids_string) . " 2>/dev/null";
        $output = [];
        $return_var = 0;
        @exec($cmd, $output, $return_var);

        // Filter out blastdbcmd error messages (lines starting with "Error:")
        $output = array_filter($output, function($line) {
            return strpos(trim($line), 'Error:') !== 0;
        });

        // Check if blastdbcmd executed
        if ($return_var > 1) {
            // Return code 1 is expected when some IDs don't exist, but >1 is an error
            $result['error'] = "Error extracting sequences (exit code: $return_var). Ensure blastdbcmd is installed and FASTA files are formatted correctly.";
            return $result;
        }

        // Check if we got any output
        if (empty($output)) {
            $result['error'] = 'No sequences found for the requested IDs';
            return $result;
        }
    }

    $result['success'] = true;
    $result['content'] = implode("\n", $output);

    return $result;
}

function validateBlastSequence($sequence) {
    $sequence = trim($sequence);

    if (empty($sequence)) {
        return ['valid' => false, 'error' => 'Sequence is empty'];
    }

    // If sequence doesn't start with >, add a header
    if ($sequence[0] !== '>') {
        $sequence = ">query_sequence\n" . $sequence;
    }

    // Basic FASTA format validation
    $lines = explode("\n", $sequence);
    $in_header = true;
    $seq_count = 0;

    foreach ($lines as $line) {
        $line = trim($line);
        if (empty($line)) {
            continue;
        }

        if ($line[0] === '>') {
            if (!$in_header && $seq_count === 0) {
                return ['valid' => false, 'error' => 'Invalid FASTA format: sequence expected before header'];
            }
            $in_header = true;
            $seq_count = 0;
        } else {
            if ($in_header) {
                $in_header = false;
            }
            $seq_count += strlen($line);
        }
    }

    if ($seq_count === 0) {
        return ['valid' => false, 'error' => 'No sequence data found'];
    }

    return ['valid' => true, 'error' => ''];
}

function validateBlastIndexFiles($assembly_path, $sequence_types = []) {
    $result = [
        'databases' => [],
        'missing_count' => 0,
        'total_count' => 0
    ];

    if (!is_dir($assembly_path)) {
        return $result;
    }

    // Map sequence types to BLAST index extensions
    $type_mapping = [
        'protein' => ['name' => 'Protein', 'extensions' => ['phr', 'pin', 'psq']],
        'cds' => ['name' => 'CDS', 'extensions' => ['nhr', 'nin', 'nsq']],
        'transcript' => ['name' => 'Transcript', 'extensions' => ['nhr', 'nin', 'nsq']],
    ];

    // Check for each configured sequence type
    if (!empty($sequence_types)) {
        foreach ($sequence_types as $seq_type => $config) {
            $pattern = $config['pattern'] ?? '';
            if (empty($pattern)) {
                continue;
            }

            $file_path = "$assembly_path/$pattern";

            // Only check if FASTA file exists
            if (!file_exists($file_path)) {
                continue;
            }

            $result['total_count']++;
            $type_info = $type_mapping[$seq_type] ?? null;

            // If not in mapping, detect from pattern
            if (!$type_info) {
                $is_protein = strpos($pattern, 'protein') !== false;
                $extensions = $is_protein ? ['phr', 'pin', 'psq'] : ['nhr', 'nin', 'nsq'];
                $type_info = ['name' => ucfirst($seq_type), 'extensions' => $extensions];
            }

            $db_entry = [
                'type' => $seq_type,
                'name' => $type_info['name'],
                'fasta' => basename($file_path),
                'fasta_path' => $file_path,
                'has_indexes' => true,
                'missing_indexes' => []
            ];

            // Check for all required index files
            foreach ($type_info['extensions'] as $ext) {
                $index_file = "$file_path.$ext";
                if (!file_exists($index_file)) {
                    $db_entry['has_indexes'] = false;
                    $db_entry['missing_indexes'][] = $ext;
                }
            }

            if (!$db_entry['has_indexes']) {
                $result['missing_count']++;
            }

            $result['databases'][] = $db_entry;
        }
    }

    return $result;
}

function checkAssemblyCanGenerateBlast($assembly_path, $fasta_files = []) {
    $result = [
        'writable' => false,
        'message' => '',
        'can_execute' => false
    ];

    if (!is_dir($assembly_path)) {
        $result['message'] = 'Assembly directory does not exist';
        return $result;
    }

    // Check if directory is readable and writable
    if (!is_readable($assembly_path)) {
        $result['message'] = 'Assembly directory is not readable by web server';
        return $result;
    }

    if (!is_writable($assembly_path)) {
        $result['message'] = 'Assembly directory is not writable by web server (FASTA index files cannot be created)';
        return $result;
    }

    // Check if FASTA files are readable by web server
    foreach ($fasta_files as $fasta_file) {
        $fasta_path = $assembly_path . '/' . $fasta_file;
        if (file_exists($fasta_path) && !is_readable($fasta_path)) {
            $result['message'] = 'FASTA file is not readable by web server: ' . htmlspecialchars($fasta_file);
            return $result;
        }
    }

    // Check if we can execute commands (shell_exec or exec available)
    if (!function_exists('shell_exec') && !function_exists('exec')) {
        $result['message'] = 'PHP shell execution functions are disabled on this server';
        return $result;
    }

    $result['writable'] = true;
    $result['can_execute'] = true;
    $result['message'] = 'Ready to generate BLAST indexes';

    return $result;
}

function checkAssemblyWritableForBlast($assembly_path) {
    $result = [
        'writable' => false,
        'message' => '',
        'can_execute' => false
    ];

    if (!is_dir($assembly_path)) {
        $result['message'] = 'Assembly directory does not exist';
        return $result;
    }

    // Check if directory is readable and writable
    if (!is_readable($assembly_path)) {
        $result['message'] = 'Assembly directory is not readable by web server';
        return $result;
    }

    if (!is_writable($assembly_path)) {
        $result['message'] = 'Assembly directory is not writable by web server (FASTA index files cannot be created)';
        return $result;
    }

    // Check if we can execute commands (shell_exec or exec available)
    if (!function_exists('shell_exec') && !function_exists('exec')) {
        $result['message'] = 'PHP shell execution functions are disabled on this server';
        return $result;
    }

    $result['writable'] = true;
    $result['can_execute'] = true;
    $result['message'] = 'Ready to generate BLAST indexes';

    return $result;
}

function generateBlastIndexes($organism, $assembly, $fasta_filename, $organism_data_path, $gene_set = 'v1') {
    $result = [
        'success' => false,
        'message' => '',
        'output' => '',
        'errors' => ''
    ];

    // Validate inputs
    if (empty($organism) || empty($assembly) || empty($fasta_filename)) {
        $result['message'] = 'Missing required parameters';
        return $result;
    }

    // Prevent directory traversal attacks
    if (strpos($organism, '/') !== false || strpos($assembly, '/') !== false
     || strpos($fasta_filename, '/') !== false || strpos($gene_set, '/') !== false) {
        $result['message'] = 'Invalid characters in parameters';
        return $result;
    }

    $assembly_path = $organism_data_path . '/' . $organism . '/' . $assembly . '/' . $gene_set;
    $fasta_path = $assembly_path . '/' . $fasta_filename;

    // Verify paths exist
    if (!is_dir($assembly_path)) {
        $result['message'] = 'Gene set directory does not exist';
        return $result;
    }

    if (!file_exists($fasta_path)) {
        $result['message'] = 'FASTA file does not exist';
        return $result;
    }

    // Check permissions
    $perm_check = checkAssemblyWritableForBlast($assembly_path);
    if (!$perm_check['writable']) {
        $result['message'] = $perm_check['message'];
        return $result;
    }

    // Determine database type
    $is_protein = strpos($fasta_filename, 'protein') !== false;
    $db_type = $is_protein ? 'prot' : 'nucl';

    // Build command with configurable path to makeblastdb
    $config = ConfigManager::getInstance();
    $blast_tools = $config->getArray('blast_tools', []);
    $makeblastdb_path = $blast_tools['makeblastdb'] ?? 'makeblastdb';
    $cd_cmd = 'cd ' . escapeshellarg($assembly_path);
    // Don't use escapeshellarg for the filename since we're already in the directory
    $makeblastdb_cmd = $makeblastdb_path . ' -in ' . $fasta_filename . ' -dbtype ' . $db_type . ' -parse_seqids 2>&1';
    $full_cmd = $cd_cmd . ' && ' . $makeblastdb_cmd;

    // Execute command
    try {
        if (function_exists('shell_exec')) {
            $output = shell_exec($full_cmd);
            $result['output'] = $output;

            // Give filesystem a moment to catch up
            sleep(2);

            // Debug: log what we're checking for
            $debug_info = [];

            // Check if indexes were created
            $index_ext = $is_protein ? ['phr', 'pin', 'psq'] : ['nhr', 'nin', 'nsq'];
            $all_created = true;
            $missing = [];
            foreach ($index_ext as $ext) {
                $index_file = $fasta_path . '.' . $ext;
                $exists = file_exists($index_file);
                $debug_info[] = $ext . ': ' . ($exists ? 'EXISTS' : 'MISSING') . ' (' . $index_file . ')';
                if (!$exists) {
                    $all_created = false;
                    $missing[] = $ext;
                }
            }

            if ($all_created) {
                $result['success'] = true;
                $result['message'] = 'BLAST indexes created successfully';
            } else {
                $result['message'] = 'Missing index files: ' . implode(', ', $missing) . '. Debug: ' . implode(' | ', $debug_info) . ' Command: ' . $full_cmd . ' Output: ' . $output;
                $result['errors'] = $output;
            }
        } else {
            $result['message'] = 'Shell execution not available';
        }
    } catch (Exception $e) {
        $result['message'] = 'Error executing command: ' . $e->getMessage();
    }

    return $result;
}

function loadFeatureCoords($assembly_path, $filter_ids = null) {
    $tsv_file = $assembly_path . '/feature_coords.tsv';
    if (!file_exists($tsv_file)) return [];

    // $filter_ids = null  → load everything (legacy callers)
    // $filter_ids = []    → return immediately (no hits, no coords needed)
    // $filter_ids = [...]  → only load matching rows (memory-safe for large files)
    if ($filter_ids !== null && empty($filter_ids)) return [];
    $filter_set = $filter_ids !== null ? array_flip($filter_ids) : null;

    $coords = [];
    $fh = fopen($tsv_file, 'r');
    if (!$fh) return [];

    while (($line = fgets($fh)) !== false) {
        $p = explode("\t", rtrim($line));
        if (count($p) < 6) continue;
        if ($filter_set !== null && !isset($filter_set[$p[0]])) continue;
        $coords[$p[0]] = [
            'gene_id' => $p[1],
            'chr'     => $p[2],
            'start'   => (int)$p[3],
            'end'     => (int)$p[4],
            'strand'  => $p[5],
        ];
        // Once we have all requested IDs, stop scanning the file.
        if ($filter_set !== null && count($coords) === count($filter_set)) break;
    }
    fclose($fh);
    return $coords;
}

function extractFastaRegion(string $fasta_path, string $fai_path, string $seqname, int $start, int $end): ?string
{
    $fh    = fopen($fai_path, 'r');
    if ($fh === false) return null;
    $entry = null;
    while (($line = fgets($fh)) !== false) {
        $parts = explode("\t", rtrim($line));
        if (count($parts) >= 5 && $parts[0] === $seqname) {
            $entry = [
                'total_len'      => (int)$parts[1],
                'offset'         => (int)$parts[2],
                'bases_per_line' => (int)$parts[3],
                'bytes_per_line' => (int)$parts[4],
            ];
            break;
        }
    }
    fclose($fh);

    if (!$entry || $entry['bases_per_line'] === 0) return null;

    // Clamp to contig boundaries so we never read past the end into the next entry
    if ($end > $entry['total_len']) $end = $entry['total_len'];
    if ($start > $end) return null;

    $s        = $start - 1;
    $len      = $end - $start + 1;
    $byte_pos = $entry['offset']
              + intdiv($s, $entry['bases_per_line']) * $entry['bytes_per_line']
              + ($s % $entry['bases_per_line']);

    $fh = fopen($fasta_path, 'rb');
    if ($fh === false) return null;
    fseek($fh, $byte_pos);

    $seq       = '';
    $remaining = $len;
    while ($remaining > 0) {
        $read_len = $remaining + (int)ceil($remaining / $entry['bases_per_line']) + 4;
        $chunk    = fread($fh, min(65536, $read_len));
        if ($chunk === false || $chunk === '') break;
        $clean     = str_replace(["\r\n", "\r", "\n"], '', $chunk);
        $take      = min($remaining, strlen($clean));
        $seq      .= substr($clean, 0, $take);
        $remaining -= $take;
    }
    fclose($fh);

    return strtoupper($seq);
}

function reverseComplement(string $seq): string
{
    return strrev(strtr(strtoupper($seq), ['A' => 'T', 'T' => 'A', 'C' => 'G', 'G' => 'C']));
}

function parseBlastResults($blast_xml) {
    $all_queries = [];

    // Parse XML
    try {
        $xml = simplexml_load_string($blast_xml);

        if ($xml === false) {
            return ['error' => 'Failed to parse BLAST XML output', 'queries' => []];
        }

        // Parse each iteration (each query gets one iteration)
        $iterations = $xml->xpath('//Iteration');

        foreach ($iterations as $iteration) {
            $query_result = [
                'hits' => [],
                'query_length' => 0,
                'query_name' => '',
                'query_desc' => '',
                'total_hits' => 0,
                'error' => ''
            ];

            // Get query info using XPath to handle hyphens in element names
            $query_len = $iteration->xpath('./Iteration_query-len');
            if (!empty($query_len)) {
                $query_result['query_length'] = (int)$query_len[0];
            }

            $query_id = $iteration->xpath('./Iteration_query-ID');
            if (!empty($query_id)) {
                $query_result['query_name'] = (string)$query_id[0];
            }

            $query_def = $iteration->xpath('./Iteration_query-def');
            if (!empty($query_def)) {
                $query_result['query_desc'] = (string)$query_def[0];
            }

            // Parse each hit using XPath - maintain Hit/HSP hierarchy
            $hits = $iteration->xpath('.//Hit');
            foreach ($hits as $hit_node) {
                // Get hit info
                $hit_id = $hit_node->xpath('./Hit_id');
                $hit_def = $hit_node->xpath('./Hit_def');
                $hit_len = $hit_node->xpath('./Hit_len');

                $hit_id_str = !empty($hit_id) ? (string)$hit_id[0] : '';
                $hit_def_str = !empty($hit_def) ? (string)$hit_def[0] : '';
                if ($hit_def_str === '' || strcasecmp(trim($hit_def_str), 'No definition line') === 0) {
                    $hit_def_str = $hit_id_str;
                }
                $hit_len_int = !empty($hit_len) ? (int)$hit_len[0] : 0;

                // Get all HSPs (High-scoring Segment Pairs) for this hit
                $hsps = $hit_node->xpath('.//Hsp');
                if (!empty($hsps)) {
                    $hsps_array = [];
                    $best_evalue = PHP_FLOAT_MAX;
                    $cumulative_coverage = [];

                    // Process each HSP for this hit
                    foreach ($hsps as $hsp) {
                        // Use XPath for HSP elements with hyphens
                        $identities = $hsp->xpath('./Hsp_identity');
                        $align_len = $hsp->xpath('./Hsp_align-len');
                        $evalue = $hsp->xpath('./Hsp_evalue');
                        $bit_score = $hsp->xpath('./Hsp_bit-score');
                        $score = $hsp->xpath('./Hsp_score');
                        $query_from = $hsp->xpath('./Hsp_query-from');
                        $query_to = $hsp->xpath('./Hsp_query-to');
                        $hit_from = $hsp->xpath('./Hsp_hit-from');
                        $hit_to = $hsp->xpath('./Hsp_hit-to');
                        $qseq = $hsp->xpath('./Hsp_qseq');
                        $hseq = $hsp->xpath('./Hsp_hseq');
                        $midline = $hsp->xpath('./Hsp_midline');

                        $identities_int = !empty($identities) ? (int)$identities[0] : 0;
                        $align_len_int = !empty($align_len) ? (int)$align_len[0] : 0;
                        $evalue_float = !empty($evalue) ? (float)$evalue[0] : 0;
                        $hit_from_int = !empty($hit_from) ? (int)$hit_from[0] : 0;
                        $hit_to_int = !empty($hit_to) ? (int)$hit_to[0] : 0;

                        // Track best (smallest) evalue
                        if ($evalue_float < $best_evalue) {
                            $best_evalue = $evalue_float;
                        }

                        // Track coverage regions for cumulative calculation
                        $cumulative_coverage[] = [
                            'from' => min($hit_from_int, $hit_to_int),
                            'to' => max($hit_from_int, $hit_to_int)
                        ];

                        // Count gaps and similarities with gap lengths
                        $query_seq = !empty($qseq) ? (string)$qseq[0] : '';
                        $hit_seq = !empty($hseq) ? (string)$hseq[0] : '';
                        $midline_str = !empty($midline) ? (string)$midline[0] : '';

                        // Count gaps and track individual gap lengths
                        $gap_count = 0;
                        $gap_lengths = [];

                        // Find gaps in query sequence
                        $in_gap = false;
                        $gap_len = 0;
                        for ($i = 0; $i < strlen($query_seq); $i++) {
                            if ($query_seq[$i] === '-') {
                                if (!$in_gap) {
                                    $in_gap = true;
                                    $gap_len = 1;
                                } else {
                                    $gap_len++;
                                }
                            } else {
                                if ($in_gap) {
                                    $gap_lengths[] = $gap_len;
                                    $gap_count += $gap_len;
                                    $in_gap = false;
                                }
                            }
                        }
                        if ($in_gap) {
                            $gap_lengths[] = $gap_len;
                            $gap_count += $gap_len;
                        }

                        // Find gaps in hit sequence
                        $in_gap = false;
                        $gap_len = 0;
                        for ($i = 0; $i < strlen($hit_seq); $i++) {
                            if ($hit_seq[$i] === '-') {
                                if (!$in_gap) {
                                    $in_gap = true;
                                    $gap_len = 1;
                                } else {
                                    $gap_len++;
                                }
                            } else {
                                if ($in_gap) {
                                    $gap_lengths[] = $gap_len;
                                    $gap_count += $gap_len;
                                    $in_gap = false;
                                }
                            }
                        }
                        if ($in_gap) {
                            $gap_lengths[] = $gap_len;
                            $gap_count += $gap_len;
                        }

                        $total_gap_length = $gap_count;
                        $gaps = count($gap_lengths);
                        $gap_lengths_str = implode(', ', $gap_lengths);

                        $similarities = strlen($midline_str) - $identities_int - substr_count($midline_str, ' ');

                        // Calculate HSP subject coverage percentage
                        $subject_coverage_percent = $hit_len_int > 0 ? round((abs($hit_to_int - $hit_from_int) + 1) / $hit_len_int * 100, 2) : 0;

                        $hsp_data = [
                            'identities' => $identities_int,
                            'alignment_length' => $align_len_int,
                            'evalue' => $evalue_float,
                            'bit_score' => !empty($bit_score) ? (float)$bit_score[0] : 0,
                            'score' => !empty($score) ? (int)$score[0] : 0,
                            'percent_identity' => $align_len_int > 0 ? round(($identities_int / $align_len_int) * 100, 2) : 0,
                            'query_from' => !empty($query_from) ? (int)$query_from[0] : 0,
                            'query_to' => !empty($query_to) ? (int)$query_to[0] : 0,
                            'hit_from' => $hit_from_int,
                            'hit_to' => $hit_to_int,
                            'query_seq' => $query_seq,
                            'hit_seq' => $hit_seq,
                            'midline' => $midline_str,
                            'gaps' => $gaps,
                            'gap_lengths' => $gap_lengths,
                            'gap_lengths_str' => $gap_lengths_str,
                            'total_gap_length' => $total_gap_length,
                            'similarities' => $similarities,
                            'subject_coverage_percent' => $subject_coverage_percent
                        ];

                        $hsps_array[] = $hsp_data;
                    }

                    // Calculate cumulative coverage for this hit across all HSPs
                    // Track query coverage (not subject coverage)
                    $query_coverage = [];
                    foreach ($hsps_array as $hsp_data) {
                        $query_coverage[] = [
                            'from' => $hsp_data['query_from'],
                            'to' => $hsp_data['query_to']
                        ];
                    }

                    usort($query_coverage, function($a, $b) { return $a['from'] - $b['from']; });
                    $merged = [];
                    foreach ($query_coverage as $region) {
                        if (empty($merged) || $merged[count($merged)-1]['to'] < $region['from']) {
                            $merged[] = $region;
                        } else {
                            $merged[count($merged)-1]['to'] = max($merged[count($merged)-1]['to'], $region['to']);
                        }
                    }
                    $total_covered = 0;
                    foreach ($merged as $region) {
                        $total_covered += $region['to'] - $region['from'] + 1;
                    }
                    $query_coverage_percent = $query_result['query_length'] > 0 ? round(($total_covered / $query_result['query_length']) * 100, 2) : 0;

                    // Also calculate subject cumulative coverage for display
                    $subject_cumulative_coverage = [];
                    foreach ($query_result['hits'] as $hit_test) {
                        if ($hit_test['subject'] === $hit_def_str) {
                            foreach ($hit_test['hsps'] as $hsp_test) {
                                $subject_cumulative_coverage[] = [
                                    'from' => min($hsp_test['hit_from'], $hsp_test['hit_to']),
                                    'to' => max($hsp_test['hit_from'], $hsp_test['hit_to'])
                                ];
                            }
                        }
                    }
                    usort($subject_cumulative_coverage, function($a, $b) { return $a['from'] - $b['from']; });
                    $merged_subject = [];
                    foreach ($subject_cumulative_coverage as $region) {
                        if (empty($merged_subject) || $merged_subject[count($merged_subject)-1]['to'] < $region['from']) {
                            $merged_subject[] = $region;
                        } else {
                            $merged_subject[count($merged_subject)-1]['to'] = max($merged_subject[count($merged_subject)-1]['to'], $region['to']);
                        }
                    }
                    $total_subject_covered = 0;
                    foreach ($merged_subject as $region) {
                        $total_subject_covered += $region['to'] - $region['from'] + 1;
                    }
                    $subject_cumulative_coverage_percent = $hit_len_int > 0 ? round(($total_subject_covered / $hit_len_int) * 100, 2) : 0;

                    // Create hit entry with all its HSPs
                    $hit = [
                        'id' => $hit_id_str,
                        'subject' => $hit_def_str,
                        'length' => $hit_len_int,
                        'hsps' => $hsps_array,
                        'best_evalue' => $best_evalue,
                        'num_hsps' => count($hsps_array),
                        'query_coverage_percent' => $query_coverage_percent,
                        'subject_cumulative_coverage_percent' => $subject_cumulative_coverage_percent
                    ];

                    $query_result['hits'][] = $hit;
                }
            }

            $query_result['total_hits'] = count($query_result['hits']);
            $all_queries[] = $query_result;
        }

    } catch (Exception $e) {
        return ['error' => 'XML parsing error: ' . $e->getMessage(), 'queries' => []];
    }

    return ['queries' => $all_queries, 'error' => ''];
}

function generateHitsSummaryTable($results, $query_num = 1) {
    $html = '<div class="blast-hits-summary mb-4">';
    $html .= '<h6><i class="fa fa-table"></i> Hits Summary (' . $results['total_hits'] . ' hits found)</h6>';
    $html .= '<div style="overflow-x: auto;">';
    $html .= '<table class="table table-sm table-striped blast-hits-table">';
    $html .= '<thead class="table-light">';
    $html .= '<tr>';
    $html .= '<th style="width: 5%">#</th>';
    $html .= '<th style="width: 45%">Hit ID / Description</th>';
    $html .= '<th style="width: 20%">Query Coverage %</th>';
    $html .= '<th style="width: 12%">E-value</th>';
    $html .= '<th style="width: 18%">HSPs</th>';
    $html .= '</tr>';
    $html .= '</thead>';
    $html .= '<tbody>';

    foreach ($results['hits'] as $idx => $hit) {
        $hit_num = $idx + 1;
        $evalue_display = sprintf('%.2e', $hit['best_evalue']);
        $query_coverage = $hit['query_coverage_percent'];
        $coverage_bar_width = min(100, $query_coverage);

        // Color based on coverage percentage
        if ($query_coverage >= 80) {
            $coverage_color = '#28a745'; // Green - excellent coverage
        } elseif ($query_coverage >= 50) {
            $coverage_color = '#ffc107'; // Yellow - good coverage
        } elseif ($query_coverage >= 30) {
            $coverage_color = '#fd7e14'; // Orange - moderate coverage
        } else {
            $coverage_color = '#dc3545'; // Red - low coverage
        }

        $html .= '<tr style="cursor: pointer;" onclick="const elem = document.getElementById(\'query-' . $query_num . '-hit-' . $hit_num . '\'); elem.scrollIntoView({behavior: \'smooth\', block: \'start\'}); highlightHitElement(elem);">';
        $html .= '<td><strong>' . $hit_num . '</strong></td>';
        $clean_id = cleanBlastHitId($hit['id']);
        $html .= '<td>';
        $html .= '<small class="d-block fw-bold">' . htmlspecialchars($clean_id) . '</small>';
        $html .= '<small class="text-muted">' . htmlspecialchars(substr($hit['subject'], 0, 60)) . '</small>';
        $html .= '</td>';
        $html .= '<td>';
        $html .= '<div class="blast-coverage-bar" style="width: 100%; background: #e9ecef; border-radius: 4px; overflow: hidden;">';
        $html .= '<div style="width: ' . $coverage_bar_width . '%; background: ' . $coverage_color . '; height: 20px; display: flex; align-items: center; justify-content: center;">';
        $html .= '<small style="font-weight: bold; color: white;">' . $query_coverage . '%</small>';
        $html .= '</div>';
        $html .= '</div>';
        $html .= '</td>';
        $html .= '<td><small>' . $evalue_display . '</small></td>';
        $html .= '<td>' . $hit['num_hsps'] . '</td>';
        $html .= '</tr>';
    }

    $html .= '</tbody>';
    $html .= '</table>';
    $html .= '</div>';
    $html .= '</div>';

    return $html;
}

function generateBlastGraphicalView($results) {
    if ($results['query_length'] <= 0 || empty($results['hits'])) {
        return '';
    }

    $query_len = $results['query_length'];
    $canvas_width = 1000;
    $canvas_height_per_row = 25;
    $total_rows = 0;

    // Count total rows (one row per HSP) - limit to top 2 HSPs per hit
    foreach ($results['hits'] as $hit) {
        $total_rows += min(2, count($hit['hsps']));
    }

    $canvas_height = 120 + ($total_rows * $canvas_height_per_row) + 40;
    $img_width = 850;
    $xscale = $img_width / $query_len;
    $top_margin = 100;
    $left_margin = 200;
    $right_margin = 100;

    // Determine tick distance based on query length
    $tick_dist = 100;
    if ($query_len > 2450) $tick_dist = 150;
    if ($query_len > 3900) $tick_dist = 200;
    if ($query_len > 5000) $tick_dist = 300;
    if ($query_len > 7500) $tick_dist = round($query_len / 5);

    $html = '<div style="margin: 20px 0; overflow-x: auto; border: 1px solid #ddd; border-radius: 8px; background: white;">';
    $html .= '<svg width="' . ($canvas_width + $left_margin + $right_margin) . '" height="' . $canvas_height . '" style="font-family: Arial, sans-serif;">';

    // Background
    $html .= '<rect width="' . ($canvas_width + $left_margin + $right_margin) . '" height="' . $canvas_height . '" fill="#f9f9f9"/>';

    // Title
    $html .= '<text x="' . ($left_margin + ($img_width / 2)) . '" y="30" font-size="18" font-weight="bold" text-anchor="middle" fill="#333">Query Length (' . $query_len . ' bp)</text>';

    // Score legend
    $legend_y = 50;
    $legend_items = [
        ['label' => '<40', 'color' => '#000000', 'range' => '<40'],
        ['label' => '40-50', 'color' => '#0047c8', 'range' => '40-50'],
        ['label' => '50-80', 'color' => '#77de75', 'range' => '50-80'],
        ['label' => '80-200', 'color' => '#e967f5', 'range' => '80-200'],
        ['label' => '≥200', 'color' => '#e83a2d', 'range' => '200+']
    ];

    $legend_x = $left_margin;
    $legend_width = $img_width / count($legend_items);
    foreach ($legend_items as $item) {
        $html .= '<rect x="' . $legend_x . '" y="' . $legend_y . '" width="' . $legend_width . '" height="20" fill="' . $item['color'] . '"/>';
        $html .= '<text x="' . ($legend_x + ($legend_width / 2)) . '" y="' . ($legend_y + 15) . '" font-size="11" font-weight="bold" text-anchor="middle" fill="white">' . $item['label'] . '</text>';
        $legend_x += $legend_width;
    }

    // Horizontal line under legend
    $html .= '<line x1="' . $left_margin . '" y1="' . ($legend_y + 25) . '" x2="' . ($left_margin + $img_width) . '" y2="' . ($legend_y + 25) . '" stroke="#333" stroke-width="2"/>';

    // Tick marks and labels
    $vline_tag = $tick_dist;
    for ($l = $tick_dist; $l + ($tick_dist / 2) < $query_len; $l += $tick_dist) {
        $x = $left_margin + ($l * $xscale);
        // Vertical line
        $html .= '<line x1="' . $x . '" y1="' . ($legend_y + 25) . '" x2="' . $x . '" y2="' . $canvas_height . '" stroke="#ccc" stroke-width="1"/>';
        // Tick label
        $html .= '<text x="' . $x . '" y="' . ($legend_y + 45) . '" font-size="12" text-anchor="middle" fill="#333">' . $vline_tag . '</text>';
        $vline_tag += $tick_dist;
    }

    // E-value column header
    $html .= '<text x="' . ($left_margin + $img_width + 15) . '" y="' . ($legend_y + 45) . '" font-size="12" font-weight="bold" fill="#333">E-value</text>';

    // Draw hits/HSPs
    $current_y = $top_margin;
    $prev_subject = '';

    foreach ($results['hits'] as $hit_idx => $hit) {
        $subject_name = cleanBlastHitId($hit['id']);
        $is_new_subject = ($prev_subject !== $hit['subject']);

        if ($is_new_subject && $prev_subject !== '') {
            $current_y += 5; // Add spacing between different subjects
        }

        // Subject name (only once per hit)
        if ($is_new_subject) {
            $html .= '<text x="5" y="' . ($current_y + 15) . '" font-size="11" font-weight="bold" fill="#333">' . htmlspecialchars($subject_name) . '</text>';
        }

        // HSPs for this hit - limit to top 2
        foreach ($hit['hsps'] as $hsp_idx => $hsp) {
            if ($hsp_idx >= 2) break; // Only show top 2 HSPs

            $start_pos = $hsp['query_from'];
            $end_pos = $hsp['query_to'];
            $score = $hsp['bit_score'];

            // Determine color based on bit score
            if ($score >= 200) {
                $fill_color = 'rgba(255, 50, 40, 0.8)';
            } elseif ($score >= 80) {
                $fill_color = 'rgba(235,96,247, 0.8)';
            } elseif ($score >= 50) {
                $fill_color = 'rgba(119,222,117, 0.8)';
            } elseif ($score >= 40) {
                $fill_color = 'rgba(0,62,203, 0.8)';
            } else {
                $fill_color = 'rgba(10,10,10, 0.8)';
            }

            $rect_x = $left_margin + ($start_pos * $xscale);
            $rect_width = (($end_pos - $start_pos + 1) * $xscale);

            // Convert rgba to hex for SVG
            if ($score >= 200) {
                $fill_hex = '#ff3228';
            } elseif ($score >= 80) {
                $fill_hex = '#eb60f7';
            } elseif ($score >= 50) {
                $fill_hex = '#77de75';
            } elseif ($score >= 40) {
                $fill_hex = '#003ecb';
            } else {
                $fill_hex = '#0a0a0a';
            }

            // HSP rectangle - clickable
            $html .= '<g onclick="document.getElementById(\'hit-' . ($hit_idx + 1) . '\').scrollIntoView({behavior: \'smooth\', block: \'start\'})" style="cursor: pointer;">';
            $html .= '<title>Hit ' . ($hit_idx + 1) . ' HSP ' . ($hsp_idx + 1) . ': ' . round($hsp['percent_identity'], 1) . '% identity | E-value: ' . sprintf('%.2e', $hsp['evalue']) . '</title>';
            $html .= '<rect x="' . $rect_x . '" y="' . ($current_y) . '" width="' . $rect_width . '" height="16" fill="' . $fill_hex . '" stroke="#333" stroke-width="0.5" rx="2"/>';
            $html .= '</g>';

            // E-value on the right
            $evalue_display = sprintf('%.2e', $hsp['evalue']);
            $html .= '<text x="' . ($left_margin + $img_width + 15) . '" y="' . ($current_y + 12) . '" font-size="10" fill="#333">' . $evalue_display . '</text>';

            $current_y += $canvas_height_per_row;
        }

        $prev_subject = $hit['subject'];
    }

    $html .= '</svg>';
    $html .= '</div>';

    // Add legend explaining the colors
    $html .= '<div style="margin: 15px 0; background: #f8f9fa; border: 1px solid #ddd; border-radius: 8px; padding: 15px;">';
    $html .= '<strong style="display: block; margin-bottom: 10px;"><i class="fa fa-info-circle"></i> Legend - Bit Score Color Coding:</strong>';
    $html .= '<div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 15px;">';

    $legend_items = [
        ['color' => '#0a0a0a', 'label' => '< 40', 'desc' => 'Weak alignment'],
        ['color' => '#003ecb', 'label' => '40 - 50', 'desc' => 'Moderate alignment'],
        ['color' => '#77de75', 'label' => '50 - 80', 'desc' => 'Good alignment'],
        ['color' => '#eb60f7', 'label' => '80 - 200', 'desc' => 'Very good alignment'],
        ['color' => '#ff3228', 'label' => '≥ 200', 'desc' => 'Excellent alignment']
    ];

    foreach ($legend_items as $item) {
        $html .= '<div style="display: flex; align-items: center;">';
        $html .= '<div style="width: 24px; height: 24px; background: ' . $item['color'] . '; border-radius: 3px; margin-right: 10px;"></div>';
        $html .= '<div>';
        $html .= '<strong>' . $item['label'] . '</strong><br>';
        $html .= '<small style="color: #666;">' . $item['desc'] . '</small>';
        $html .= '</div>';
        $html .= '</div>';
    }

    $html .= '</div>';
    $html .= '</div>';

    return $html;
}

function generateAlignmentViewer($results, $blast_program = 'blastn', $query_num = 1, $context = []) {
    $html = '<div class="blast-alignment-viewer mt-4">';
    $html .= '<h6><i class="fa fa-align-justify"></i> Detailed Alignments (HSPs)</h6>';
    $html .= '<small class="text-muted d-block mb-3">Each Hit section contains one or more High-Scoring Segment Pairs (HSPs)</small>';

    if (empty($results['hits'])) {
        $html .= '<div class="alert alert-info"><small>No alignments to display</small></div>';
        return $html . '</div>';
    }

    // Extract context for per-HSP JBrowse buttons (genome BLAST only)
    $ctx_site         = $context['site']          ?? '';
    $ctx_organism     = $context['organism']      ?? '';
    $ctx_assembly     = $context['assembly']      ?? '';
    $ctx_is_genome    = $context['is_genome_db']  ?? false;
    $ctx_has_jbrowse  = $context['has_jbrowse']   ?? false;
    $ctx_jb2_asm      = $ctx_organism . '_' . $ctx_assembly;
    $ctx_lc           = $context['linkout_config'] ?? [];
    $ctx_jb_enabled   = (bool)($ctx_lc['jbrowse'] ?? false);

    // Determine correct unit based on program
    $unit = 'bp';
    if (strpos($blast_program, 'blastp') !== false || strpos($blast_program, 'tblastn') !== false) {
        $unit = 'aa';
    }

    $html .= '<div style="background: #f8f9fa; border-radius: 4px; overflow-x: auto;">';

    foreach ($results['hits'] as $hit_idx => $hit) {
        $hit_num = $hit_idx + 1;
        $evalue_display = sprintf('%.2e', $hit['best_evalue']);

        // Hit header card
        $clean_hit_id = cleanBlastHitId($hit['id']);
        $html .= '<div id="query-' . $query_num . '-hit-' . $hit_num . '" style="padding: 15px; scroll-margin-top: 20px; background: #f0f7ff; margin-bottom: 15px;">';
        $html .= '<h5 style="margin-bottom: 4px; color: #007bff; font-family: monospace;">';
        $html .= '<strong>Hit ' . $hit_num . ': ' . htmlspecialchars($clean_hit_id) . '</strong>';
        $html .= '</h5>';
        $html .= '<div style="margin-bottom: 10px; color: #555; font-size: 0.9em;">' . htmlspecialchars($hit['subject']) . '</div>';
        $html .= '<small class="d-block" style="margin-bottom: 10px;">';
        $html .= '<strong>Length:</strong> ' . $hit['length'] . ' ' . $unit . ' | ';
        $html .= '<strong>Best E-value:</strong> ' . $evalue_display . ' | ';
        $html .= '<strong>HSPs:</strong> ' . $hit['num_hsps'] . ' | ';
        $html .= '<strong>Query Coverage:</strong> ' . $hit['query_coverage_percent'] . '% | ';
        $html .= '<strong>Subject Coverage:</strong> ' . $hit['subject_cumulative_coverage_percent'] . '%';
        $html .= '</small>';
        if (!empty($context)) {
            $linkout_html = buildBlastHitLinkouts($hit, $context);
            if ($linkout_html) {
                $html .= '<div style="margin-top:8px;">' . $linkout_html . '</div>';
            }
        }
        $html .= '</div>';

        // HSPs for this hit
        foreach ($hit['hsps'] as $hsp_idx => $hsp) {
            $hsp_num = $hsp_idx + 1;

            $html .= '<div style="padding: 15px; border-bottom: 1px solid #dee2e6; margin-left: 15px; background: #ffffff; margin-bottom: 10px; border-left: 4px solid #28a745;">';
            $html .= '<h6 style="margin-bottom: 10px;"><strong>HSP ' . $hsp_num . '</strong></h6>';
            $html .= '<small class="text-muted d-block" style="margin-bottom: 10px;">';
            $html .= 'E-value: ' . sprintf('%.2e', $hsp['evalue']) . ' | ';
            $html .= 'Alignment length: ' . $hsp['alignment_length'] . ' | ';
            $html .= 'Identity: ' . $hsp['identities'] . '/' . $hsp['alignment_length'] . ' (' . $hsp['percent_identity'] . '%) | ';
            $html .= 'Similarities: ' . $hsp['similarities'] . ' | ';
            $html .= 'Gaps: ' . $hsp['gaps'];
            if ($hsp['gaps'] > 0) {
                $html .= ' (lengths: ' . $hsp['gap_lengths_str'] . ', total: ' . $hsp['total_gap_length'] . ')';
            }
            $html .= '</small>';

            // Query coverage information for this HSP
            $query_hsp_coverage = $results['query_length'] > 0 ? round((($hsp['query_to'] - $hsp['query_from'] + 1) / $results['query_length']) * 100, 2) : 0;
            $html .= '<small class="d-block" style="margin-bottom: 10px; background: #e7f3ff; padding: 8px; border-radius: 3px; border-left: 3px solid #007bff;">';
            $html .= '<strong>Query Coverage (This HSP):</strong> ';
            $html .= $query_hsp_coverage . '% (' . ($hsp['query_to'] - $hsp['query_from'] + 1) . '/' . $results['query_length'] . ') | ';
            $html .= '<strong>Subject Coverage (This HSP):</strong> ';
            $html .= $hsp['subject_coverage_percent'] . '% (' . abs($hsp['hit_to'] - $hsp['hit_from']) + 1 . '/' . $results['hits'][$hit_idx]['length'] . ')';
            $html .= '</small>';

            // Per-HSP JBrowse button (genome BLAST only)
            if ($ctx_is_genome && $ctx_has_jbrowse && $ctx_jb_enabled && $ctx_site !== '') {
                $hsp_subject = cleanBlastHitId($hit['id'] ?? '');
                $s = min((int)$hsp['hit_from'], (int)$hsp['hit_to']) - 1;
                $e = max((int)$hsp['hit_from'], (int)$hsp['hit_to']);
                $hsp_track_id = 'blast_hsp_' . substr(md5($hit['id'] . '_' . $hsp_idx), 0, 10);
                $hsp_features = [[
                    'uniqueId' => $hsp_track_id . '_f',
                    'refName'  => $hsp_subject,
                    'start'    => $s,
                    'end'      => $e,
                    'name'     => 'HSP ' . $hsp_num . ' (evalue=' . ($hsp['evalue'] ?? '?') . ')',
                    'type'     => 'match_part',
                ]];
                $hsp_tracks = [[
                    'type'          => 'FeatureTrack',
                    'trackId'       => $hsp_track_id,
                    'name'          => 'BLAST HSP ' . $hsp_num . ': ' . $hsp_subject,
                    'assemblyNames' => [$ctx_jb2_asm],
                    'adapter'       => ['type' => 'FromConfigAdapter', 'features' => $hsp_features],
                ]];
                $hsp_loc = $hsp_subject . ':' . ($s + 1) . '-' . $e;
                $hsp_url = '/' . $ctx_site . '/jbrowse2.php?organism=' . urlencode($ctx_organism)
                         . '&assembly='      . urlencode($ctx_assembly)
                         . '&loc='           . urlencode($hsp_loc)
                         . '&sessionTracks=' . urlencode(json_encode($hsp_tracks))
                         . '&sessionTrackId='. urlencode($hsp_track_id);
                $html .= '<div style="margin-bottom:8px;">'
                       . '<a href="' . htmlspecialchars($hsp_url) . '" target="_blank" '
                       . 'class="btn btn-sm btn-outline-success">'
                       . 'View HSP ' . $hsp_num . ' in Browser</a>'
                       . '</div>';
            }

            // Display alignment in monospace with frame-aware formatting
            $html .= '<pre style="background: white; border: 1px solid #dee2e6; padding: 10px; border-radius: 3px; overflow-x: auto; font-size: 11px; margin: 0; font-family: \'Courier New\', monospace;">';

            // Use frame-aware alignment formatter if frames are available
            if (isset($hsp['query_frame']) || isset($hsp['hit_frame'])) {
                $query_frame = isset($hsp['query_frame']) ? (int)$hsp['query_frame'] : 0;
                $hit_frame = isset($hsp['hit_frame']) ? (int)$hsp['hit_frame'] : 0;
                $alignment_text = formatBlastAlignment(
                    $hsp['alignment_length'],
                    $hsp['query_seq'],
                    $hsp['query_from'],
                    $hsp['query_to'],
                    $hsp['midline'],
                    $hsp['hit_seq'],
                    $hsp['hit_from'],
                    $hsp['hit_to'],
                    'Plus',
                    $query_frame,
                    $hit_frame
                );
                $html .= htmlspecialchars($alignment_text);
            } else {
                // Fallback to simple formatting
                $label_width = 15;
                $query_label = str_pad('Query  ' . $hsp['query_from'], $label_width);
                $midline_label = str_pad('', $label_width);
                $sbjct_label = str_pad('Sbjct  ' . $hsp['hit_from'], $label_width);

                $html .= $query_label . htmlspecialchars($hsp['query_seq']) . ' ' . $hsp['query_to'] . "\n";
                $html .= $midline_label . htmlspecialchars($hsp['midline']) . "\n";
                $html .= $sbjct_label . htmlspecialchars($hsp['hit_seq']) . ' ' . $hsp['hit_to'] . "\n";
            }

            $html .= '</pre>';

            $html .= '</div>';
        }
    }

    $html .= '</div>';
    $html .= '</div>';

    return $html;
}

function generateBlastStatisticsSummary($results, $query_seq, $blast_program) {
    if ($results['total_hits'] === 0) {
        return '';
    }

    $html = '<div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; border-radius: 8px; padding: 25px; margin-bottom: 25px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);">';

    // Title
    $html .= '<h4 style="margin: 0 0 20px 0; font-weight: bold;"><i class="fa fa-chart-bar"></i> BLAST Search Statistics</h4>';

    // Statistics grid
    $html .= '<div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 20px;">';

    // Query info
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #4fc3f7;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Query</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . strlen($query_seq) . ' bp</div>';
    if (!empty($results['query_name'])) {
        $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">' . htmlspecialchars(substr($results['query_name'], 0, 30)) . '</div>';
    }
    $html .= '</div>';

    // Hits found
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #81c784;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Hits Found</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $results['total_hits'] . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Subject sequences</div>';
    $html .= '</div>';

    // Best hit info
    $best_hit = $results['hits'][0];
    $best_hsp = $best_hit['hsps'][0];
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ffa726;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Best E-value</div>';
    $evalue_display = sprintf('%.2e', $best_hit['best_evalue']);
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $evalue_display . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Top hit</div>';
    $html .= '</div>';

    // Best identity
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ef5350;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Best Identity</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $best_hsp['percent_identity'] . '%</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">' . $best_hsp['identities'] . '/' . $best_hsp['alignment_length'] . ' bp/aa</div>';
    $html .= '</div>';

    // Total HSPs
    $total_hsps = 0;
    foreach ($results['hits'] as $hit) {
        $total_hsps += $hit['num_hsps'];
    }
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ab47bc;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Total HSPs</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $total_hsps . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Alignments</div>';
    $html .= '</div>';

    // Program
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #29b6f6;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Program</div>';
    $html .= '<div style="font-size: 18px; font-weight: bold;">' . strtoupper(htmlspecialchars($blast_program)) . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Sequence search</div>';
    $html .= '</div>';

    $html .= '</div>'; // End grid

    $html .= '</div>'; // End container

    return $html;
}

