/**
* Check whether a tool should appear on the given page.
*/

functions.code:
function _tool_visible_on_page($tool, $page) {
    $pages = $tool['pages'] ?? 'all';
    if ($pages === 'all') {
        return true;
    }
    if (is_array($pages)) {
        return in_array($page, $pages);
    }
    return $page === $pages;
}

function createToolContext($page, $params = []) {
    $context = ['page' => $page];

    $optional_keys = ['organism', 'assembly', 'gene_set', 'group', 'organisms', 'display_name', 'use_onclick_handler', 'loc'];
    foreach ($optional_keys as $key) {
        if (!empty($params[$key])) {
            $context[$key] = $params[$key];
        }
    }

    if (empty($context['display_name'])) {
        if (!empty($context['organism'])) {
            $context['display_name'] = $context['organism'];
        } elseif (!empty($context['group'])) {
            $context['display_name'] = $context['group'];
        } elseif (in_array($page, ['index', 'multi_organism_search'])) {
            $context['display_name'] = 'Multi-Organism Search';
        }
    }

    return $context;
}

function sanitize_search_input($input, $quoted_search = false) {
    // Remove null bytes and control characters
    $input = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/', '', $input);

    // Trim whitespace
    $input = trim($input);

    // Remove quotes if this is a quoted search - they will be removed before passing to database
    if ($quoted_search) {
        $input = trim($input, '"');
    }

    // Remove excessive whitespace (multiple spaces become single space)
    $input = preg_replace('/\s+/', ' ', $input);

    return $input;
}

function validate_search_term($term) {
    $term = sanitize_search_input($term);

    if (empty($term)) {
        return ['valid' => false, 'error' => 'Search term cannot be empty'];
    }

    if (strlen($term) < 2) {
        return ['valid' => false, 'error' => 'Search term must be at least 2 characters long'];
    }

    if (strlen($term) > 100) {
        return ['valid' => false, 'error' => 'Search term too long (maximum 100 characters)'];
    }

    // Check for patterns that might cause performance issues
    if (preg_match('/^[%_*]+$/', $term)) {
        return ['valid' => false, 'error' => 'Search term cannot consist only of wildcards'];
    }

    return ['valid' => true, 'term' => $term];
}

function is_quoted_search($term) {
    $term = trim($term);
    return (strlen($term) >= 2 && 
            (($term[0] === '"' && $term[-1] === '"') ||
             ($term[0] === "'" && $term[-1] === "'")));
}

function validateOrganismParam($organism_name, $redirect_on_empty = null) {
    if (empty($organism_name)) {
        if ($redirect_on_empty === null) {
            $site = ConfigManager::getInstance()->getString('site');
            $redirect_on_empty = "/$site/index.php";
        }
        header("Location: $redirect_on_empty");
        exit;
    }
    return $organism_name;
}

function validateAssemblyParam($assembly, $redirect_on_empty = null) {
    if (empty($assembly)) {
        if ($redirect_on_empty === null) {
            $site = ConfigManager::getInstance()->getString('site');
            $redirect_on_empty = "/$site/index.php";
        }
        header("Location: $redirect_on_empty");
        exit;
    }
    return $assembly;
}

function decodeAnnotationText($text) {
    if (empty($text)) {
        return $text;
    }
    // Decode URL-encoded characters: %XX -> character
    return preg_replace_callback('/%([0-9A-F]{2})/i', function($matches) {
        return chr(hexdec($matches[1]));
    }, $text);
}

public function __construct($url, $apiKey, $mode = 'shared') {
        $this->url = rtrim($url, '/');
        $this->apiKey = $apiKey;
        $this->mode = $mode;
    }

public function testConnection() {
        try {
            $response = $this->get('/api/users/current');

            if ($response && isset($response['quota_percent'])) {
                return [
                    'success' => true,
                    'message' => 'Connected to Galaxy'
                ];
            } else {
                return [
                    'success' => false,
                    'message' => 'Invalid response from Galaxy'
                ];
            }
        } catch (Exception $e) {
            return [
                'success' => false,
                'message' => $e->getMessage()
            ];
        }
    }

public function createHistory($userId, $toolName) {
        $historyName = sprintf(
            "MOOP - User %d - %s - %s",
            $userId,
            $toolName,
            date('Y-m-d H:i:s')
        );

        $response = $this->post('/api/histories', [
            'name' => $historyName
        ]);

        if (!$response || !isset($response['id'])) {
            throw new Exception('Failed to create history: ' . json_encode($response));
        }

        return $response['id'];
    }

public function uploadFile($historyId, $filename, $fileType = 'fasta') {
        if (!file_exists($filename)) {
            throw new Exception("File not found: $filename");
        }

        // Read file content
        $fileContent = file_get_contents($filename);

        // For UseGalaxy.org, we need to use form data
        // Create a temporary URL or use direct upload
        $response = $this->uploadFileContent(
            $historyId,
            basename($filename),
            $fileContent,
            $fileType
        );

        if (!$response || !isset($response['id'])) {
            throw new Exception('Failed to upload file: ' . json_encode($response));
        }

        return $response['id'];
    }

private function uploadFileContent($historyId, $filename, $content, $fileType) {
        // Use the same approach as the working shell script: POST to /api/tools with upload1 tool
        $payload = [
            'history_id' => $historyId,
            'tool_id' => 'upload1',
            'inputs' => [
                'files_0|url_paste' => $content,
                'files_0|type' => 'upload_dataset',
                'files_0|NAME' => $filename,
                'dbkey' => '?',
                'file_type' => $fileType
            ]
        ];

        try {
            $response = $this->post('/api/tools', $payload);
        } catch (Exception $e) {
            error_log("Upload failed: " . $e->getMessage());
            throw new Exception("Upload API error: " . $e->getMessage());
        }

        if (!$response) {
            error_log("Upload response is empty");
            return null;
        }

        // Galaxy returns: { outputs: [ { id: ... } ], ... }
        if (isset($response['outputs']) && is_array($response['outputs']) && count($response['outputs']) > 0) {
            return ['id' => $response['outputs'][0]['id']];
        }

        // Fallback: direct ID response
        if (isset($response['id'])) {
            return $response;
        }

        return null;
    }

public function runTool($historyId, $toolId, $inputs) {
        $payload = [
            'history_id' => $historyId,
            'tool_id' => $toolId,
            'inputs' => $inputs
        ];

        $response = $this->post('/api/tools', $payload);

        if (!$response || !isset($response['outputs'][0]['id'])) {
            throw new Exception('Failed to run tool: ' . json_encode($response));
        }

        // Return the output dataset ID (we'll use this to track the job)
        return [
            'job_id' => $response['jobs'][0]['id'] ?? null,
            'output_id' => $response['outputs'][0]['id']
        ];
    }

public function getJobStatus($jobId) {
        $response = $this->get('/api/jobs/' . urlencode($jobId));

        return [
            'state' => $response['state'] ?? 'unknown',
            'status' => $response['status'] ?? 'unknown',
            'create_time' => $response['create_time'] ?? null,
            'update_time' => $response['update_time'] ?? null,
            'tool_id' => $response['tool_id'] ?? null
        ];
    }

public function getDatasetContent($datasetId) {
        // Download dataset
        $url = $this->url . '/api/datasets/' . urlencode($datasetId) . '/download';

        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, $this->timeout);
        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, true);
        curl_setopt($ch, CURLOPT_HTTPHEADER, [
            'x-api-key: ' . $this->apiKey
        ]);

        $content = curl_exec($ch);
        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        curl_close($ch);

        if ($httpCode >= 200 && $httpCode < 300) {
            return $content;
        } else {
            throw new Exception("Failed to download dataset: HTTP $httpCode");
        }
    }

public function waitForCompletion($jobId, $maxWaitSeconds = 3600) {
        $startTime = time();
        $pollInterval = 5; // Start with 5 seconds

        while ((time() - $startTime) < $maxWaitSeconds) {
            $status = $this->getJobStatus($jobId);

            if ($status['state'] === 'ok') {
                return ['success' => true, 'status' => $status];
            } else if ($status['state'] === 'error') {
                return ['success' => false, 'status' => $status, 'error' => 'Job failed'];
            }

            // Wait before polling again
            sleep($pollInterval);
            // Gradually increase poll interval (up to 30 seconds)
            $pollInterval = min($pollInterval + 2, 30);
        }

        return [
            'success' => false,
            'status' => $status,
            'error' => 'Job timeout'
        ];
    }

public function getDatasetInfo($datasetId) {
        $response = $this->get('/api/datasets/' . urlencode($datasetId));

        return [
            'id' => $response['id'] ?? null,
            'name' => $response['name'] ?? null,
            'state' => $response['state'] ?? null,
            'visible' => $response['visible'] ?? true,
            'file_size' => $response['file_size'] ?? 0,
            'created' => $response['create_time'] ?? null
        ];
    }

public function listHistories($limit = 10) {
        $response = $this->get('/api/histories?limit=' . $limit);

        if (!is_array($response)) {
            return [];
        }

        return $response;
    }

public function deleteHistory($historyId) {
        try {
            $response = $this->delete('/api/histories/' . urlencode($historyId));
            return true;
        } catch (Exception $e) {
            return false;
        }
    }

