/**
* Get all color schemes
*/

functions.code:
public static function getSchemes()
    {
        return self::$schemes;
    }

public static function getScheme($name)
    {
        // Handle exact color: exact=ColorName
        if (strpos($name, 'exact=') === 0) {
            $color = substr($name, 6); // Remove "exact="
            return [$color]; // Return as single-element array
        }

        // Handle specific index: blues3 (0-indexed)
        if (preg_match('/^([a-z]+)(\d+)$/', $name, $matches)) {
            $schemeName = $matches[1];
            $index = intval($matches[2]);

            if (isset(self::$schemes[$schemeName])) {
                $scheme = self::$schemes[$schemeName];
                if ($index < count($scheme)) {
                    return [$scheme[$index]]; // Return single color as array
                }
            }
            return null; // Invalid scheme or index
        }

        // Regular scheme name
        return self::$schemes[$name] ?? null;
    }

functions.comment:
/**
* Get color scheme info
*/

functions.code:
public static function getInfo($name)
    {
        return self::$info[$name] ?? ['type' => 'unknown', 'best_for' => 'general use'];
    }

public static function listSchemes()
    {
        // Build sorted list
        $groups = [];
        foreach (self::$schemes as $name => $colors) {
            $info = self::$info[$name] ?? ['type' => 'unknown', 'best_for' => 'general use'];
            $groups[] = [
                'name' => $name,
                'count' => count($colors),
                'type' => $info['type'],
                'best_for' => $info['best_for']
            ];
        }

        // Sort by count (descending), then name
        usort($groups, function($a, $b) {
            if ($b['count'] != $a['count']) {
                return $b['count'] - $a['count'];
            }
            return strcmp($a['name'], $b['name']);
        });

        // Display formatted table
        echo str_repeat('=', 80) . "\n";
        echo "AVAILABLE COLOR GROUPS\n";
        echo str_repeat('=', 80) . "\n\n";

        printf("%-15s %-8s %-12s %s\n", "Group", "Colors", "Type", "Best For");
        echo str_repeat('-', 80) . "\n";

        foreach ($groups as $group) {
            printf("%-15s %-8d %-12s %s\n", 
                $group['name'], 
                $group['count'], 
                $group['type'], 
                $group['best_for']
            );
        }

        echo "\n" . str_repeat('=', 80) . "\n";
        echo "USAGE EXAMPLES:\n";
        echo str_repeat('-', 80) . "\n";
        echo "  ## blues: Sample Group          # Use blues color group\n";
        echo "  ## exact=OrangeRed: Group       # Use specific color\n";
        echo "  ## reds3: Group                 # Use 4th color from reds (0-indexed)\n";
        echo str_repeat('=', 80) . "\n";
    }

public static function suggestSchemes($numFiles, $maxSuggestions = 5)
    {
        $suitable = [];

        foreach (self::$schemes as $name => $colors) {
            if (count($colors) >= $numFiles) {
                $info = self::$info[$name] ?? ['type' => 'unknown', 'best_for' => 'general use'];
                $suitable[] = [
                    'name' => $name,
                    'count' => count($colors),
                    'type' => $info['type'],
                    'best_for' => $info['best_for']
                ];
            }
        }

        // Sort by: closest to needed count, then by name
        usort($suitable, function($a, $b) use ($numFiles) {
            $diffA = abs($a['count'] - $numFiles);
            $diffB = abs($b['count'] - $numFiles);
            if ($diffA != $diffB) {
                return $diffA - $diffB;
            }
            return strcmp($a['name'], $b['name']);
        });

        return array_slice($suitable, 0, $maxSuggestions);
    }

public static function displaySuggestions($numFiles)
    {
        $suggestions = self::suggestSchemes($numFiles, 5);

        if (empty($suggestions)) {
            echo "No color schemes have $numFiles or more colors.\n";
            echo "Largest available: " . max(array_map('count', self::$schemes)) . " colors\n";
            return;
        }

        echo str_repeat('=', 80) . "\n";
        echo "COLOR GROUP SUGGESTIONS FOR $numFiles FILES\n";
        echo str_repeat('=', 80) . "\n\n";

        printf("%-15s %-8s %-12s %s\n", "Group", "Colors", "Type", "Best For");
        echo str_repeat('-', 80) . "\n";

        foreach ($suggestions as $group) {
            printf("%-15s %-8d %-12s %s\n", 
                $group['name'], 
                $group['count'], 
                $group['type'], 
                $group['best_for']
            );
        }

        echo "\nRECOMMENDED:\n";
        echo "  ## {$suggestions[0]['name']}: Your Group Name\n\n";
        echo str_repeat('=', 80) . "\n";
    }

public function download($sheetId, $gid)
    {
        $url = "https://docs.google.com/spreadsheets/d/$sheetId/export?format=tsv&gid=$gid";

        // Use file_get_contents with error handling
        $content = @file_get_contents($url);

        if ($content === false) {
            throw new RuntimeException(
                "Failed to download Google Sheet. Check sheet ID and GID are correct and sheet is publicly accessible.\n" .
                "URL: $url"
            );
        }

        if (empty($content)) {
            throw new RuntimeException("Downloaded sheet is empty");
        }

        return $content;
    }

public function parseTracks($content, $organism, $assembly)
    {
        $lines = explode("\n", $content);

        if (empty($lines)) {
            return ['regular' => [], 'combo' => []];
        }

        // Parse header
        $header = str_getcsv(trim($lines[0]), "\t");
        $header[0] = preg_replace('/^\xEF\xBB\xBF/', '', $header[0]); // Remove BOM

        // Normalize column names to lowercase for consistency
        $header = array_map('strtolower', $header);

        // Filter out columns starting with #
        $validColumns = [];
        $validIndices = [];
        foreach ($header as $index => $col) {
            if (!preg_match('/^#/', $col)) {
                $validColumns[] = $col;
                $validIndices[] = $index;
            }
        }

        // Parse all rows
        $regularTracks = [];
        $comboTracks = [];

        $inCombo = false;
        $comboName = null;
        $comboGroup = null;
        $comboColor = null;
        $currentCombo = null;

        for ($i = 1; $i < count($lines); $i++) {
            $line = trim($lines[$i]);

            if (empty($line)) {
                continue;
            }

            // Check for combo track markers
            if (preg_match('/^###/', $line)) {
                // End of combo track
                if ($currentCombo && !empty($currentCombo['groups'])) {
                    $comboTracks[] = $currentCombo;
                }
                $inCombo = false;
                $comboName = null;
                $comboGroup = null;
                $currentCombo = null;
                continue;

            } elseif (preg_match('/^# ([^#].*)/', $line, $matches)) {
                // Start of combo track: # SIMR:Four_Adult_Tissues_MOLNG-2707
                $comboName = trim($matches[1]);
                $inCombo = true;
                $currentCombo = [
                    'track_id' => strtolower(str_replace([' ', ',', ':'], ['_', '', '_'], $comboName)),
                    'name' => $comboName,
                    'organism' => $organism,
                    'assembly' => $assembly,
                    'groups' => []
                ];
                continue;

            } elseif (preg_match('/^## (\S+):\s*(.+)/', $line, $matches)) {
                // Color group: ## greens: body_wall +
                $comboColor = trim($matches[1]);
                $comboGroup = trim($matches[2]);

                if ($currentCombo) {
                    $currentCombo['groups'][$comboGroup] = [
                        'color' => $comboColor,
                        'tracks' => []
                    ];
                }
                continue;
            }

            // Parse data row
            $values = str_getcsv($line, "\t");

            // Filter to valid columns
            $filteredValues = [];
            foreach ($validIndices as $index) {
                $filteredValues[] = $values[$index] ?? '';
            }

            // Create associative array
            $row = [];
            foreach ($validColumns as $index => $columnName) {
                $row[$columnName] = $filteredValues[$index] ?? '';
            }

            // Skip if missing required fields
            if (empty($row['track_id']) || empty($row['name']) || empty($row['track_path'])) {
                continue;
            }

            // Add organism and assembly
            $row['organism'] = $organism;
            $row['assembly'] = $assembly;

            // Generate browser track ID from file path (for JBrowse2 config)
            $row['browser_track_id'] = $this->generateBrowserTrackId($row['track_path']);

            // Clean track data
            $track = $this->cleanTrackData($row);

            // Add to combo group if we're in a combo track
            if ($inCombo && $currentCombo && $comboGroup) {
                $currentCombo['groups'][$comboGroup]['tracks'][] = $track;
            }

            // Always add to regular tracks (combo tracks are made from regular tracks)
            $regularTracks[] = $track;
        }

        // Add final combo track if we're still in one
        if ($currentCombo && !empty($currentCombo['groups'])) {
            $comboTracks[] = $currentCombo;
        }

        return [
            'regular' => $regularTracks,
            'combo' => $comboTracks
        ];
    }

public function parseTSV($content)
    {
        $lines = explode("\n", $content);

        if (empty($lines)) {
            return [];
        }

        // First line is header
        $header = str_getcsv(trim($lines[0]), "\t");

        // Remove BOM if present
        $header[0] = preg_replace('/^\xEF\xBB\xBF/', '', $header[0]);

        // Normalize column names to lowercase for consistency
        $header = array_map('strtolower', $header);

        $rows = [];

        // Parse data rows
        for ($i = 1; $i < count($lines); $i++) {
            $line = trim($lines[$i]);

            // Skip empty lines
            if (empty($line)) {
                continue;
            }

            $values = str_getcsv($line, "\t");

            // Create associative array
            $row = [];
            foreach ($header as $index => $columnName) {
                $row[$columnName] = $values[$index] ?? '';
            }

            $rows[] = $row;
        }

        return $rows;
    }

public function extractRegularTracks($parsed)
    {
        $tracks = [];

        foreach ($parsed as $row) {
            // Skip if missing required fields
            if (empty($row['track_id']) || empty($row['name'])) {
                continue;
            }

            // Skip if no TRACK_PATH (might be combo track definition)
            if (empty($row['track_path'])) {
                continue;
            }

            // Skip if TRACK_PATH is "AUTO" but this is a combo track row
            if (strtoupper($row['track_path']) === 'AUTO' && !empty($row['combo_track_id'])) {
                continue;
            }

            // Clean up the row
            $track = $this->cleanTrackData($row);

            $tracks[] = $track;
        }

        return $tracks;
    }

public function extractComboTracks($parsed)
    {
        $comboTracks = [];

        // Group rows by COMBO_TRACK_ID
        $comboGroups = [];
        foreach ($parsed as $row) {
            if (!empty($row['combo_track_id'])) {
                $comboId = $row['combo_track_id'];
                if (!isset($comboGroups[$comboId])) {
                    $comboGroups[$comboId] = [];
                }
                $comboGroups[$comboId][] = $row;
            }
        }

        // Process each combo track
        foreach ($comboGroups as $comboId => $rows) {
            // Use first row for track metadata
            $firstRow = $rows[0];

            // Map ACCESS column to access_level
            $accessLevel = trim($firstRow['access'] ?? $firstRow['access_level'] ?? 'PUBLIC');

            $comboTrack = [
                'track_id' => $comboId,
                'name' => $firstRow['combo_name'] ?? $comboId,
                'category' => $firstRow['category'] ?? 'Combo',
                'access_level' => $accessLevel,
                'organism' => $firstRow['organism'],
                'assembly' => $firstRow['assembly'],
                'files' => [],
                'names' => [],
                'colors' => []
            ];

            // Extract file paths, names, and colors
            foreach ($rows as $row) {
                if (!empty($row['track_path'])) {
                    $comboTrack['files'][] = $row['track_path'];
                    $comboTrack['names'][] = $row['name'] ?? basename($row['track_path']);
                    $comboTrack['colors'][] = $row['color'] ?? '';
                }
            }

            // Only add if we have files
            if (!empty($comboTrack['files'])) {
                $comboTracks[] = $comboTrack;
            }
        }

        return $comboTracks;
    }

private function normalizeTrackPath(string $path): string
    {
        // Collapse accidental double (or more) slashes in the path portion of a URL
        // without touching the :// in the scheme (https://, http://)
        if (preg_match('/^https?:\/\//i', $path)) {
            // Split on :// so we only normalize the part after the scheme
            [$scheme, $rest] = explode('://', $path, 2);
            $rest = preg_replace('#/{2,}#', '/', $rest);
            return $scheme . '://' . $rest;
        }
        return $path;
    }

private function cleanTrackData($row)
    {
        // Map ACCESS column to access_level
        $accessLevel = trim($row['access'] ?? $row['access_level'] ?? 'PUBLIC');

        return [
            'track_id' => trim($row['track_id']),
            'browser_track_id' => trim($row['browser_track_id'] ?? ''),
            'name' => trim($row['name']),
            'TRACK_PATH' => $this->normalizeTrackPath(trim($row['track_path'])),
            'category' => trim($row['category'] ?? 'Uncategorized'),
            'access_level' => $accessLevel,
            'color' => trim($row['color'] ?? ''),
            'description' => trim($row['description'] ?? ''),
            'organism' => $row['organism'],
            'assembly' => $row['assembly'],

            // Optional metadata fields
            'technique' => trim($row['technique'] ?? ''),
            'institute' => trim($row['institute'] ?? ''),
            'source' => trim($row['source'] ?? ''),
            'experiment' => trim($row['experiment'] ?? ''),
            'developmental_stage' => trim($row['developmental_stage'] ?? ''),
            'tissue' => trim($row['tissue'] ?? ''),
            'condition' => trim($row['condition'] ?? ''),
            'summary' => trim($row['summary'] ?? ''),
        ];
    }

public function validateColumns($parsed)
    {
        if (empty($parsed)) {
            return [
                'valid' => false,
                'missing' => ['Sheet is empty']
            ];
        }

        $firstRow = $parsed[0];
        $actualColumns = array_keys($firstRow);

        $missing = [];
        foreach ($this->requiredColumns as $required) {
            if (!in_array($required, $actualColumns)) {
                $missing[] = $required;
            }
        }

        return [
            'valid' => empty($missing),
            'missing' => $missing
        ];
    }

public function getStatistics($tracks)
    {
        return [
            'regular_tracks' => count($tracks['regular']),
            'combo_tracks' => count($tracks['combo']),
            'total' => count($tracks['regular']) + count($tracks['combo'])
        ];
    }

public function generateBrowserTrackId($filePath)
    {
        if (empty($filePath)) {
            return '';
        }

        // Create MD5 hash of the file path
        $hash = md5($filePath);

        // Take first 10 characters for a compact ID
        return "track_" . substr($hash, 0, 10);
    }

public function __construct($config)
    {
        $this->config = $config;
        $this->tracksServerConfig = $config->get('tracks_server', []);
    }

public function toWebUri($filesystemPath)
    {
        if (empty($filesystemPath)) {
            throw new InvalidArgumentException("Filesystem path cannot be empty");
        }

        // If already a URL, return as-is — don't strip the host
        if ($this->isRemote($filesystemPath)) {
            return $filesystemPath;
        }

        // Check if this is a reference genome (always local)
        $isReferenceGenome = strpos($filesystemPath, '/data/genomes/') !== false || 
                            strpos($filesystemPath, '/genomes/') !== false;

        // Get site configuration
        $sitePath = $this->config->getPath('site_path');
        $site = $this->config->getString('site');

        // Local filesystem paths always serve locally — if you want remote serving,
        // register the file with its remote https:// URL directly in the sheet.
        if (false) {
            // (remote routing block disabled — kept for reference)
        } else {
            // Local server
            // Extract the path after the site directory name
            // Works for any deployment:
            //   /data/moop/data/tracks/... -> /moop/data/tracks/...
            //   /var/www/html/moop/data/tracks/... -> /moop/data/tracks/...
            //   /opt/simrbase/data/tracks/... -> /simrbase/data/tracks/...

            // Find the site directory in the path
            $parts = explode('/', $filesystemPath);
            $siteIndex = array_search($site, $parts);

            if ($siteIndex === false) {
                throw new InvalidArgumentException(
                    "Cannot determine web URI: site directory '$site' not found in path '$filesystemPath'"
                );
            }

            // Build URI from site directory onward
            $uriParts = array_slice($parts, $siteIndex);
            return '/' . implode('/', $uriParts);
        }
    }

public function toFilesystemPath($webUri)
    {
        if (empty($webUri)) {
            throw new InvalidArgumentException("Web URI cannot be empty");
        }

        // If it's a full URL (http:// or https://), return as-is
        if ($this->isRemote($webUri)) {
            return $webUri;
        }

        // Local URI - convert to filesystem path
        $sitePath = $this->config->getPath('site_path');
        $site = $this->config->getString('site');

        // Remove leading slash and site name from URI
        $webUri = ltrim($webUri, '/');
        if (strpos($webUri, $site . '/') === 0) {
            $webUri = substr($webUri, strlen($site) + 1);
        }

        // Build filesystem path
        return $sitePath . '/' . $webUri;
    }

public function resolveTrackPath($path, $organism = null, $assembly = null, $type = null)
    {
        if (empty($path)) {
            throw new InvalidArgumentException("Track path cannot be empty");
        }

        // Handle AUTO keyword (reference genome and annotations)
        if (strtoupper($path) === 'AUTO') {
            return $this->resolveAutoPath($organism, $assembly, $type);
        }

        // Remote URL - return as-is
        if ($this->isRemote($path)) {
            return [$path, true];
        }

        // Absolute path - return as-is
        if ($path[0] === '/') {
            return [$path, false];
        }

        // Relative path - prepend site_path
        $sitePath = $this->config->getPath('site_path');
        $absolutePath = $sitePath . '/' . ltrim($path, '/');
        return [$absolutePath, false];
    }

private function resolveAutoPath($organism, $assembly, $type)
    {
        if (empty($organism) || empty($assembly)) {
            throw new InvalidArgumentException(
                "AUTO paths require --organism and --assembly parameters"
            );
        }

        // Get genomes directory from config (required)
        $jbrowse2Config = $this->config->get('jbrowse2');
        if (empty($jbrowse2Config['genomes_directory'])) {
            throw new RuntimeException(
                "Configuration error: jbrowse2.genomes_directory not defined in site_config.php"
            );
        }

        $genomesDir = rtrim($jbrowse2Config['genomes_directory'], '/');

        switch ($type) {
            case 'fasta':
                // Symlinked from /organisms/{organism}/{assembly}/{genome_pattern}
                // to {genomes_directory}/{organism}/{assembly}/reference.fasta
                $path = "$genomesDir/$organism/$assembly/reference.fasta";
                break;

            case 'gff':
                // Compressed from /organisms/{organism}/{assembly}/{annotation_pattern}
                // to {genomes_directory}/{organism}/{assembly}/annotations.gff3.gz
                $path = "$genomesDir/$organism/$assembly/annotations.gff3.gz";
                break;

            default:
                throw new InvalidArgumentException(
                    "AUTO only supported for fasta and gff track types, not '$type'"
                );
        }

        return [$path, false];
    }

public function isRemote($path)
    {
        return preg_match('#^https?://#i', $path) === 1;
    }

public function isTracksServerEnabled()
    {
        return !empty($this->tracksServerConfig['enabled']);
    }

public function getTracksServerUrl()
    {
        return $this->tracksServerConfig['url'] ?? null;
    }

public function fileExists($path)
    {
        // Can't check remote URLs
        if ($this->isRemote($path)) {
            return true; // Assume remote URLs are valid
        }

        return file_exists($path);
    }

public function getTrackDirectory($organism, $assembly, $trackType)
    {
        $jbrowse2Config = $this->config->get('jbrowse2');
        if (empty($jbrowse2Config['tracks_directory'])) {
            throw new RuntimeException(
                "Configuration error: jbrowse2.tracks_directory not defined in site_config.php"
            );
        }

        $tracksDir = rtrim($jbrowse2Config['tracks_directory'], '/');
        $fullPath = "$tracksDir/$organism/$assembly/$trackType";

        // Ensure directory exists
        $this->ensureDirectoryExists($fullPath);

        return $fullPath;
    }

public function getMetadataDirectory($organism, $assembly, $trackType)
    {
        $metadataDir = $this->config->getPath('metadata_path');
        $fullPath = "$metadataDir/jbrowse2-configs/tracks/$organism/$assembly/$trackType";

        // Ensure directory exists
        $this->ensureDirectoryExists($fullPath);

        return $fullPath;
    }

private function ensureDirectoryExists($path)
    {
        if (!is_dir($path)) {
            if (!mkdir($path, 0775, true)) {
                throw new RuntimeException(
                    "Failed to create directory: $path"
                );
            }
        }
    }

function loadJBrowse2Plugins() {
    $pluginFile = __DIR__ . '/../../config/jbrowse2_plugins.json';

    if (!file_exists($pluginFile)) {
        error_log("JBrowse2 plugin config not found: $pluginFile");
        return [];
    }

    $plugins = loadJsonFile($pluginFile, []);

    if (!is_array($plugins)) {
        error_log("Invalid JBrowse2 plugin config format");
        return [];
    }

    // Filter to only enabled plugins and return in JBrowse2 format
    $enabledPlugins = [];
    foreach ($plugins as $plugin) {
        if (isset($plugin['enabled']) && $plugin['enabled'] === true) {
            $enabledPlugins[] = [
                'name' => $plugin['name'],
                'url' => $plugin['url']
            ];
        }
    }

    return $enabledPlugins;
}

function getJBrowse2PluginConfiguration() {
    return loadJBrowse2Plugins();
}

public function __construct($config)
    {
        $this->config = $config;
        $this->pathResolver = new PathResolver($config);
        $this->sheetsParser = new GoogleSheetsParser();

        // Register track type handlers
        $this->registerTrackTypes();
    }

private function registerTrackTypes()
    {
        // Map track type identifier to class name
        // NOTE: PAF, PIF, and MCScan are dual-assembly synteny tracks
        // and should be generated using generate_synteny_tracks_from_sheet.php
        $trackTypeClasses = [
            'bigwig' => 'BigWigTrack',
            'bam' => 'BamTrack',
            'combo' => 'ComboTrack',
            'auto' => 'AutoTrack',
            'vcf' => 'VCFTrack',
            'bed' => 'BEDTrack',
            'gtf' => 'GTFTrack',
            'gff' => 'GFFTrack',
            'cram' => 'CRAMTrack',
            'maf' => 'MAFTrack',  // Multiple alignment format (single-assembly)
            // Optional: 'bigbed' => 'BigBedTrack',  // For BigMaf conversion
            // Dual-assembly synteny tracks (NOT registered here):
            // - paf, pif, mcscan
            // Use: generate_synteny_tracks_from_sheet.php
        ];

        // Load and instantiate each track type
        foreach ($trackTypeClasses as $type => $className) {
            $classFile = __DIR__ . "/TrackTypes/$className.php";

            if (file_exists($classFile)) {
                require_once $classFile;

                if (class_exists($className)) {
                    $this->trackTypes[$type] = new $className($this->pathResolver, $this->config);
                } else {
                    error_log("TrackGenerator: Class $className not found in $classFile");
                }
            } else {
                error_log("TrackGenerator: Track type file not found: $classFile");
            }
        }
    }

public function getTrackTypeHandler($type)
    {
        return $this->trackTypes[$type] ?? null;
    }

public function getRegisteredTrackTypes()
    {
        return array_keys($this->trackTypes);
    }

public function determineTrackType($path)
    {
        // Check for AUTO keyword - reference sequences and annotations
        // These are handled by assembly setup, not as separate tracks
        if (strtoupper(trim($path)) === 'AUTO') {
            return 'auto';
        }

        // Check against each registered track type
        foreach ($this->trackTypes as $type => $handler) {
            foreach ($handler->getValidExtensions() as $ext) {
                if (preg_match('/' . preg_quote($ext, '/') . '$/i', $path)) {
                    return $type;
                }
            }
        }

        return null;
    }

public function loadFromSheet($sheetId, $gid, $organism, $assembly)
    {
        // Download sheet content
        $content = $this->sheetsParser->download($sheetId, $gid);

        // Parse tracks
        $tracks = $this->sheetsParser->parseTracks($content, $organism, $assembly);

        // Validate columns
        $parsed = $this->sheetsParser->parseTSV($content);
        $validation = $this->sheetsParser->validateColumns($parsed);

        if (!$validation['valid']) {
            throw new RuntimeException(
                "Sheet missing required columns: " . implode(', ', $validation['missing'])
            );
        }

        return $tracks;
    }

public function generateTracks($tracks, $options = [])
    {
        $results = [
            'success' => [],
            'failed' => [],
            'skipped' => [],
            'stats' => [
                'total' => 0,
                'created' => 0,
                'failed' => 0,
                'skipped' => 0
            ]
        ];

        // Get force list (empty array means force all)
        $forceIds = $options['force'] ?? null;
        $dryRun = !empty($options['dry_run']);

        // Process regular tracks
        foreach ($tracks['regular'] as $track) {
            $results['stats']['total']++;

            // Determine if we should force regenerate this track
            $shouldForce = false;
            if ($forceIds !== null) {
                if (empty($forceIds)) {
                    // Empty array = force all
                    $shouldForce = true;
                } elseif (in_array($track['track_id'], $forceIds)) {
                    // Specific track ID in force list
                    $shouldForce = true;
                }
            }

            // Check if track exists
            $trackExists = $this->trackExists($track['track_id'], $track['organism'], $track['assembly']);

            if ($trackExists && !$shouldForce) {
                $results['skipped'][] = $track['track_id'];
                $results['stats']['skipped']++;
                continue;
            }

            // Output what we're doing
            if ($shouldForce && $trackExists) {
                echo "  ♻ Regenerating: " . $track['track_id'] . " (" . $track['name'] . ")\n";
            }

            // Generate track
            $result = $this->generateSingleTrack($track, ['force' => $shouldForce, 'dry_run' => $dryRun]);

            if ($result === 'skipped') {
                // Track generation was skipped (e.g., assembly already exists)
                $results['skipped'][] = $track['track_id'];
                $results['stats']['skipped']++;
                echo "  ⊘ Skipped: " . $track['track_id'] . " (already exists)\n";
            } elseif ($result === true) {
                $results['success'][] = [
                    'track_id' => $track['track_id'],
                    'name' => $track['name'],
                    'regenerated' => ($shouldForce && $trackExists)
                ];
                $results['stats']['created']++;

                // Show what was created/regenerated
                if ($shouldForce && $trackExists) {
                    echo "    ✓ Regenerated successfully\n";
                } else {
                    echo "  ✓ Created: " . $track['track_id'] . " (" . $track['name'] . ")\n";
                }
            } else {
                // Check why it failed
                $trackType = $this->determineTrackType($track['TRACK_PATH']);
                $errorMsg = 'Generation failed';

                if (!$trackType) {
                    $errorMsg = 'Unknown track type: ' . basename($track['TRACK_PATH']);
                }

                $results['failed'][] = [
                    'track_id' => $track['track_id'],
                    'name' => $track['name'],
                    'error' => $errorMsg
                ];
                $results['stats']['failed']++;
                echo "  ✗ Failed: " . $track['track_id'] . " (" . $errorMsg . ")\n";
            }
        }

        // Process combo tracks
        if (!empty($tracks['combo'])) {
            echo "\nProcessing combo tracks...\n";
            echo str_repeat('-', 60) . "\n";

            foreach ($tracks['combo'] as $combo) {
                // Determine if we should force regenerate this track
                $shouldForce = false;
                if ($forceIds !== null) {
                    if (empty($forceIds)) {
                        // Empty array = force all
                        $shouldForce = true;
                    } elseif (in_array($combo['track_id'], $forceIds)) {
                        // Specific track ID in force list
                        $shouldForce = true;
                    }
                }

                // Check if track exists and should skip
                $trackFile = $this->config->getPath('site_path') . '/metadata/jbrowse2-configs/tracks/' . 
                            $combo['organism'] . '/' . $combo['assembly'] . '/combo/' . 
                            strtolower($combo['track_id']) . '.json';

                if (!$shouldForce && file_exists($trackFile)) {
                    echo "  ⊘ Skipping " . $combo['track_id'] . " (already exists, use --force to regenerate)\n";
                    $results['skipped'][] = $combo['track_id'];
                    $results['stats']['skipped']++;
                    continue;
                }

                $results['stats']['total']++;

                // Generate combo track
                if (isset($this->trackTypes['combo'])) {
                    $success = $this->trackTypes['combo']->generate(
                        $combo,
                        $combo['organism'],
                        $combo['assembly'],
                        ['dry_run' => $dryRun]
                    );

                    if ($success) {
                        $results['success'][] = $combo['track_id'];
                        $results['stats']['created']++;
                    } else {
                        $results['failed'][] = [
                            'track_id' => $combo['track_id'],
                            'name' => $combo['name'],
                            'error' => 'Combo track generation failed'
                        ];
                        $results['stats']['failed']++;
                    }
                } else {
                    echo "    ✗ Combo track type not registered\n";
                    $results['failed'][] = [
                        'track_id' => $combo['track_id'],
                        'name' => $combo['name'],
                        'error' => 'Combo track type not available'
                    ];
                    $results['stats']['failed']++;
                }
            }
        }

        return $results;
    }

private function generateSingleTrack($trackData, $options = [])
    {
        // Determine track type
        $trackType = $this->determineTrackType($trackData['TRACK_PATH']);

        if (!$trackType) {
            // Don't output error here - let the calling function handle it
            return false;
        }

        // Get track handler
        $handler = $this->getTrackTypeHandler($trackType);

        if (!$handler) {
            // Don't output error here - let the calling function handle it
            return false;
        }

        // Validate track
        $validation = $handler->validate($trackData);
        if (!$validation['valid']) {
            // Don't output error here - let the calling function handle it
            return false;
        }

        // Generate track
        return $handler->generate(
            $trackData,
            $trackData['organism'],
            $trackData['assembly'],
            $options
        );
    }

public function trackExists($trackId, $organism, $assembly)
    {
        // Check all track type directories
        $metadataDir = $this->config->getPath('metadata_path');
        $baseDir = "$metadataDir/jbrowse2-configs/tracks/$organism/$assembly";

        if (!is_dir($baseDir)) {
            return false;
        }

        // Check each track type directory
        $trackTypeDirs = ['bigwig', 'bam', 'vcf', 'gff', 'gtf', 'bed', 'cram', 'paf', 'maf', 'combo', 'auto'];

        foreach ($trackTypeDirs as $typeDir) {
            $trackFile = "$baseDir/$typeDir/$trackId.json";
            if (file_exists($trackFile)) {
                return true;
            }
        }

        return false;
    }

public function getTrackStatus($organism, $assembly)
    {
        $tracks = [];

        $metadataDir = $this->config->getPath('metadata_path');
        $baseDir = "$metadataDir/jbrowse2-configs/tracks/$organism/$assembly";

        if (!is_dir($baseDir)) {
            return $tracks;
        }

        // Scan each track type directory
        $trackTypeDirs = ['bigwig', 'bam', 'vcf', 'bed', 'gtf', 'gff', 'cram', 'paf', 'maf', 'combo'];

        foreach ($trackTypeDirs as $typeDir) {
            $fullPath = "$baseDir/$typeDir";
            if (!is_dir($fullPath)) {
                continue;
            }

            $files = glob("$fullPath/*.json");
            foreach ($files as $file) {
                $trackId = basename($file, '.json');
                $metadata = loadJsonFile($file, []);

                $tracks[] = [
                    'track_id' => $trackId,
                    'type' => $typeDir,
                    'name' => $metadata['name'] ?? $trackId,
                    'category' => $metadata['category'] ?? 'Unknown',
                    'file' => $file
                ];
            }
        }

        return $tracks;
    }

public function regenerateTracks($trackIds, $organism, $assembly)
