functions.code:
private function findTbiIndex(string $bedPath): ?string
    {
        // Try .bed.gz.tbi
        $tbiPath = $bedPath . '.tbi';
        if (file_exists($tbiPath)) {
            return $tbiPath;
        }

        // Try .tbi (replace .bed.gz or .bed)
        $tbiPath = preg_replace('/\.bed(\.gz)?$/i', '.tbi', $bedPath);
        if (file_exists($tbiPath)) {
            return $tbiPath;
        }

        return null;
    }

