        $craiPath = $cramPath . '.crai';
        if (file_exists($craiPath)) {
            return $craiPath;
        }

        // Try .crai (replace .cram)
        $craiPath = preg_replace('/\.cram$/i', '.crai', $cramPath);
        if (file_exists($craiPath)) {
            return $craiPath;
        }

        return null;
    }

