function moopmartCountFeatures(array $gene_set_ids, string $db_path, array $filters = []): int
{
    if (empty($gene_set_ids)) return 0;

    $params       = [];
    $placeholders = implode(',', array_fill(0, count($gene_set_ids), '?'));
    array_push($params, ...$gene_set_ids);

    $where = ["f.gene_set_id IN ($placeholders)"];

    $types = !empty($filters['feature_types'])
        ? array_values($filters['feature_types'])
        : ['gene', 'pseudogene'];
    $tp    = implode(',', array_fill(0, count($types), '?'));
    $where[] = "f.feature_type IN ($tp)";
    array_push($params, ...$types);

    if (!empty($filters['feature_ids'])) {
        $ids = $filters['feature_ids'];
        $ph  = implode(',', array_fill(0, count($ids), '?'));
        $where[] = "f.feature_uniquename IN ($ph)";
        array_push($params, ...$ids);
    }
    if (!empty($filters['gene_name'])) {
        $parsed = moopmartBuildTextConditions($filters['gene_name'], 'f.feature_name');
        if ($parsed) { foreach ($parsed['conditions'] as $c) $where[] = $c; array_push($params, ...$parsed['params']); }
    }
    if (!empty($filters['gene_description'])) {
        $parsed = moopmartBuildTextConditions($filters['gene_description'], 'f.feature_description');
        if ($parsed) { foreach ($parsed['conditions'] as $c) $where[] = $c; array_push($params, ...$parsed['params']); }
    }

    foreach ($filters['annotation_criteria'] ?? [] as $criterion) {
        $crit_where  = [];
        $crit_params = [];
        if (!empty($criterion['src'])) {
            $crit_where[]  = 'ans.annotation_source_name = ?';
            $crit_params[] = $criterion['src'];
        }
        if (!empty($criterion['acc'])) {
            $crit_where[]  = 'a.annotation_accession = ?';
            $crit_params[] = $criterion['acc'];
        }
        if (!empty($criterion['kw'])) {
            $parsed = moopmartBuildTextConditions($criterion['kw'], 'a.annotation_description');
            if ($parsed) { foreach ($parsed['conditions'] as $c) $crit_where[] = $c; array_push($crit_params, ...$parsed['params']); }
        }
        if (!empty($crit_where)) {
            $where[] = 'EXISTS (
                SELECT 1
                FROM feature           child
                JOIN feature_annotation fa2 ON fa2.feature_id         = child.feature_id
                JOIN annotation         a   ON fa2.annotation_id      = a.annotation_id
                JOIN annotation_source  ans ON a.annotation_source_id = ans.annotation_source_id
                WHERE child.parent_feature_id = f.feature_id
                  AND ' . implode(' AND ', $crit_where) . '
            )';
            array_push($params, ...$crit_params);
        }
    }

    $where_sql = implode(' AND ', $where);

    $query = "SELECT COUNT(DISTINCT f.feature_id) AS cnt
              FROM feature f
              JOIN gene_set gs ON f.gene_set_id  = gs.gene_set_id
              JOIN genome   g  ON gs.genome_id   = g.genome_id
              JOIN organism o  ON g.organism_id  = o.organism_id
              WHERE $where_sql";

    $rows = fetchData($query, $db_path, $params);
    return (int)($rows[0]['cnt'] ?? 0);
}

function moopmartGetAnnotationsForFeatures(array $feature_ids, string $db_path): array
{
    if (empty($feature_ids)) return [];

    // Annotations live on mRNA/transcript children, not on gene features directly.
    // Join through parent_feature_id so gene feature_ids resolve to their children's
    // annotations. Result is keyed by the gene (parent) feature_id.
    $result = [];
    foreach (array_chunk($feature_ids, 500) as $chunk) {
        $ph    = implode(',', array_fill(0, count($chunk), '?'));
        $query = "SELECT child.parent_feature_id   AS gene_feature_id,
                         ans.annotation_source_name,
                         a.annotation_accession,
                         a.annotation_description
                  FROM feature            child
                  JOIN feature_annotation fa  ON fa.feature_id          = child.feature_id
                  JOIN annotation         a   ON fa.annotation_id       = a.annotation_id
                  JOIN annotation_source  ans ON a.annotation_source_id = ans.annotation_source_id
                  WHERE child.parent_feature_id IN ($ph)
                  ORDER BY child.parent_feature_id, ans.annotation_source_name, a.annotation_accession";

        foreach (fetchData($query, $db_path, $chunk) as $row) {
            $gfid = $row['gene_feature_id'];
            $src  = $row['annotation_source_name'];
            $acc  = $row['annotation_accession'];
            // Deduplicate: the same accession may appear on multiple mRNA isoforms
            $result[$gfid][$src][$acc] = [
                'accession'   => $acc,
                'description' => $row['annotation_description'],
            ];
        }
    }

    // Convert inner associative-by-accession arrays to plain indexed arrays
    foreach ($result as &$by_source) {
        foreach ($by_source as &$entries) {
            $entries = array_values($entries);
        }
    }
    unset($by_source, $entries);

    return $result;
}

function moopmartGetChrNames(string $gene_set_path): array
{
    $tsv   = "$gene_set_path/feature_coords.tsv";
    if (!file_exists($tsv)) return [];

    // Source TSV stays in the organism tree; only the cache goes to the cache root.
    $cache_dir = moop_cache_dir_for($gene_set_path);
    $cache     = $cache_dir !== '' ? "$cache_dir/chr_names_cache.json" : '';
    if ($cache !== '' && file_exists($cache) && filemtime($cache) >= filemtime($tsv)) {
        return loadJsonFile($cache, []);
    }

    $chrs = [];
    $fh   = fopen($tsv, 'r');
    if ($fh === false) return [];
    while (($line = fgets($fh)) !== false) {
        $p = explode("\t", $line, 4);
        if (isset($p[2])) $chrs[trim($p[2])] = true;
    }
    fclose($fh);

    $result = array_keys($chrs);
    sort($result, SORT_NATURAL);
    if ($cache !== '') @file_put_contents($cache, json_encode($result));
    return $result;
}

function moopmartLoadGeneCoords(string $gene_set_path, array $filter_uniquenames = []): array
{
    $tsv = "$gene_set_path/feature_coords.tsv";
    if (!file_exists($tsv)) return [];

    // Build a fast lookup set when a filter is provided.
    $filter = !empty($filter_uniquenames) ? array_flip($filter_uniquenames) : null;

    $coords = [];
    $fh     = fopen($tsv, 'r');
    if ($fh === false) return [];
    while (($line = fgets($fh)) !== false) {
        $p = explode("\t", rtrim($line));
        if (count($p) < 6) continue;
        [$uniquename, $gene_id, $chr, $start, $end, $strand] = $p;

        if ($filter !== null) {
            // Targeted load: match on gene_id (col1) — feature uniquenames are gene-level,
            // but col0 in the TSV is the mRNA/isoform uniquename with a suffix.
            if (!isset($filter[$gene_id])) continue;
            if (isset($coords[$gene_id])) continue; // keep first isoform only
            $coords[$gene_id] = [
                'chr'    => $chr,
                'start'  => (int)$start,
                'end'    => (int)$end,
                'strand' => rtrim($strand),
            ];
        } else {
            // No filter: gene-level rows only (col0 === col1) for memory efficiency.
            if ($uniquename !== $gene_id) continue;
            $coords[$uniquename] = [
                'chr'    => $chr,
                'start'  => (int)$start,
                'end'    => (int)$end,
                'strand' => $strand,
            ];
        }
    }
    fclose($fh);
    return $coords;
}

function moopmartAttachCoords(array $features, array $coords_by_gs_id, array $coord_filter = []): array
{
    $filter_chr   = $coord_filter['chr']   ?? '';
    $filter_start = (int)($coord_filter['start'] ?? 0);
    $filter_end   = (int)($coord_filter['end']   ?? 0);

    $has_filter = $filter_chr !== '' || $filter_start > 0 || $filter_end > 0;

    $result = [];
    foreach ($features as $f) {
        $coords = $coords_by_gs_id[$f['gene_set_id']] ?? [];
        $entry  = $coords[$f['uniquename']] ?? null;

        if (!$entry) {
            // With a coord filter we can't verify the feature is in range — drop it.
            // Without a coord filter keep the feature; just leave coord fields empty.
            if ($has_filter) continue;
            $result[] = array_merge($f, ['chr' => '', 'start' => '', 'end' => '', 'strand' => '']);
            continue;
        }

        if ($filter_chr !== '' && $entry['chr'] !== $filter_chr) continue;
        if ($filter_start > 0 && $entry['end']   < $filter_start) continue;
        if ($filter_end   > 0 && $entry['start'] > $filter_end)   continue;

        $result[] = array_merge($f, $entry);
    }
    return $result;
}

function moopmartGetExonCoords(string $gff_path, array $gene_uniquenames): array
{
    if (!file_exists($gff_path) || empty($gene_uniquenames)) return [];

    $target_genes    = array_flip($gene_uniquenames);
    $gene_first_mrna = [];  // gene_id => mrna_id (first isoform only)
    $mrna_to_gene    = [];  // mrna_id => gene_id
    $sub_features    = [];  // gene_id => [{start, end, type, strand}]

    $mrna_types = ['mrna', 'transcript', 'lnc_rna', 'ncrna', 'pre_mirna', 'rrna', 'trna',
                   'pseudogenic_transcript', 'processed_transcript'];
    $exon_types = ['exon', 'cds', 'five_prime_utr', 'three_prime_utr', 'utr'];

    $fh = fopen($gff_path, 'r');
    if ($fh === false) return [];
    while (($line = fgets($fh)) !== false) {
        if ($line[0] === '#') continue;
        $parts = explode("\t", rtrim($line));
        if (count($parts) < 9) continue;

        $feat_type_raw = $parts[2];
        $feat_type     = strtolower($feat_type_raw);
        $attrs         = $parts[8];

        if (!preg_match('/\bID=([^;]+)/', $attrs, $mid)) continue;
        $id = $mid[1];

        $parent = null;
        if (preg_match('/\bParent=([^;,]+)/', $attrs, $pm)) {
            $parent = $pm[1];
        }

        // Detect first mRNA-type child of each target gene
        if ($parent !== null
            && isset($target_genes[$parent])
            && in_array($feat_type, $mrna_types)
            && !isset($gene_first_mrna[$parent])
        ) {
            $gene_first_mrna[$parent] = $id;
            $mrna_to_gene[$id]        = $parent;
        }

        // Collect exon/CDS/UTR children of the first isoform
        if ($parent !== null
            && isset($mrna_to_gene[$parent])
            && in_array($feat_type, $exon_types)
        ) {
            $gene_id = $mrna_to_gene[$parent];
            $sub_features[$gene_id][] = [
                'start'  => (int)$parts[3],
                'end'    => (int)$parts[4],
                'type'   => $feat_type_raw,
                'strand' => $parts[6],
            ];
        }
    }
    fclose($fh);

    foreach ($sub_features as &$feats) {
        usort($feats, fn($a, $b) => $a['start'] - $b['start']);
    }

    return $sub_features;
}

function moopmartStreamGenomicFasta(
    array $genes,
    string $assembly_dir,
    string $gff_path,
    string $mode,
    int $flank_bp,
    $handle
): void {
    $fasta = "$assembly_dir/genome.fa";
    $fai   = "$assembly_dir/genome.fa.fai";
    if (!file_exists($fasta) || !file_exists($fai)) return;

    // Pre-load all exon coords in one GFF pass for the exons mode
    $exon_coords = [];
    if ($mode === 'exons') {
        $exon_coords = moopmartGetExonCoords($gff_path, array_column($genes, 'uniquename'));
    }

    foreach ($genes as $g) {
        $uname  = $g['uniquename'];
        $chr    = $g['chr'];
        $gstart = $g['start'];
        $gend   = $g['end'];
        $strand = $g['strand'];

        if ($mode === 'exons') {
            $gene_exons = $exon_coords[$uname] ?? [];
            if (empty($gene_exons)) continue;
            $n = 0;
            foreach ($gene_exons as $exon) {
                $n++;
                $seq = extractFastaRegion($fasta, $fai, $chr, $exon['start'], $exon['end']);
                if ($seq === null) continue;
                if ($strand === '-') $seq = reverseComplement($seq);
                $header = ">$uname.{$exon['type']}$n {$chr}:{$exon['start']}-{$exon['end']}($strand)";
                fwrite($handle, "$header\n" . chunk_split($seq, 60, "\n"));
            }
            continue;
        }

        // Compute the genomic region to extract based on mode + strand
        $ext_start = $gstart;
        $ext_end   = $gend;
        $rc        = ($strand === '-');

        if ($mode === 'upstream') {
            if ($strand === '+') {
                $ext_start = max(1, $gstart - $flank_bp);
                $ext_end   = $gstart - 1;
                $rc        = false;
            } else {
                $ext_start = $gend + 1;
                $ext_end   = $gend + $flank_bp;
                $rc        = true;
            }
        } elseif ($mode === 'downstream') {
            if ($strand === '+') {
                $ext_start = $gend + 1;
                $ext_end   = $gend + $flank_bp;
                $rc        = false;
            } else {
                $ext_start = max(1, $gstart - $flank_bp);
                $ext_end   = $gstart - 1;
                $rc        = true;
            }
        }

        if ($ext_start < 1 || $ext_start > $ext_end) continue;

        $seq = extractFastaRegion($fasta, $fai, $chr, $ext_start, $ext_end);
        if ($seq === null) continue;
        if ($rc) $seq = reverseComplement($seq);

        $label = match($mode) {
            'upstream'   => "upstream_{$flank_bp}bp",
            'downstream' => "downstream_{$flank_bp}bp",
            default      => 'gene',
        };
        $header = ">$uname $label {$chr}:{$ext_start}-{$ext_end}($strand)";
        fwrite($handle, "$header\n" . chunk_split($seq, 60, "\n"));
    }
}

function moopmartParsePreviewRequest(array $post): array {
    // Raw input IDs (resolved per-organism downstream)
    $raw_input_ids = array_values(array_filter(array_map('trim', (array)($post['feature_ids'] ?? []))));

    // Base filters (no feature_ids — those are resolved per-organism)
    $filters = [];
    $types = array_filter($post['feature_types'] ?? []);
    if (!empty($types))                     $filters['feature_types']    = array_values($types);
    if (!empty($post['gene_name']))         $filters['gene_name']        = trim($post['gene_name']);
    if (!empty($post['gene_description']))  $filters['gene_description'] = trim($post['gene_description']);

    $crit_srcs = $post['ann_criteria_src'] ?? [];
    $crit_accs = $post['ann_criteria_acc'] ?? [];
    $crit_kws  = $post['ann_criteria_kw']  ?? [];
    $criteria  = [];
    foreach (array_keys((array)$crit_srcs) as $i) {
        $src = trim($crit_srcs[$i] ?? '');
        $acc = trim($crit_accs[$i] ?? '');
        $kw  = trim($crit_kws[$i]  ?? '');
        if ($src !== '' || $acc !== '' || $kw !== '') {
            $criteria[] = ['src' => $src, 'acc' => $acc, 'kw' => $kw];
        }
    }
    if (!empty($criteria)) $filters['annotation_criteria'] = $criteria;

    $coord_filter = [];
    if (!empty($post['coord_chr']))   $coord_filter['chr']   = trim($post['coord_chr']);
    if (!empty($post['coord_start'])) $coord_filter['start'] = (int)$post['coord_start'];
    if (!empty($post['coord_end']))   $coord_filter['end']   = (int)$post['coord_end'];

    // Uniform reason string for non-ID filters (same for every matched row)
    $global_filter_reason = buildMoopmartFilterReason($filters, $coord_filter);

    // Annotation columns for the preview (which sources, and ID vs Description)
    $annotation_columns = array_values(array_filter($post['annotation_columns'] ?? []));
    $requested_ann      = array_flip(array_values(array_filter($post['ann_columns'] ?? [])));
    $ann_incl_id        = empty($requested_ann) || isset($requested_ann['ann_id']);
    $ann_incl_desc      = empty($requested_ann) || isset($requested_ann['ann_description']);

    return [
        'raw_input_ids'        => $raw_input_ids,
        'filters'              => $filters,
        'coord_filter'         => $coord_filter,
        'global_filter_reason' => $global_filter_reason,
        'annotation_columns'   => $annotation_columns,
        'ann_incl_id'          => $ann_incl_id,
        'ann_incl_desc'        => $ann_incl_desc,
    ];
}

function moopmartCollectOrganismRows(string $org, array $org_sources, array $filters, array $coord_filter, array $raw_input_ids, string $global_filter_reason, string $organism_data, ?int $row_cap = null): array {
    $empty = ['gene_count' => 0, 'row_count' => 0, 'rows' => []];

    $db = "$organism_data/$org/organism.sqlite";
    if (!file_exists($db)) return $empty;

    $gene_set_ids = array_values(array_filter(array_column($org_sources, 'gene_set_id')));
    if (empty($gene_set_ids)) return $empty;

    // Resolve input IDs for this organism and build per-gene reason map
    $id_reasons  = [];
    $org_filters = $filters;
    if (!empty($raw_input_ids)) {
        $id_reasons = moopmartResolveInputIds($raw_input_ids, $db, $gene_set_ids);
        if (empty($id_reasons)) return $empty;
        $org_filters['feature_ids'] = array_keys($id_reasons);
    }

    $features = moopmartQueryFeatures($gene_set_ids, $db, $org_filters);
    if (empty($features)) return $empty;

    $uniquenames_by_gs = [];
    foreach ($features as $f) {
        $uniquenames_by_gs[$f['gene_set_id']][] = $f['uniquename'];
    }

    $coords_by_gs = [];
    foreach ($org_sources as $src) {
        $gs_id = $src['gene_set_id'];
        if ($gs_id && !isset($coords_by_gs[$gs_id])) {
            $coords_by_gs[$gs_id] = moopmartLoadGeneCoords($src['path'], $uniquenames_by_gs[$gs_id] ?? []);
        }
    }

    $matched   = moopmartAttachCoords($features, $coords_by_gs, $coord_filter);
    $gene_rows = [];
    foreach ($matched as $f) {
        $f['organism_dir'] = $org;
        $f['db_path']      = $db;
        // "why included": ID resolution takes priority; fall back to filter description
        if (!empty($id_reasons)) {
            $reason = $id_reasons[$f['uniquename']] ?? '';
            if ($global_filter_reason) $reason .= ($reason ? ' + ' : '') . $global_filter_reason;
        } else {
            $reason = $global_filter_reason;
        }
        $f['match_reason'] = $reason;
        $gene_rows[]       = $f;
    }

    // Total expanded rows, counted rather than built: expansion copies the whole gene row
    // once per transcript, which for a large genome is hundreds of MB the caller would only
    // throw away. Genes with no transcript children still render one row, hence max(n, 1).
    $child_counts = moopmartCountChildRows(array_column($gene_rows, 'feature_id'), $db);
    $row_count    = 0;
    foreach ($gene_rows as $f) {
        $row_count += max($child_counts[(int)$f['feature_id']] ?? 0, 1);
    }

    // Expand only as far as the caller will read. Every gene yields at least one row, so the
    // first $row_cap genes always supply at least $row_cap rows.
    $to_expand = $row_cap === null ? $gene_rows : array_slice($gene_rows, 0, $row_cap);
    $mrna_rows = moopmartExpandToMrnaRows($to_expand, $db);
    if ($row_cap !== null && count($mrna_rows) > $row_cap) {
        $mrna_rows = array_slice($mrna_rows, 0, $row_cap);
    }

    return ['gene_count' => count($gene_rows), 'row_count' => $row_count, 'rows' => $mrna_rows];
}

function moopmartBuildPreviewRows(array $preview, array $annotation_columns_selected, bool $ann_incl_id, bool $ann_incl_desc): array {
    $clean_prev        = fn($s) => str_replace(["\r\n", "\r", "\n", "\t"], ' ', (string)$s);
    $ann_col_headers   = [];
    $ann_by_uniquename = [];

    if (!empty($annotation_columns_selected)) {
        foreach ($annotation_columns_selected as $src) {
            if ($ann_incl_id)   $ann_col_headers[] = 'ID:' . $src;
            if ($ann_incl_desc) $ann_col_headers[] = 'Description:' . $src;
        }

        // Deduplicate by gene feature_id before fetching annotations
        $seen_fids     = [];
        $preview_by_db = [];
        foreach ($preview as $f) {
            if (empty($f['db_path']) || isset($seen_fids[$f['feature_id']])) continue;
            $seen_fids[$f['feature_id']]    = true;
            $preview_by_db[$f['db_path']][] = $f;
        }
        foreach ($preview_by_db as $db_path => $db_feats) {
            $chunk_anns = moopmartGetAnnotationsForFeatures(array_column($db_feats, 'feature_id'), $db_path);
            foreach ($db_feats as $f) {
                $ann_by_uniquename[$f['uniquename']] = $chunk_anns[$f['feature_id']] ?? [];
            }
        }
    }

    $rows = array_map(function ($f) use ($annotation_columns_selected, $ann_by_uniquename, $ann_incl_id, $ann_incl_desc, $clean_prev) {
        $row = [
            'uniquename'       => $f['uniquename'],
            'name'             => $f['name']          ?? '',
            'description'      => $f['description']   ?? '',
            'organism_dir'     => $f['organism_dir'],
            'genome_accession' => $f['genome_accession'],
            'gene_set_name'    => $f['gene_set_name'],
            'mrna_id'          => $f['mrna_id']       ?? '',
            'protein_id'       => $f['protein_id']    ?? '',
            'chr'              => $f['chr']            ?? '',
            'start'            => $f['start']          ?? '',
            'end'              => $f['end']            ?? '',
            'strand'           => $f['strand']         ?? '',
            'match_reason'     => $f['match_reason']   ?? '',
        ];
        foreach ($annotation_columns_selected as $src) {
            $entries = $ann_by_uniquename[$f['uniquename']][$src] ?? [];
            if ($ann_incl_id)   $row['ID:' . $src]          = implode('; ', array_map(fn($e) => $e['accession'], $entries));
            if ($ann_incl_desc) $row['Description:' . $src] = implode('; ', array_map(fn($e) => $clean_prev($e['description'] ?? ''), $entries));
        }
        return $row;
    }, $preview);

    return ['rows' => $rows, 'ann_col_headers' => $ann_col_headers];
}

function organism_cache_write_atomic($cache_file, array $data) {
    $json = json_encode($data, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES);
    if ($json === false) return false;
    $tmp = $cache_file . '.tmp.' . getmypid();
    if (@file_put_contents($tmp, $json) === false) return false;
    @chmod($tmp, 0664);
    if (!@rename($tmp, $cache_file)) {
        @unlink($tmp);
        return false;
    }
    return true;
}

function getCachedOrganismsInfo($organism_data_path, $sequence_types, $taxonomy_tree_file, $groups_data, $groups_file, $force_refresh = false, $progress_callback = null, $force_organisms = []) {
    $cache_file = moop_organism_cache_file();

    // Build per-organism fingerprints for all current organisms
    $current_fingerprints = buildPerOrganismFingerprints($organism_data_path);

    // Config fingerprint used only for the DECISION of what to rescan.
    // We recompute it at the end before writing so the stored value reflects
    // the final state of config files, not the state at scan start. This prevents
    // the cache from being born stale when a config file changes during a long scan.
    $decision_config_fp = buildConfigFingerprint($taxonomy_tree_file, $groups_file);

    // Try to load existing cache
    $cached = null;
    $cached_fingerprints = [];
    $cached_config = null;
    $cached_data = [];

    if (!$force_refresh && file_exists($cache_file)) {
        $cached = loadJsonFile($cache_file, []);
        if ($cached && isset($cached['org_fingerprints']) && isset($cached['config_fingerprint']) && isset($cached['data'])
            && ($cached['schema_version'] ?? 0) === ORGANISM_CACHE_SCHEMA_VERSION) {
            $cached_fingerprints = $cached['org_fingerprints'];
            $cached_config = $cached['config_fingerprint'];
            $cached_data = $cached['data'];
        }
    }

    // Determine what needs updating
    $config_changed = ($cached_config !== $decision_config_fp);
    $organisms_to_scan = [];
    $organisms_to_keep = [];
    // Organisms whose files are unchanged but config changed — reuse expensive validation,
    // only recalculate status fields (group membership, tree placement, overall_status).
    $organisms_config_only = [];

    foreach ($current_fingerprints as $org_name => $fingerprint) {
        // Specific organisms can be force-rescanned regardless of fingerprint.
        if (!empty($force_organisms) && in_array($org_name, $force_organisms, true)) {
            $organisms_to_scan[] = $org_name;
            continue;
        }
        $cached_fingerprint = $cached_fingerprints[$org_name] ?? null;
        if ($cached_fingerprint === $fingerprint) {
            if (!$config_changed) {
                // Organism and config both unchanged — fully reuse
                if (isset($cached_data[$org_name])) {
                    $organisms_to_keep[$org_name] = $cached_data[$org_name];
                } else {
                    $organisms_to_scan[] = $org_name;
                }
            } else {
                // Config changed but organism files unchanged — lightweight status refresh
                if (isset($cached_data[$org_name])) {
                    $organisms_config_only[$org_name] = $cached_data[$org_name];
                } else {
                    $organisms_to_scan[] = $org_name;
                }
            }
        } else {
            // Organism files changed — full rescan
            $organisms_to_scan[] = $org_name;
        }
    }

    // Check for removed organisms (in cache but not in current directory scan)
    foreach ($cached_fingerprints as $org_name => $fingerprint) {
        if (!isset($current_fingerprints[$org_name])) {
            unset($organisms_to_keep[$org_name]);
            unset($organisms_config_only[$org_name]);
        }
    }

    // For config-only changes: recalculate overall_status and in_taxonomy_tree
    // without re-running the expensive DB/FASTA/BLAST validation.
    foreach ($organisms_config_only as $org_name => $org_data) {
        $org_data['in_taxonomy_tree'] = isAssemblyInTaxonomyTree($org_name, '', $taxonomy_tree_file);
        $org_data['overall_status']   = getOrganismOverallStatus($org_name, $org_data, $groups_data, $taxonomy_tree_file, $sequence_types);
        $organisms_to_keep[$org_name] = $org_data;
    }

    $total_scan_count = count($organisms_to_scan);
    $removed_count = count($cached_fingerprints) - count($current_fingerprints);

    if ($total_scan_count === 0) {
        // Nothing to scan, but the on-disk cache can still be stale in two ways:
        //   - organisms were deleted (removed entries must not persist), or
        //   - only the groups/taxonomy config changed. In that case we recomputed the
        //     config-only organisms above and must persist the new config_fingerprint;
        //     otherwise a non-force "Update Cache" click never clears the stale banner
        //     (the reload recomputes the new fingerprint and it won't match the old one).
        if ($removed_count > 0 || $config_changed) {
            $cache_data = [
                'generated'          => date('Y-m-d H:i:s'),
                'schema_version'     => ORGANISM_CACHE_SCHEMA_VERSION,
                'config_fingerprint' => buildConfigFingerprint($taxonomy_tree_file, $groups_file),
                'org_fingerprints'   => $current_fingerprints,
                'data'               => $organisms_to_keep,
            ];
            organism_cache_write_atomic($cache_file, $cache_data);
        }
        return $organisms_to_keep;
    }

    // Scan only the organisms that need updating
    $scanned_organisms = [];
    $current = 0;

    // Load metadata for organisms we're about to scan
    $organisms_metadata = loadAllOrganismsMetadata($organism_data_path);

    foreach ($organisms_to_scan as $org_name) {
        $current++;
        if ($progress_callback) {
            $progress_callback($org_name, $current, $total_scan_count, 'scanning');
        }

        $org_path = "$organism_data_path/$org_name";
        if (!is_dir($org_path)) {
            continue;
        }

        // Build organism info (inline from getDetailedOrganismsInfo logic)
        $info = $organisms_metadata[$org_name] ?? [];

        // Get assemblies
        $assemblies = [];
        $files = scandir($org_path);
        foreach ($files as $file) {
            if ($file[0] === '.' || !is_dir("$org_path/$file")) {
                continue;
            }
            $assemblies[] = $file;
        }

        // Check for database file
        $db_file = null;
        if (file_exists("$org_path/organism.sqlite")) {
            $db_file = "$org_path/organism.sqlite";
        }

        $has_db = !is_null($db_file);

        // Validate database integrity if exists
        $db_validation = null;
        $assembly_validation = null;
        $fasta_validation = null;
        if ($has_db) {
            if ($progress_callback) {
                $progress_callback($org_name, $current, $total_scan_count, 'checking database');
            }
            $db_validation = validateDatabaseIntegrity($db_file);
            if ($progress_callback) {
                $progress_callback($org_name, $current, $total_scan_count, 'checking assembly directories');
            }
            $assembly_validation = validateAssemblyDirectories($db_file, $org_path);
        }
        // Validate FASTA files in assembly directories
        if ($progress_callback) {
            $progress_callback($org_name, $current, $total_scan_count, 'checking FASTA files');
        }
        $fasta_validation = validateAssemblyFastaFiles($org_path, $sequence_types);

        $org_info = [
            'path' => $org_path,
            'info' => $info,
            'assemblies' => $assemblies,
            'has_db' => $has_db,
            'db_file' => $db_file,
            'db_validation' => $db_validation,
            'assembly_validation' => $assembly_validation,
            'fasta_validation' => $fasta_validation,
            'json_validation' => validateOrganismJson("$org_path/organism.json")
        ];

        // Pre-compute blast validation per assembly — aggregate across gene_set subdirs
        if ($progress_callback) {
            $progress_callback($org_name, $current, $total_scan_count, 'checking BLAST indexes');
        }
        $blast_by_assembly = [];
        foreach ($org_info['assemblies'] as $assembly) {
            $assembly_path = $org_path . '/' . $assembly;
            $aggregated = ['databases' => [], 'missing_count' => 0, 'total_count' => 0];
            foreach (glob($assembly_path . '/*', GLOB_ONLYDIR) ?: [] as $gs_dir) {
                $bv = validateBlastIndexFiles($gs_dir, $sequence_types);
                $aggregated['databases']     = array_merge($aggregated['databases'], $bv['databases']);
                $aggregated['missing_count'] += $bv['missing_count'];
                $aggregated['total_count']   += $bv['total_count'];
            }
            $blast_by_assembly[$assembly] = $aggregated;
        }
        $org_info['blast_validation'] = $blast_by_assembly;

        // Pre-compute FAI validation per assembly
        $fai_by_assembly = [];
        foreach ($org_info['assemblies'] as $assembly) {
            $genome_fa = $org_path . '/' . $assembly . '/genome.fa';
            $fai_by_assembly[$assembly] = [
                'genome_fa_exists' => file_exists($genome_fa),
                'fai_exists'       => file_exists($genome_fa . '.fai'),
            ];
        }
        $org_info['fai_validation'] = $fai_by_assembly;

        // Pre-compute taxonomy tree membership
        $org_info['in_taxonomy_tree'] = isAssemblyInTaxonomyTree($org_name, '', $taxonomy_tree_file);

        // Pre-compute overall status
        $org_info['overall_status'] = getOrganismOverallStatus($org_name, $org_info, $groups_data, $taxonomy_tree_file, $sequence_types);

        $scanned_organisms[$org_name] = $org_info;
    }

    // Merge: kept organisms + newly scanned organisms
    $all_organisms = array_merge($organisms_to_keep, $scanned_organisms);

    // Sort by organism name
    ksort($all_organisms);

    // Recompute config fingerprint at END of scan so the stored value reflects
    // the final state of config files, not the state when scanning started.
    $cache_data = [
        'generated'          => date('Y-m-d H:i:s'),
        'schema_version'     => ORGANISM_CACHE_SCHEMA_VERSION,
        'config_fingerprint' => buildConfigFingerprint($taxonomy_tree_file, $groups_file),
        'org_fingerprints'   => $current_fingerprints,
        'data'               => $all_organisms,
    ];

    organism_cache_write_atomic($cache_file, $cache_data);

    return $all_organisms;
}

functions.comment:
/**
* Build fingerprint for config files (tree, groups)
*/

functions.code:
function buildConfigFingerprint($taxonomy_tree_file, $groups_file) {
    $parts = [];
    // Note: taxonomy_tree_config.json is intentionally excluded — it is an output
    // of the organism scan, so including its mtime would create a circular invalidation.
    if (file_exists($groups_file)) {
        // mtime + size — a re-synced groups file can preserve its mtime, so size makes
        // an actual content change detectable (same reasoning as buildPerOrganismFingerprints).
        $parts[] = 'groups:' . filemtime($groups_file) . ':' . filesize($groups_file);
    }
    return md5(implode('|', $parts));
}

function buildPerOrganismFingerprints($organism_data_path) {
    $fingerprints = [];

    if (!is_dir($organism_data_path)) {
        return $fingerprints;
    }

    $organisms = scandir($organism_data_path);

    foreach ($organisms as $organism) {
        if ($organism[0] === '.' || !is_dir("$organism_data_path/$organism")) {
            continue;
        }

        $org_path = "$organism_data_path/$organism";
        $parts = [];

        // SQLite file: mtime + size. Size catches timestamp-preserving replacements
        // (rsync -a, cp -p, tar extract, restore-from-backup all keep the old mtime) —
        // a rebuilt or re-synced DB is virtually always a different byte size.
        $sqlite_file = "$org_path/organism.sqlite";
        if (file_exists($sqlite_file)) {
            $parts[] = 'db:' . filemtime($sqlite_file) . ':' . filesize($sqlite_file);
        }

        // organism.json: mtime + size (same timestamp-lies reasoning as the DB above)
        $json_file = "$org_path/organism.json";
        if (file_exists($json_file)) {
            $parts[] = 'json:' . filemtime($json_file) . ':' . filesize($json_file);
        }

        // Assembly directories — include each dir's mtime so that adding/removing
        // files inside an assembly (FASTA, FAI, BLAST indexes) triggers a rescan.
        $assemblies = array_filter(scandir($org_path), function($f) use ($org_path) {
            return $f[0] !== '.' && is_dir("$org_path/$f");
        });
        $parts[] = 'asm:' . count($assemblies);
        foreach ($assemblies as $asm) {
            $parts[] = 'asm_mtime:' . filemtime("$org_path/$asm");
            // Gene_set subdirs sit one level below the assembly dir. On Linux, only direct
            // children affect a directory's mtime, so files changed inside a gene_set subdir
            // (e.g. BLAST indexes rebuilt) must be tracked here explicitly.
            foreach (glob("$org_path/$asm/*", GLOB_ONLYDIR) ?: [] as $gs_dir) {
                $parts[] = 'gs_mtime:' . basename($gs_dir) . ':' . filemtime($gs_dir);
            }
        }

        $fingerprints[$organism] = md5(implode('|', $parts));
    }

    return $fingerprints;
}

function getAncestors($feature_uniquename, $dbFile, $gene_set_ids = []) {
    $params = [$feature_uniquename];

    $gs_clause = '';
    if (!empty($gene_set_ids)) {
        $ph        = implode(',', array_fill(0, count($gene_set_ids), '?'));
        $gs_clause = "AND f.gene_set_id IN ($ph)";
        array_push($params, ...$gene_set_ids);
    }

    $query = "WITH RECURSIVE ancestors AS (
        SELECT f.feature_id, f.feature_uniquename, f.feature_name,
               f.feature_description, f.feature_type, f.parent_feature_id
        FROM   feature f
        WHERE  f.feature_uniquename = ? $gs_clause
        UNION ALL
        SELECT f.feature_id, f.feature_uniquename, f.feature_name,
               f.feature_description, f.feature_type, f.parent_feature_id
        FROM   feature f
        JOIN   ancestors a ON f.feature_id = a.parent_feature_id
    )
    SELECT * FROM ancestors";

    return fetchData($query, $dbFile, $params);
}

function getAncestorsByFeatureId($feature_id, $dbFile, $gene_set_ids = []) {
    $rows = fetchData(
        "SELECT feature_uniquename FROM feature WHERE feature_id = ?",
        $dbFile,
        [$feature_id]
    );
    if (empty($rows)) return [];
    $chain = getAncestors($rows[0]['feature_uniquename'], $dbFile, $gene_set_ids);
    // Original callers expect the chain WITHOUT the seed feature itself
    return array_slice($chain, 1);
}

function getChildren($feature_id, $dbFile, $gene_set_ids = []) {
    $params = [$feature_id];

    $gs_clause = '';
    if (!empty($gene_set_ids)) {
        $ph        = implode(',', array_fill(0, count($gene_set_ids), '?'));
        $gs_clause = "AND f.gene_set_id IN ($ph)";
        array_push($params, ...$gene_set_ids);
    }

    $query = "WITH RECURSIVE descendants AS (
        SELECT f.feature_id, f.feature_uniquename, f.feature_name,
               f.feature_description, f.feature_type, f.parent_feature_id
        FROM   feature f
        WHERE  f.parent_feature_id = ? $gs_clause
        UNION ALL
        SELECT f.feature_id, f.feature_uniquename, f.feature_name,
               f.feature_description, f.feature_type, f.parent_feature_id
        FROM   feature f
        JOIN   descendants d ON f.parent_feature_id = d.feature_id
    )
    SELECT * FROM descendants";

    return fetchData($query, $dbFile, $params);
}

function getChildrenHierarchical($feature_id, $dbFile, $gene_set_ids = []) {
    $flat = getChildren($feature_id, $dbFile, $gene_set_ids);
    if (empty($flat)) return [];

    // Group all nodes by their parent_feature_id for O(1) child lookup
    $by_parent = [];
    foreach ($flat as $row) {
        $by_parent[$row['parent_feature_id']][] = $row;
    }

    // Recursively attach grandchildren starting from direct children of $feature_id
    return _buildChildTree($feature_id, $by_parent);
}

function _buildChildTree($parent_id, array &$by_parent) {
    $children = $by_parent[$parent_id] ?? [];
    foreach ($children as &$child) {
        $child['grandchildren'] = _buildChildTree($child['feature_id'], $by_parent);
    }
    return $children;
}

function generateAnnotationTableHTML($results, $uniquename, $type, $count, $annotation_type, $desc, $color = 'warning', $organism = '', $annotation_type_key = '') {
    if (empty($results)) {
        return '';
    }

    $table_id = "annotTable_$count";
    $result_count = count($results);
    $desc_id = "annotDesc_$count";

    // Determine text color based on background color
    $text_color = in_array($color, ['warning', 'info', 'secondary']) ? 'text-dark' : 'text-white';

    // Border color matches badge color
    $border_class = "border-$color";

    // Create unique ID for this annotation section
    // Use annotation_type_key if provided, otherwise fall back to annotation_type
    $key_for_anchor = $annotation_type_key ?: $annotation_type;
    $section_id = "annot_section_" . preg_replace('/[^a-zA-Z0-9_]/', '_', $uniquename . '_' . $key_for_anchor);

    $html = '<div class="annotation-section mb-3 ' . htmlspecialchars($border_class) . '" id="' . htmlspecialchars($section_id) . '">';
    $html .= '<div class="d-flex justify-content-between align-items-center mb-2">';
    $html .= "<h5 class=\"mb-0\"><span class=\"badge bg-" . htmlspecialchars($color) . " $text_color badge-lg\">" . htmlspecialchars($annotation_type) . "</span>";
    $html .= " <span class=\"badge bg-secondary badge-lg\">" . htmlspecialchars($result_count) . " result" . ($result_count > 1 ? 's' : '') . "</span>";

    if ($desc) {
        $html .= "&nbsp;<button class=\"btn btn-sm btn-link p-0 annotation-info-btn\" type=\"button\" data-bs-toggle=\"collapse\" data-bs-target=\"#" . htmlspecialchars($desc_id) . "\" aria-expanded=\"false\">";
        $html .= "<i class=\"fas fa-info-circle\"></i>";
        $html .= "</button>";
    }

    $html .= "</h5>";
    $html .= '<div class="d-flex gap-2 align-items-center">';
    $html .= '<div id="' . htmlspecialchars($table_id) . '_filter" class="dataTables_filter"></div>';
    $html .= '</div>';
    $html .= '</div>';

    if ($desc) {
        $html .= '<div class="collapse mb-3" id="' . htmlspecialchars($desc_id) . '">';
        $html .= '<div class="alert alert-info mb-0 font-size-xsmall">';
        $html .= $desc;
        $html .= '</div>';
        $html .= '</div>';
    }

    // Table with DataTables
    $html .= "<div class=\"table-responsive\">";
    $html .= "<table id=\"" . htmlspecialchars($table_id) . "\" class=\"table table-sm table-striped table-hover substring-search\" style=\"width:100%;\">";
    $html .= "<thead><tr>";
    $html .= "<th class=\"export-only\">Organism</th>";
    $html .= "<th class=\"export-only\">Feature ID</th>";
    $html .= "<th class=\"export-only\">Feature Type</th>";
    $html .= "<th class=\"export-only\">Annotation Type</th>";
    $html .= "<th>Annotation ID</th>";
    $html .= "<th>Description</th>";
    $html .= "<th>Score</th>";
    $html .= "<th>Source</th>";
    $html .= "</tr></thead>";
    $html .= "<tbody>";

    foreach ($results as $row) {
        $hit_id = htmlspecialchars(trim($row['annotation_accession']));
        $hit_description = htmlspecialchars($row['annotation_description']);
        $hit_score = htmlspecialchars($row['score']);
        $annotation_source = htmlspecialchars($row['annotation_source_name']);
        $annotation_accession_url = htmlspecialchars(trim($row['annotation_accession_url']));
        $hit_id_link = $annotation_accession_url . urlencode(trim($row['annotation_accession']));

        $html .= "<tr>";
        $html .= "<td class=\"export-only\">" . htmlspecialchars($organism) . "</td>";
        $html .= "<td class=\"export-only\">" . htmlspecialchars($uniquename) . "</td>";
        $html .= "<td class=\"export-only\">" . htmlspecialchars($type) . "</td>";
        $html .= "<td class=\"export-only\">" . htmlspecialchars($annotation_type) . "</td>";
        $html .= "<td><a href=\"" . htmlspecialchars($hit_id_link) . "\" target=\"_blank\">" . $hit_id . "</a></td>";
        $html .= "<td>" . $hit_description . "</td>";
        $html .= "<td>" . $hit_score . "</td>";
        $html .= "<td>" . $annotation_source . "</td>";
        $html .= "</tr>";
    }

    $html .= "</tbody></table>";
    $html .= "</div>";
    $html .= "</div>";

    return $html;
}

function getAllAnnotationsForFeatures($feature_ids, $dbFile, $gene_set_ids = []) {
    if (empty($feature_ids)) {
        return [];
    }

    $placeholders = implode(',', array_fill(0, count($feature_ids), '?'));

    // Build WHERE clause with optional genome filtering
    $where_clause = "f.feature_id IN ($placeholders)";
    $params = $feature_ids;

    if (!empty($gene_set_ids)) {
        $gene_set_placeholders = implode(',', array_fill(0, count($gene_set_ids), '?'));
        $where_clause .= " AND f.gene_set_id IN ($gene_set_placeholders)";
        $params = array_merge($params, $gene_set_ids);
    }

    $query = "SELECT f.feature_id, f.feature_uniquename, f.feature_type,
              a.annotation_accession, a.annotation_description,
              fa.score, fa.date,
              ans.annotation_source_name, ans.annotation_accession_url, ans.annotation_type
        FROM annotation a, feature f, feature_annotation fa, annotation_source ans, gene_set gs, genome g, organism o
        WHERE f.organism_id = o.organism_id
          AND f.gene_set_id = gs.gene_set_id
          AND gs.genome_id = g.genome_id
          AND ans.annotation_source_id = a.annotation_source_id
          AND f.feature_id = fa.feature_id
          AND fa.annotation_id = a.annotation_id
          AND $where_clause
        ORDER BY f.feature_id, ans.annotation_type";

    $results = fetchData($query, $dbFile, $params);

    // Organize by feature_id and annotation_type
    $organized = [];
    foreach ($results as $row) {
        $feature_id = $row['feature_id'];
        $annotation_type = $row['annotation_type'];

        if (!isset($organized[$feature_id])) {
            $organized[$feature_id] = [];
        }
        if (!isset($organized[$feature_id][$annotation_type])) {
            $organized[$feature_id][$annotation_type] = [];
        }

        $organized[$feature_id][$annotation_type][] = $row;
    }

    return $organized;
}

function generateTreeHTML($feature_id, $dbFile, $all_annotations = [], $analysis_order = [], $prefix = '', $is_last = true, $gene_set_ids = []) {
    $results = getChildrenByFeatureId($feature_id, $dbFile, $gene_set_ids);

    if (empty($results)) {
        return '';
    }

    $html = "<ul>";
    $total = count($results);

    foreach ($results as $index => $row) {
        $is_last_child = ($index === $total - 1);

        $feature_type = htmlspecialchars($row['feature_type']);
        $feature_name = htmlspecialchars($row['feature_uniquename']);
        $child_feature_id = $row['feature_id'];

        // Color code badges by feature type
        $badge_class = 'bg-secondary';
        $text_color = 'text-white';

        if ($feature_type == 'mRNA') {
            $badge_class = 'bg-feature-mrna';
            $text_color = 'text-white';
        } elseif ($feature_type == 'CDS') {
            $badge_class = 'bg-info';
            $text_color = 'text-white';
        } elseif ($feature_type == 'exon') {
            $badge_class = 'bg-warning';
            $text_color = 'text-dark';
        } elseif ($feature_type == 'gene') {
            $badge_class = 'bg-feature-gene';
            $text_color = 'text-white';
        } elseif ($feature_type == 'protein' || $feature_type == 'polypeptide') {
            $badge_class = 'bg-feature-protein';
            $text_color = 'text-white';
        }

        // Calculate annotation count for this child
        $child_annot_count = 0;
        if (isset($all_annotations[$child_feature_id])) {
            foreach ($all_annotations[$child_feature_id] as $annotation_type => $annots) {
                $child_annot_count += count($annots);
            }
        }

        // Generate anchor for first annotation type (or use first one available)
        $child_annot_anchor = preg_replace('/[^a-zA-Z0-9_]/', '_', $row['feature_uniquename'] . '_' . ($analysis_order[0] ?? 'annotation'));

        // Tree character - └── for last child, ├── for others
        $tree_char = $is_last_child ? '└── ' : '├── ';

        $html .= "<li>";
        $html .= "<span class=\"tree-char\">$tree_char</span>";
        $html .= "<a href=\"#annot_section_$child_annot_anchor\" class=\"link-light-bordered text-decoration-none\"><span class=\"text-dark\">$feature_name</span></a> ";
        $html .= "<span class=\"badge $badge_class $text_color\">$feature_type</span>";

        // Add annotation count badge if there are annotations
        if ($child_annot_count > 0) {
            $html .= " <span class=\"badge bg-success text-white badge-sm\">$child_annot_count annotation" . ($child_annot_count > 1 ? 's' : '') . "</span>";
        }

        // Recursive call for nested children
        $html .= generateTreeHTML($child_feature_id, $dbFile, $all_annotations, $analysis_order, $prefix, $is_last_child, $gene_set_ids);
        $html .= "</li>";
    }
    $html .= "</ul>";

    return $html;
}

function generateChildAnnotationCards($child, $all_annotations, $analysis_order, $annotation_colors, $annotation_labels, $analysis_desc, $organism_name, &$count, $is_grandchild = false, $annotated_child_types = []) {
    $child_feature_id = $child['feature_id'];
    $child_uniquename = $child['feature_uniquename'];
    $child_type = $child['feature_type'];

    // Skip feature types that never carry annotations in this gene set
    if (!empty($annotated_child_types) && !in_array($child_type, $annotated_child_types)) {
        return '';
    }

    // Count annotations for this child
    $child_annotation_count = 0;
    foreach ($analysis_order as $annotation_type) {
        $annot_results = $all_annotations[$child_feature_id][$annotation_type] ?? [];
        if (!empty($annot_results)) {
            $child_annotation_count += count($annot_results);
        }
    }

    // Determine header styling based on feature type and nesting level
    $header_class = 'child-feature-header';
    $badge_class = 'bg-feature-mrna';

    if ($is_grandchild) {
        $header_class = 'child-feature-header grandchild-feature-header';
        if ($child_type == 'protein' || $child_type == 'polypeptide') {
            $badge_class = 'bg-feature-protein';
        } else {
            $badge_class = 'bg-secondary';
        }
    }

    $html = '<div class="card annotation-card border-info">';
    $html .= "  <div class=\"card-header d-flex align-items-center $header_class\">";
    $html .= "    <span class=\"collapse-section\" data-bs-toggle=\"collapse\" data-bs-target=\"#child_$child_feature_id\" aria-expanded=\"true\" role=\"button\">";
    $html .= "      <i class=\"fas fa-minus toggle-icon text-info\"></i>";
    $html .= "    </span>";
    $html .= "    <span class=\"ms-2 text-white px-2 py-1 rounded child-feature-badge $badge_class badge-md\">$child_uniquename ($child_type)</span>";

    // Annotation-type navigation now lives in the section sidebar (parent-nav.js),
    // so per-type chips are no longer shown next to the child name. Children with
    // no annotations still get a clear indicator here.
    if ($child_annotation_count === 0) {
        $html .= " <span class=\"badge bg-secondary ms-2\">No annotations</span>";
    }

    $html .= '  </div>';
    $html .= "  <div id=\"child_$child_feature_id\" class=\"collapse show\">";
    $html .= '    <div class="card-body">';

    $child_has_annotations = false;
    foreach ($analysis_order as $annotation_type) {
        $count++;
        $annot_results = $all_annotations[$child_feature_id][$annotation_type] ?? [];
        if (!empty($annot_results)) {
            $child_has_annotations = true;
            $color = $annotation_colors[$annotation_type] ?? 'warning';
            $display_label = $annotation_labels[$annotation_type] ?? $annotation_type;
            $html .= generateAnnotationTableHTML($annot_results, $child_uniquename, $child_type, $count, $display_label, $analysis_desc[$annotation_type] ?? '', $color, $organism_name, $annotation_type);
        }
    }

    if (!$child_has_annotations) {
        $type_label = ($child_type === 'mRNA') ? 'transcript' : strtolower($child_type);
        $html .= "<p class=\"text-muted\"><i class=\"fas fa-info-circle\"></i> No annotations loaded for this $type_label.</p>";
    }

    // Render grandchildren (recursively)
    if (!empty($child['grandchildren'])) {
        foreach ($child['grandchildren'] as $grandchild) {
            $html .= generateChildAnnotationCards($grandchild, $all_annotations, $analysis_order, $annotation_colors, $annotation_labels, $analysis_desc, $organism_name, $count, true, $annotated_child_types);
        }
    }

    $html .= '    </div>';
    $html .= '  </div>';
    $html .= '</div>';

    return $html;
}

function moop_permission_check_mode(string $name): string {
    // 'secret' — private key material.
    if ($name === 'JWT Key Files' || $name === 'JWT Certificates Directory') return 'secret';

    // 'writable' — the ONLY paths the web server (apache/httpd_t) legitimately writes,
    // straight from the table in docs/SELINUX_AND_HARDENING.md §55. Everything else is
    // read-only served content.
    //
    // NOTE on organisms/: the tree IS writable to apache by design (§73 — the web builds
    // BLAST/.fai indexes in place), but its entries stay 'data' here deliberately. The
    // *directories* need apache write (makeblastdb creates new files); the FASTA/SQLite
    // *files* do not, and should stay unwritable. performPermissionCheck's 'data' branch
    // therefore checks writability for data-tree DIRECTORIES only.
    //
    // (An earlier version of this comment claimed 'data' mode "already reports a softened
    // not-writable for data trees". It did not — the check did not exist, and 22 assembly
    // dirs at 2755 were invisible to the dashboard because of it. Do not trust a comment
    // that says a check exists; grep for the check.)
    static $writable = [
        'Logs Directory'                  => 1,  // error.log, login_attempts.json
        'Site Configuration Files'        => 1,  // config/config_editable.json (admin UI)
        'Metadata Configuration Files'    => 1,  // metadata/*.json
        'Taxonomy Lineage Cache'          => 1,  // metadata/taxonomy_lineage_cache.json
        'Metadata Directory'              => 1,
        'Metadata Backups Directory'      => 1,
        'Change Log Directory'            => 1,
        'JBrowse2 Track Config Directory' => 1,  // metadata/jbrowse2-configs
        'Genome Data Directory'           => 1,  // data/genomes — gff.gz + tabix
        'Cache Directory'                 => 1,  // cache_path
        'Organism Cache File'             => 1,  // under cache_path
        'Images Directory'                => 1,  // images/ — organism images upload HERE, flat
                                                //   (handle_image_upload.php -> absolute_images_path)
        'Documentation Directory'         => 1,  // docs/ — the admin "Generate registry" button
                                                //   rewrites function_registry.json here
        'NCBI Taxonomy Images Cache'      => 1,  // images/ncbi_taxonomy (php downloads)
        'Wikimedia Images Cache'          => 1,  // images/wikimedia (php downloads)
        'Banner Images Directory'         => 1,  // images/banners — admin UI uploads/deletes
        'Organism Metadata Files'         => 1,  // organisms/*/organism.json — admin UI edits in place
    ];
    if (isset($writable[$name])) return 'writable';

    // Default: read-only served content (FASTA/genome/SQLite, the organism tree,
    // top-level images/, docs, data/tracks, jbrowse2/ app dir).
    return 'data';
}

function moop_permission_expectation(string $mode, string $type): string {
    $is_dir = ($type === 'directory');
    switch ($mode) {
        case 'secret':
            return 'Readable by the web server; not accessible to any other user on the host';
        case 'writable':
            return $is_dir
                ? 'Writable by the web server; SGID so new files inherit the group; not world-writable'
                : 'Writable by the web server; not world-writable; not executable';
        default:
            return $is_dir
                ? 'Readable and traversable by the web server; not world-writable'
                : 'Readable by the web server; not world-writable; not executable';
    }
}

function moop_permission_fix_commands(array $check, string $moop_owner): array {
    $path = (string)($check['path'] ?? '');
    if ($path === '') return [];

    $mode   = (string)($check['check_mode'] ?? 'data');
    $is_dir = (($check['type'] ?? 'file') === 'directory');
    $q      = escapeshellarg($path);
    $R      = $is_dir ? '-R ' : '';
    $bits   = octdec((string)($check['current_perms'] ?? '0'));
    $group  = (string)($check['required_group'] ?? '');
    $cmds   = [];

    // A wrong SELinux label cannot be fixed with chmod — say so first, it is the real gate.
    foreach (($check['issues'] ?? []) as $issue) {
        if (strpos((string)$issue, 'SELinux label') !== false) {
            $cmds[] = 'sudo scripts/fix_moop_selinux.sh   # label is the real gate — chmod will not help';
            break;
        }
    }

    if (empty($check['exists'])) {
        if ($is_dir) $cmds[] = "sudo mkdir -p $q";
    }
    if ($mode === 'writable') {
        if ($group !== '' && (string)($check['current_group'] ?? '') !== $group) {
            $cmds[] = 'sudo chgrp ' . $R . escapeshellarg($group) . " $q";
        }
        if (empty($check['is_writable'])) {
            $cmds[] = $is_dir ? "sudo chmod -R g+rwX $q && sudo chmod g+s $q" : "sudo chmod g+rw $q";
        }
    } elseif ($mode === 'secret') {
        if (empty($check['is_readable']) || ($bits & 0007) !== 0) $cmds[] = "sudo chmod 640 $q";
    } else {
        if (empty($check['is_readable'])) $cmds[] = "sudo chmod {$R}g+rX $q";
    }
    if (($bits & 0002) === 0002) $cmds[] = "sudo chmod {$R}o-w $q";
    if (!$is_dir && ($bits & 0111) !== 0) $cmds[] = "sudo chmod a-x $q";

    return $cmds;
}

function moop_permission_fix_exec_files_command(string $organism_data): string {
    return 'sudo find ' . escapeshellarg($organism_data) . ' -type f -exec chmod a-x {} +';
}

function moop_selinux_enforcing(): bool {
    static $enf = null;
    if ($enf !== null) return $enf;
    // Read the kernel state directly — PATH-independent. php-fpm runs with a restricted
    // PATH (often no /usr/sbin, where getenforce lives), so shell_exec('getenforce') would
    // return empty under the web server and silently disable the label check.
    $f = @file_get_contents('/sys/fs/selinux/enforce');
    if ($f !== false && $f !== '') return $enf = (trim($f) === '1');
    // Fallback: getenforce by absolute path.
    foreach (['/usr/sbin/getenforce', '/sbin/getenforce'] as $bin) {
        if (is_executable($bin)) {
            $out = @trim((string) shell_exec(escapeshellarg($bin) . ' 2>/dev/null'));
            return $enf = (strcasecmp($out, 'Enforcing') === 0);
        }
    }
    return $enf = false;
}

function moop_selinux_type(string $path): ?string {
    $out = [];
    @exec('ls -dZ ' . escapeshellarg($path) . ' 2>/dev/null', $out);
    if (empty($out[0])) return null;
    // context: user_u:object_r:<type>:s0
    return preg_match('/:([a-z0-9_]+_t):/', $out[0], $m) ? $m[1] : null;
}

function moop_permission_category(string $name): string {
    if (str_starts_with($name, 'FASTA File:'))            return 'Sequence files (FASTA)';
    if (str_starts_with($name, 'Assembly Subdirectory:')) return 'Assembly directories';
    if (str_starts_with($name, 'Gene Set Subdirectory:')) return 'Gene-set directories';
    if ($name === 'Organism Directory')                   return 'Organism directories';
    return $name;
}

function moop_permission_is_data_tree(string $name): bool {
    if (str_starts_with($name, 'Assembly Subdirectory:')) return true;
    if (str_starts_with($name, 'Gene Set Subdirectory:')) return true;
    return in_array($name, [
        'Organism Data Directories', 'Organism Directory', 'Genome Data Directory',
        'Track Data Directory',
    ], true);
}

function moop_permission_needs_build_write(string $name): bool {
    if (str_starts_with($name, 'Assembly Subdirectory:')) return true;
    if (str_starts_with($name, 'Gene Set Subdirectory:')) return true;
    return in_array($name, ['Organism Data Directories', 'Organism Directory'], true);
}

function moop_web_owned_evidence(string $dir, string $web_user, array $prune_paths = [], int $limit = 3): array {
    if ($web_user === '' || !is_dir($dir)) return [];

    $dir = rtrim($dir, '/');
    $cmd = 'find ' . escapeshellarg($dir) . ' -xdev';
    foreach ($prune_paths as $p) {
        $p = rtrim((string) $p, '/');
        // Only prune things actually inside $dir; a sibling rule is irrelevant here.
        if ($p === '' || strpos($p, $dir . '/') !== 0) continue;
        $cmd .= ' -path ' . escapeshellarg($p) . ' -prune -o';
    }
    $cmd .= ' -user ' . escapeshellarg($web_user) . ' -print 2>/dev/null';

    $out = [];
    @exec($cmd . ' | head -n ' . (int) $limit, $out);
    return array_values(array_filter(array_map('trim', $out), fn($s) => $s !== ''));
}

function performPermissionCheck($path, $item, $web_group = 'www-data') {
    $mode = $item['check_mode'] ?? moop_permission_check_mode($item['name']);
    $result = [
        'name' => $item['name'],
        'path' => $path,
        'exists' => file_exists($path),
        'type' => $item['type'],
        'required_perms' => $item['required_perms'],
        'required_group' => $item['required_group'] ?? $web_group,
        'reason' => $item['reason'] ?? '',
        'why_write' => $item['why_write'] ?? '',
        'sticky_bit' => $item['sticky_bit'] ?? false,
        'check_mode' => $mode,
        'category' => moop_permission_category($item['name']),
        'severity' => 'low',
        'issues' => [],
    ];

    if (!$result['exists']) {
        $result['issues'][] = 'Path does not exist';
        $result['severity'] = 'medium';
        return $result;
    }

    $perms_full = substr(sprintf('%o', fileperms($path)), -4);
    // Remove leading zero for comparison (0664 -> 664, 02775 -> 2775)
    $perms = ltrim($perms_full, '0') ?: '0';
    $mode_bits = octdec($perms_full) & 07777; // numeric perm bits for bit tests
    $file_uid = fileowner($path);
    $file_gid = filegroup($path);
    $owner = 'unknown';
    $group = 'unknown';
    if (function_exists('posix_getpwuid')) {
        $pw = posix_getpwuid($file_uid);
        if ($pw) { $owner = $pw['name']; }
    }
    if (function_exists('posix_getgrgid')) {
        $gr = posix_getgrgid($file_gid);
        if ($gr) { $group = $gr['name']; }
    }
    // Fallback: use stat command if posix not available
    if ($owner === 'unknown' || $group === 'unknown') {
        $stat_out = [];
        @exec("stat -c '%U:%G' " . escapeshellarg($path) . " 2>/dev/null", $stat_out);
        if (!empty($stat_out[0])) {
            $parts = explode(':', $stat_out[0]);
            if ($owner === 'unknown' && !empty($parts[0])) { $owner = $parts[0]; }
            if ($group === 'unknown' && !empty($parts[1])) { $group = $parts[1]; }
        }
    }

    $result['current_perms'] = $perms;
    $result['current_owner'] = $owner;
    $result['current_group'] = $group;
    $result['is_readable'] = is_readable($path);
    $result['is_writable'] = is_writable($path);

    $rank = ['low' => 1, 'medium' => 2, 'high' => 3];
    $sev  = 'low';
    $bump = function (string $s) use (&$sev, $rank) { if ($rank[$s] > $rank[$sev]) $sev = $s; };

    $world_writable = ($mode_bits & 0002) === 0002;
    $any_exec       = ($mode_bits & 0111) !== 0;
    $world_any      = ($mode_bits & 0007) !== 0;

    if ($mode === 'data') {
        // Read-only data the web serves. World-readability is NOT required.
        if (!$result['is_readable']) {
            $result['issues'][] = "Not readable by the web server ($web_group) — BLAST and sequence views will fail";
            $bump('high');
        }
        if ($world_writable) {
            $result['issues'][] = "World-writable ($perms) — any user on the host can overwrite it";
            $bump('high');
        }
        if ($any_exec && $result['type'] !== 'directory') {
            // Directories legitimately carry the traverse (x) bit; only flag executable FILES.
            $result['issues'][] = "Marked executable ($perms) — data files should not be executable";
            $bump('medium');
        }
        // Data-tree DIRECTORIES must stay web-writable even though their FILES need not be:
        // makeblastdb and samtools faidx create NEW files, which needs write on the
        // directory. Nothing checked this until 2026-07-16 — 'data' mode tested readable /
        // world-writable / exec and stopped, so 22 assembly dirs sat at 2755 (group r-x, no
        // write) with the dashboard reporting a clean bill of health while every in-app index
        // build there would fail. moop_permission_is_data_tree() was written for exactly this
        // ("future-build concern, medium — not live breakage") but was only ever wired into
        // the 'writable' branch, which these never reach.
        if ($result['type'] === 'directory'
            && moop_permission_needs_build_write($item['name'])
            && !$result['is_writable']) {
            $result['issues'][] = "Not writable by the web server ($web_group) — in-app builds"
                . ' here (Build BLAST Index, samtools faidx, assembly rename) will fail';
            $bump('medium');
        }
        // Does the web server write here despite being classified read-only? Skip the data
        // trees (organisms/, data/tracks): those ARE web-written by design and are only
        // 'data' here because their FILES need not be writable — see moop_permission_check_mode.
        if ($result['type'] === 'directory' && !moop_permission_is_data_tree($item['name'])) {
            $evidence = moop_web_owned_evidence($path, (string) ($item['_web_user'] ?? ''), $item['prune_paths'] ?? []);
            if ($evidence) {
                $result['issues'][] = 'Contains file(s) owned by the web server ('
                    . ($item['_web_user'] ?? '?') . ') — e.g. ' . $evidence[0]
                    . '. This path is classified read-only, so nothing here checks its SELinux'
                    . ' label. Either it belongs in the writable set, or these are leftovers'
                    . ' from a retired feature and should be chowned back.';
                $bump('medium');
            }
        }
    } elseif ($mode === 'secret') {
        if (!$result['is_readable']) {
            $result['issues'][] = "Not readable by the web server — JWT signing/verification will fail";
            $bump('high');
        }
        if ($world_any) {
            $result['issues'][] = "Accessible to other users on the host ($perms) — private key should not be world-accessible";
            $bump('high');
        }
    } else { // 'writable'
        // Under enforcing SELinux the LABEL decides writability, not the Unix mode —
        // is_writable() below sees only DAC and would false-green a wrong label.
        if (moop_selinux_enforcing()) {
            $type = moop_selinux_type($path);
            if ($type !== null && $type !== 'httpd_sys_rw_content_t') {
                $result['issues'][] = "SELinux label is '$type' — php-fpm (httpd_t) cannot write here regardless of Unix perms; needs httpd_sys_rw_content_t (see docs/SELINUX_AND_HARDENING.md / scripts/fix_moop_selinux.sh)";
                $bump('high');
            }
        }
        if (!$result['is_writable']) {
            $is_tree = moop_permission_is_data_tree($item['name']);
            $result['issues'][] = "Not writable by the web server ($web_group)"
                . ($is_tree ? ' — admin builds/renames into this tree will fail' : ' — admin saves/logging/caching here will fail');
            $bump($is_tree ? 'medium' : 'high');
        }
        if (isset($item['required_group']) && $group !== $item['required_group']) {
            $result['issues'][] = "Group is $group, should be " . $item['required_group'] . ' — new files here inherit the wrong group';
            $bump('medium');
        }
        if ($world_writable) {
            $result['issues'][] = "World-writable ($perms)";
            $bump('high');
        }
        if ($any_exec && $result['type'] !== 'directory') {
            // Same rule as the 'data' branch: directories legitimately carry the traverse (x)
            // bit, files never do. A file that is BOTH web-writable and executable is strictly
            // worse than a read-only one, so this matters more here, not less.
            $result['issues'][] = "Marked executable ($perms) — data files should not be executable";
            $bump('medium');
        }
    }

    $result['severity'] = empty($result['issues']) ? 'low' : $sev;
    return $result;
}

functions.comment:
/**
* Run every permission check and return the full result set.
*
* @return array{
*   checks: array, assembly_subdir_issues: array, fasta_file_issues: array,
*   web_user: string, web_group: string, moop_owner: string, organism_data: string
* }
*/

functions.code:
function moop_collect_permission_checks($config): array {
    $organism_data        = $config->getPath('organism_data');
    $metadata_path        = $config->getPath('metadata_path');
    $cache_path           = $config->getPath('cache_path'); // empty = caches live in organisms/
    $absolute_images_path = $config->getPath('absolute_images_path');
    $site_path            = $config->getPath('site_path');
    $docs_path            = $config->getPath('docs_path');

    $webserver = getWebServerUser();
    $web_user  = $webserver['user'];
    $web_group = $webserver['group'];
    $moop_owner = getMoopOwner();

    $permission_items = moop_build_permission_items($config, [
        'web_group'            => $web_group,
        'moop_owner'           => $moop_owner,
        'metadata_path'        => $metadata_path,
        'organism_data'        => $organism_data,
        'cache_path'           => $cache_path,
        'site_path'            => $site_path,
        'absolute_images_path' => $absolute_images_path,
        'docs_path'            => $docs_path,
    ]);

    // Paths that carry their own writable rule. The read-only evidence scan must not
    // descend into them: images/wikimedia sits under images/, and flagging the parent for
    // its own cache subdir would be a false alarm.
    $writable_paths = [];
    foreach ($permission_items as $item) {
        if (moop_permission_check_mode($item['name']) !== 'writable') continue;
        foreach ($item['paths'] ?? [] as $p) {
            $writable_paths[] = rtrim($p, '/');
        }
    }

    // Check permissions for each fixed item
    $checks = [];
    foreach ($permission_items as $item) {
        // Consumed by the read-only evidence scan in performPermissionCheck().
        $item['_web_user']   = $web_user;
        $item['prune_paths'] = $writable_paths;

        if ($item['type'] === 'directory' || ($item['type'] === 'file' && !isset($item['pattern']))) {
            foreach ($item['paths'] ?? [] as $path) {
                $checks[] = performPermissionCheck($path, $item, $web_group);
            }
        } elseif ($item['type'] === 'file_pattern' && !empty($item['pattern'])) {
            // Glob-expanded rules (organism.json, organism.sqlite). Until 2026-07-16 this
            // branch did not exist, so both rules were declared but never actually ran —
            // organism.json writability and DB readability went unverified.
            foreach (glob($item['pattern']) as $path) {
                $checks[] = performPermissionCheck($path, $item, $web_group);
            }
        }
    }

    // ── Executable data files, ANY extension ─────────────────────────────────────────
    //
    // Ask the filesystem instead of a pattern list. The per-file rules below enumerate
    // *.fa, organism.json and organism.sqlite — a hand-maintained second copy of "what
    // files live here", which cannot know about a type nobody added to it. BLAST index
    // files (.nsq/.nin/.nhr/.pto/...) were never in that list, so 234 executable ones sat
    // invisible on this box (2026-07-16) while the checker reported clean.
    //
    // It matters for the realistic workflow: an admin scp's in a new organism with
    // pre-built BLAST databases, and whatever modes the source had come with it. A pattern
    // list will never cover that; a sweep does. ~9ms over the whole tree.
    $exec_file_issues = [];
    if (is_dir($organism_data)) {
        $found = [];
        @exec('find ' . escapeshellarg($organism_data) . ' -type f -perm /111 -print 2>/dev/null', $found);
        foreach ($found as $path) {
            $path = trim($path);
            if ($path === '') continue;
            $exec_file_issues[] = [
                'name'           => 'Executable Data Files',
                'path'           => $path,
                'type'           => 'file',
                'check_mode'     => 'data',
                'exists'         => true,
                'current_perms'  => substr(sprintf('%o', @fileperms($path)), -4),
                'current_owner'  => '',
                'current_group'  => '',
                'is_readable'    => true,
                'is_writable'    => false,
                'severity'       => 'medium',
                'required_group' => $web_group,
                'reason'         => 'Data files are read by BLAST and the app; nothing executes them.',
                'issues'         => ['Marked executable — data files should never carry the execute bit'
                                     . ' (commonly from a recursive chmod, or copied in with the bit already set)'],
            ];
        }
    }

    // Check assembly subdirectories and FASTA files
    $assembly_subdir_issues = [];
    $fasta_file_issues = [];
    if (is_dir($organism_data)) {
        foreach (scandir($organism_data) as $organism) {
            if ($organism !== '.' && $organism !== '..' && is_dir($organism_data . '/' . $organism)) {
                $org_path = $organism_data . '/' . $organism;

                // Check organism subdirectory itself
                $check = performPermissionCheck($org_path, [
                    'name' => 'Organism Directory',
                    'type' => 'directory',
                    'required_perms' => '2775',
                    'required_group' => $web_group,
                    'reason' => 'SGID required for assembly rename operations',
                    'why_write' => 'Web server needs to rename/move assembly subdirectories',
                ], $web_group);

                if (!empty($check['issues'])) {
                    $assembly_subdir_issues[] = $check;
                }

                // Check assembly subdirectories and FASTA files
                foreach (scandir($org_path) as $item) {
                    $item_path = $org_path . '/' . $item;

                    // Skip dots and files
                    if ($item === '.' || $item === '..') {
                        continue;
                    }

                    if (is_dir($item_path)) {
                        // Check assembly subdirectory
                        $check = performPermissionCheck($item_path, [
                            'name' => 'Assembly Subdirectory: ' . $organism . '/' . $item,
                            'type' => 'directory',
                            'required_perms' => '2775',
                            'required_group' => $web_group,
                            'reason' => 'Web server needs write access to rename gene set subdirectories within this assembly dir',
                            'why_write' => 'Gene set rename operations require group-write on the parent assembly directory',
                        ], $web_group);

                        if (!empty($check['issues'])) {
                            $assembly_subdir_issues[] = $check;
                        }

                        // Check gene_set subdirectories and their FASTA files
                        $sequence_types = $config->getSequenceTypes();
                        foreach (scandir($item_path) as $gs_item) {
                            $gs_path = $item_path . '/' . $gs_item;
                            if ($gs_item === '.' || $gs_item === '..') {
                                continue;
                            }

                            if (is_dir($gs_path)) {
                                // Check gene_set subdirectory
                                $check = performPermissionCheck($gs_path, [
                                    'name' => 'Gene Set Subdirectory: ' . $organism . '/' . $item . '/' . $gs_item,
                                    'type' => 'directory',
                                    'required_perms' => '2775',
                                    'required_group' => $web_group,
                                    'reason' => 'Web server needs to write BLAST index files into gene set directories',
                                    'why_write' => 'BLAST indexes (.nhr, .nin, .nsq, .phr, .pin, .psq) must be writable by web server',
                                ], $web_group);

                                if (!empty($check['issues'])) {
                                    $assembly_subdir_issues[] = $check;
                                }

                                // Check FASTA files in gene_set directory
                                foreach ($sequence_types as $seq_type => $seq_config) {
                                    $pattern = $seq_config['pattern'] ?? '';
                                    if (empty($pattern)) {
                                        continue;
                                    }
                                    $expected_file = basename($pattern);
                                    $fasta_path = $gs_path . '/' . $expected_file;
                                    if (file_exists($fasta_path)) {
                                        $check = performPermissionCheck($fasta_path, [
                                            'name' => 'FASTA File: ' . $organism . '/' . $item . '/' . $gs_item . '/' . $expected_file,
                                            'type' => 'file',
                                            'required_perms' => '644',
                                            'required_group' => $web_group,
                                            'reason' => ucfirst($seq_type) . ' file must be readable by web server for BLAST',
                                            'why_write' => 'Web server reads ' . $seq_type . ' files to run BLAST searches',
                                        ], $web_group);
                                        if (!empty($check['issues'])) {
                                            $fasta_file_issues[] = $check;
                                        }
                                    }
                                }
                            } else {
                                // Files at assembly level (genome.fa, genome.fa.fai) — check genome type only
                                foreach ($sequence_types as $seq_type => $seq_config) {
                                    $pattern = $seq_config['pattern'] ?? '';
                                    if (empty($pattern)) {
                                        continue;
                                    }
                                    $expected_file = basename($pattern);
                                    if ($gs_item === $expected_file && file_exists($gs_path)) {
                                        $check = performPermissionCheck($gs_path, [
                                            'name' => 'FASTA File: ' . $organism . '/' . $item . '/' . $gs_item,
                                            'type' => 'file',
                                            'required_perms' => '644',
                                            'required_group' => $web_group,
                                            'reason' => ucfirst($seq_type) . ' file must be readable by web server',
                                            'why_write' => 'Web server reads ' . $seq_type . ' files for JBrowse2 and sequence views',
                                        ], $web_group);
                                        if (!empty($check['issues'])) {
                                            $fasta_file_issues[] = $check;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    return [
        'checks'                 => $checks,
        'assembly_subdir_issues' => $assembly_subdir_issues,
        'fasta_file_issues'      => $fasta_file_issues,
        'exec_file_issues'       => $exec_file_issues,
        'web_user'               => $web_user,
        'web_group'              => $web_group,
        'moop_owner'             => $moop_owner,
        'organism_data'          => $organism_data,
    ];
}

function moop_permission_findings($config, ?array $collected = null): array {
    if ($collected === null) {
        $collected = moop_collect_permission_checks($config);
    }
    $all = array_merge(
        $collected['checks'],
        $collected['assembly_subdir_issues'],
        $collected['fasta_file_issues'],
        $collected['exec_file_issues'] ?? []
    );
    $rank = ['low' => 1, 'medium' => 2, 'high' => 3];
    $cats = [];
    foreach ($all as $c) {
        if (empty($c['issues'])) continue;
        $cat = $c['category'] ?? $c['name'];
        if (!isset($cats[$cat])) {
            $cats[$cat] = ['category' => $cat, 'severity' => 'low', 'count' => 0, 'reasons' => [], 'example' => null];
        }
        $cats[$cat]['count']++;
        $s = $c['severity'] ?? 'medium';
        if (!isset($rank[$s])) $s = 'medium';
        if ($rank[$s] > $rank[$cats[$cat]['severity']]) $cats[$cat]['severity'] = $s;
        foreach ($c['issues'] as $iss) $cats[$cat]['reasons'][$iss] = true;
        if ($cats[$cat]['example'] === null) $cats[$cat]['example'] = $c['path'] ?? null;
    }
    $findings = [];
    foreach ($cats as $d) {
        $d['reasons'] = array_keys($d['reasons']);
        $findings[] = $d;
    }
    usort($findings, fn($a, $b) => ($rank[$b['severity']] <=> $rank[$a['severity']]) ?: ($b['count'] <=> $a['count']));
    return $findings;
}

functions.comment:
/**
* Compact summary for the dashboard pointer card — built from CATEGORY findings, not
* raw file counts. high/medium/low are how many *areas* (findings) sit at each severity;
* affected_files is the underlying path total if it's ever wanted. See §N.
*
* @return array{findings:array, finding_count:int, high:int, medium:int, low:int, affected_files:int, worst:?string, checked_at:string}
*/

functions.code:
function moop_permission_issue_summary($config, ?array $collected = null): array {
    if ($collected === null) {
        $collected = moop_collect_permission_checks($config);
    }
    $findings = moop_permission_findings($config, $collected);
    $sev = ['high' => 0, 'medium' => 0, 'low' => 0];
    $affected = 0;
    foreach ($findings as $f) {
        $sev[$f['severity']]++;
        $affected += $f['count'];
    }
    $worst = $sev['high'] > 0 ? 'high' : ($sev['medium'] > 0 ? 'medium' : ($sev['low'] > 0 ? 'low' : null));
    return [
        'findings'       => $findings,
        'finding_count'  => count($findings),
        'high'           => $sev['high'],
        'medium'         => $sev['medium'],
        'low'            => $sev['low'],
        'affected_files' => $affected,
        'worst'          => $worst,
        'checked_at'     => date('Y-m-d H:i:s'),
    ];
}

function fetch_taxonomy_lineage($taxon_id, $max_retries = 3) {
    $url = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?db=taxonomy&id={$taxon_id}&retmode=xml";

    $attempt  = 0;
    $response = false;

    while ($attempt < $max_retries && $response === false) {
        $ch = curl_init($url);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT        => 15,
            CURLOPT_USERAGENT      => 'MOOP/1.0 Taxonomy Tree Generator',
        ]);
        $result = curl_exec($ch);
        $err    = curl_errno($ch);
        curl_close($ch);

        if ($result !== false && !$err) {
            $response = $result;
        } else {
            $attempt++;
            if ($attempt < $max_retries) {
                usleep(1000000 * (int)pow(2, $attempt - 1));
            }
        }
    }

    if ($response === false) {
        error_log("NCBI taxonomy fetch failed for taxon_id {$taxon_id} after {$max_retries} attempts");
        return null;
    }

    // Parse XML using regex since SimpleXML isn't always available
    $lineage = [];

    // Extract Lineage text (semicolon-separated)
    if (preg_match('/<Lineage>(.+?)<\/Lineage>/s', $response, $matches)) {
        $lineage_text = trim($matches[1]);
        $lineage_parts = array_filter(array_map('trim', explode(';', $lineage_text)));

        // Extract ranks from LineageEx
        $rank_map = [];
        if (preg_match_all('/<Taxon>.*?<ScientificName>(.+?)<\/ScientificName>.*?<Rank>(.+?)<\/Rank>.*?<\/Taxon>/s', $response, $matches, PREG_SET_ORDER)) {
            foreach ($matches as $match) {
                $sci_name = trim($match[1]);
                $rank = trim($match[2]);
                $rank_map[$sci_name] = $rank;
            }
        }

        // Build lineage array with matched ranks
        $valid_ranks = ['superkingdom', 'kingdom', 'phylum', 'class', 'order', 'family', 'genus'];
        foreach ($lineage_parts as $name) {
            $rank = $rank_map[$name] ?? null;

            // Map domain to superkingdom
            if ($rank === 'domain') {
                $rank = 'superkingdom';
            }

            // Only include standard taxonomic ranks (skip intermediate ranks like 'clade')
            if ($rank && in_array($rank, $valid_ranks)) {
                $lineage[] = [
                    'rank' => $rank,
                    'name' => $name
                ];
            }
        }
    }

    // Add the species itself
    if (preg_match('/<ScientificName>(.+?)<\/ScientificName>/', $response, $matches)) {
        $sci_name = trim($matches[1]);
        // Only add if it's not already in lineage
        if (empty($lineage) || $lineage[count($lineage)-1]['name'] !== $sci_name) {
            $lineage[] = [
                'rank' => 'species',
                'name' => $sci_name
            ];
        }
    }

    return !empty($lineage) ? $lineage : null;
}

function ncbi_load_local_dump_meta($metadata_path) {
    $f = "$metadata_path/.ncbi_taxonomy_meta.json";
    if (!file_exists($f)) return [];
    return loadJsonFile($f, []);
}

function ncbi_save_local_dump_meta($metadata_path, array $meta) {
    $f = "$metadata_path/.ncbi_taxonomy_meta.json";
    @file_put_contents($f, json_encode($meta, JSON_PRETTY_PRINT));
    @chmod($f, 0664);
}

function ncbi_fetch_remote_md5($md5_url) {
    $ch = curl_init($md5_url);
    curl_setopt_array($ch, [
        CURLOPT_RETURNTRANSFER => true,
        CURLOPT_CONNECTTIMEOUT => 5,
        CURLOPT_TIMEOUT        => 5,
        CURLOPT_USERAGENT      => 'MOOP/1.0 Taxonomy Sync',
    ]);
    $body = curl_exec($ch);
    $err  = curl_errno($ch);
    $http = curl_getinfo($ch, CURLINFO_HTTP_CODE);
    curl_close($ch);

    if ($err || $http !== 200 || !$body) return null;
    // File format: "<md5hash>  new_taxdump.tar.gz\n"
    $parts = preg_split('/\s+/', trim($body));
    return (!empty($parts[0]) && strlen($parts[0]) === 32) ? $parts[0] : null;
}

function ncbi_scan_local_dump(array $taxid_set, string $stored_gz): array {
    if (!file_exists($stored_gz) || empty($taxid_set)) return [];

    $rank_fields = [
        'superkingdom' => 9, 'kingdom' => 8, 'phylum' => 7,
        'class'        => 6, 'order'   => 5, 'family' => 4,
        'genus'        => 3, 'species' => 1,
    ];

    $results = [];
    $needed  = $taxid_set;

    $gz = gzopen($stored_gz, 'r');
    if (!$gz) return [];

    while (!empty($needed) && ($line = gzgets($gz)) !== false) {
        $tab = strpos($line, "\t");
        if ($tab === false) continue;
        $tid = substr($line, 0, $tab);
        if (!isset($needed[$tid])) continue;

        $stripped = rtrim($line, "\r\n");
        if (substr($stripped, -2) === "\t|") $stripped = substr($stripped, 0, -2);
        $parts   = explode("\t|\t", $stripped);
        $lineage = [];
        foreach ($rank_fields as $rank => $idx) {
            $name = isset($parts[$idx]) ? trim($parts[$idx]) : '';
            if ($name !== '') $lineage[] = ['rank' => $rank, 'name' => $name];
        }
        if (!empty($lineage)) {
            $results[$tid] = [
                'lineage' => $lineage,
                'image'   => null,
                'fetched' => date('Y-m-d'),
                'source'  => 'ncbi_dump',
            ];
        }
        unset($needed[$tid]);
    }
    gzclose($gz);

    return $results;
}

function load_lineage_cache($metadata_path) {
    $cache_file = "$metadata_path/taxonomy_lineage_cache.json";
    if (!file_exists($cache_file)) return [];
    $data = loadJsonFile($cache_file, []);
    if (!is_array($data)) return [];
    unset($data['generated']);
    return $data;
}

functions.comment:
/**
* Persist the taxonomy lineage cache to disk.
*/

functions.code:
function save_lineage_cache($lineage_cache, $metadata_path) {
    $cache_file = "$metadata_path/taxonomy_lineage_cache.json";
    $data = $lineage_cache;
    ksort($data);
    $data['generated'] = date('Y-m-d H:i:s');
    if (@file_put_contents($cache_file, json_encode($data, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES)) !== false) {
        @chmod($cache_file, 0664);
        return true;
    }
    return false;
}

function refresh_lineage_cache($organisms, $lineage_cache, $progress_cb = null) {
    $to_fetch = [];
    foreach ($organisms as $org_name => $data) {
        if (empty($data['taxon_id'])) continue;
        $tid = (string)$data['taxon_id'];
        if (!isset($lineage_cache[$tid])) {
            $to_fetch[$org_name] = $data;
        }
    }

    if (empty($to_fetch)) return $lineage_cache;

    $config    = ConfigManager::getInstance();
    $stored_gz = $config->getPath('metadata_path') . '/ncbi_rankedlineage.dmp.gz';

    if (!file_exists($stored_gz)) {
        $missing = implode(', ', array_keys($to_fetch));
        error_log("refresh_lineage_cache: local NCBI dump not found at $stored_gz. "
            . "Run scripts/sync_ncbi_taxonomy_dump.php to download it. "
            . "Skipped organisms: $missing");
        return $lineage_cache;
    }

    $taxid_set = [];
    foreach ($to_fetch as $data) {
        if (!empty($data['taxon_id'])) $taxid_set[(string)$data['taxon_id']] = true;
    }

    $from_dump = ncbi_scan_local_dump($taxid_set, $stored_gz);
    foreach ($from_dump as $tid => $entry) {
        $lineage_cache[$tid] = $entry;
    }

    // Report any taxon_ids that weren't found in the dump (dump may be stale)
    $still_missing = [];
    foreach ($to_fetch as $org_name => $data) {
        if (!isset($lineage_cache[(string)$data['taxon_id']])) {
            $still_missing[] = "$org_name (taxon_id={$data['taxon_id']})";
        }
    }
    if (!empty($still_missing)) {
        error_log("refresh_lineage_cache: " . count($still_missing) . " taxon_id(s) not found in local dump — "
            . "dump may be stale. Re-run scripts/sync_ncbi_taxonomy_dump.php. "
            . "Missing: " . implode(', ', $still_missing));
    }

    return $lineage_cache;
}

function build_tree_from_lineage_cache($organisms, $lineage_cache) {
    $tree = ['name' => 'Life', 'children' => []];

    foreach ($organisms as $org_name => $data) {
        if (empty($data['taxon_id'])) continue;
        $tid = (string)$data['taxon_id'];
        if (!isset($lineage_cache[$tid])) continue;

        $cached  = $lineage_cache[$tid];
        $current = &$tree;

        foreach ($cached['lineage'] as $level) {
            $name = $level['name'];
            $rank = $level['rank'];

            $found = false;
            foreach ($current['children'] as &$child) {
                if ($child['name'] === $name) {
                    $current = &$child;
                    $found = true;
                    break;
                }
            }
            unset($child);

            if (!$found) {
                $node = ['name' => $name];
                if ($rank === 'species') {
                    $node['organism']    = $org_name;
                    $node['common_name'] = $data['common_name'] ?? '';
                    if (!empty($cached['image'])) $node['image'] = $cached['image'];
                } else {
                    $node['children'] = [];
                }
                $current['children'][] = $node;
                $current = &$current['children'][count($current['children']) - 1];
            }
        }
        unset($current);
    }

    return ['tree' => $tree];
}

function build_tree_from_organisms($organisms, $force_refetch = false) {
    $config       = ConfigManager::getInstance();
    $metadata_path = $config->getPath('metadata_path');

    $lineage_cache = $force_refetch ? [] : load_lineage_cache($metadata_path);
    $lineage_cache = refresh_lineage_cache($organisms, $lineage_cache);

    save_lineage_cache($lineage_cache, $metadata_path);

    return build_tree_from_lineage_cache($organisms, $lineage_cache);
}

function getWikipediaTaxonomyData($rank_name) {
    $result = [
        'description' => '',
        'image_url' => '',
        'wikipedia_url' => '',
        'source' => 'Wikipedia'
    ];

    if (empty($rank_name)) {
        return $result;
    }

    // Use Wikipedia API to search for the taxonomic rank
    $wiki_search_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
        'action' => 'query',
        'titles' => $rank_name,
        'format' => 'json',
        'prop' => 'extracts|pageimages|info',
        'exlimit' => 1,
        'exintro' => true,
        'explaintext' => true,
        'piprop' => 'thumbnail|original',
        'pithumbsize' => 300,
        'redirects' => true
    ]);

    $response = moop_curl_get($wiki_search_url);

    if ($response === false) {
        return $result;
    }

    $data = json_decode($response, true);

    if (empty($data['query']['pages'])) {
        return $result;
    }

    // Get first (and usually only) page result
    $pages = array_values($data['query']['pages']);
    $page = $pages[0];

    if (!isset($page['pageid'])) {
        // Page not found, try search instead
        return getWikipediaTaxonomyDataFromSearch($rank_name);
    }

    // Determine the actual title (in case of redirects)
    $actual_title = $page['title'] ?? $rank_name;

    // Get the page URL
    $result['wikipedia_url'] = 'https://en.wikipedia.org/wiki/' . str_replace(' ', '_', $actual_title);

    // Extract description from intro
    if (!empty($page['extract'])) {
        $description = $page['extract'];
        // Truncate if too long
        if (strlen($description) > 500) {
            $description = substr($description, 0, 500) . '...';
        }
        $result['description'] = trim($description);
    }

    // Extract image (try thumbnail first, then original)
    if (!empty($page['thumbnail']['source'])) {
        $result['image_url'] = $page['thumbnail']['source'];
    } elseif (!empty($page['original']['source'])) {
        $result['image_url'] = $page['original']['source'];
    }

    return $result;
}

function getWikipediaTaxonomyDataFromSearch($rank_name) {
    $result = [
        'description' => '',
        'image_url' => '',
        'wikipedia_url' => '',
        'source' => 'Wikipedia'
    ];

    // Search for the term
    $search_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
        'action' => 'query',
        'list' => 'search',
        'srsearch' => $rank_name,
        'format' => 'json',
        'srlimit' => 3
    ]);

    $response = moop_curl_get($search_url);

    if ($response === false) {
        return $result;
    }

    $data = json_decode($response, true);

    if (empty($data['query']['search'])) {
        return $result;
    }

    // Try the first few results to find one with content
    foreach ($data['query']['search'] as $search_result) {
        $found_title = $search_result['title'];

        // Fetch details about this page
        $fetch_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
            'action' => 'query',
            'titles' => $found_title,
            'format' => 'json',
            'prop' => 'extracts|pageimages',
            'exintro' => true,
            'explaintext' => true,
            'piprop' => 'thumbnail|original',
            'pithumbsize' => 300,
            'redirects' => true
        ]);

        $response = moop_curl_get($fetch_url);

        if ($response === false) {
            continue;
        }

        $data = json_decode($response, true);

        if (empty($data['query']['pages'])) {
            continue;
        }

        $pages = array_values($data['query']['pages']);
        $page = $pages[0];

        // Skip if no content
        if (empty($page['extract'])) {
            continue;
        }

        if (!empty($page['extract'])) {
            $description = $page['extract'];
            if (strlen($description) > 500) {
                $description = substr($description, 0, 500) . '...';
            }
            $result['description'] = trim($description);
        }

        if (!empty($page['thumbnail']['source'])) {
            $result['image_url'] = $page['thumbnail']['source'];
        } elseif (!empty($page['original']['source'])) {
            $result['image_url'] = $page['original']['source'];
        }

        $result['wikipedia_url'] = 'https://en.wikipedia.org/wiki/' . str_replace(' ', '_', $page['title']);

        // Found a good result, return it
        return $result;
    }

    return $result;
}

function getWikipediaOrganismData($organism_name, $scientific_name = '') {
    $result = [
        'description' => '',
        'image_url' => '',
        'wikipedia_url' => '',
        'source' => 'Wikipedia'
    ];

    if (empty($organism_name) && empty($scientific_name)) {
        return $result;
    }

    // Try scientific name first, then common name
    $names_to_try = array_filter([
        $scientific_name,
        $organism_name,
        // Also try common name without underscores
        str_replace('_', ' ', $organism_name)
    ]);

    foreach ($names_to_try as $search_name) {
        $wiki_search_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
            'action' => 'query',
            'titles' => $search_name,
            'format' => 'json',
            'prop' => 'extracts|pageimages|info',
            'exlimit' => 1,
            'exintro' => true,
            'explaintext' => true,
            'piprop' => 'thumbnail|original',
            'pithumbsize' => 400,
            'redirects' => true
        ]);

        $response = moop_curl_get($wiki_search_url);

        if ($response === false) {
            continue;
        }

        $data = json_decode($response, true);

        if (empty($data['query']['pages'])) {
            continue;
        }

        $pages = array_values($data['query']['pages']);
        $page = $pages[0];

        if (!isset($page['pageid']) || empty($page['extract'])) {
            continue;
        }

        // Found good data, return it
        $actual_title = $page['title'] ?? $search_name;
        $result['wikipedia_url'] = 'https://en.wikipedia.org/wiki/' . str_replace(' ', '_', $actual_title);

        if (!empty($page['extract'])) {
            $description = $page['extract'];
            if (strlen($description) > 500) {
                $description = substr($description, 0, 500) . '...';
            }
            $result['description'] = trim($description);
        }

        if (!empty($page['thumbnail']['source'])) {
            $result['image_url'] = $page['thumbnail']['source'];
        } elseif (!empty($page['original']['source'])) {
            $result['image_url'] = $page['original']['source'];
        }

        return $result;
    }

    // If direct search failed, try Wikipedia search API as fallback
    return getWikipediaOrganismDataFromSearch($organism_name);
}

function getWikipediaOrganismDataFromSearch($organism_name) {
    $result = [
        'description' => '',
        'image_url' => '',
        'wikipedia_url' => '',
        'source' => 'Wikipedia'
    ];

    // Search for the organism
    $search_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
        'action' => 'query',
        'list' => 'search',
        'srsearch' => str_replace('_', ' ', $organism_name) . ' species animal',
        'format' => 'json',
        'srlimit' => 3
    ]);

    $response = moop_curl_get($search_url);

    if ($response === false) {
        return $result;
    }

    $data = json_decode($response, true);

    if (empty($data['query']['search'])) {
        return $result;
    }

    // Try the first few results
    foreach ($data['query']['search'] as $search_result) {
        $found_title = $search_result['title'];

        // Fetch details about this page
        $fetch_url = 'https://en.wikipedia.org/w/api.php?' . http_build_query([
            'action' => 'query',
            'titles' => $found_title,
            'format' => 'json',
            'prop' => 'extracts|pageimages',
            'exintro' => true,
            'explaintext' => true,
            'piprop' => 'thumbnail|original',
            'pithumbsize' => 400,
            'redirects' => true
        ]);

        $response = moop_curl_get($fetch_url);

        if ($response === false) {
            continue;
        }

        $data = json_decode($response, true);

        if (empty($data['query']['pages'])) {
            continue;
        }

        $pages = array_values($data['query']['pages']);
        $page = $pages[0];

        // Skip if no extract
        if (empty($page['extract'])) {
            continue;
        }

        // Reject results whose title shares no words with the organism name —
        // prevents generic pages like "Largest and heaviest animals" from matching.
        $result_title_lower = strtolower($page['title'] ?? '');
        $name_words = preg_split('/[\s_]+/', strtolower(str_replace('_', ' ', $organism_name)));
        $name_words = array_filter($name_words, fn($w) => strlen($w) > 3); // skip short words
        $title_matches = false;
        foreach ($name_words as $word) {
            if (strpos($result_title_lower, $word) !== false) {
                $title_matches = true;
                break;
            }
        }
        if (!$title_matches) {
            continue;
        }

        $description = $page['extract'];
        if (strlen($description) > 500) {
            $description = substr($description, 0, 500) . '...';
        }
        $result['description'] = trim($description);

        if (!empty($page['thumbnail']['source'])) {
            $result['image_url'] = $page['thumbnail']['source'];
        } elseif (!empty($page['original']['source'])) {
            $result['image_url'] = $page['original']['source'];
        }

        $result['wikipedia_url'] = 'https://en.wikipedia.org/wiki/' . str_replace(' ', '_', $page['title']);

        return $result;
    }

    return $result;
}

function getPasswordInput() {
    if (PHP_OS_FAMILY === 'Windows') {
        // Windows doesn't support stty, so we echo the input
        $handle = fopen('php://stdin', 'r');
        $password = trim(fgets($handle));
        fclose($handle);
        echo "\n";
        return $password;
    } else {
        // Unix/Linux: disable terminal echo
        system('stty -echo');
        $handle = fopen('php://stdin', 'r');
        $password = trim(fgets($handle));
        fclose($handle);
        system('stty echo');
        echo "\n";
        return $password;
    }
}

function pass($label) {
    global $passes;
    $passes++;
    echo "  " . C_GREEN . "[PASS]" . C_RESET . " $label\n";
}

function fail($label, $fix = '') {
    global $fails;
    $fails++;
    echo "  " . C_RED . "[FAIL]" . C_RESET . " $label\n";
    if ($fix) {
        echo "         " . C_YELLOW . "Fix: " . C_RESET . "$fix\n";
    }
}

function warn($label, $note = '') {
    global $warns;
    $warns++;
    echo "  " . C_YELLOW . "[WARN]" . C_RESET . " $label\n";
    if ($note) {
        echo "         $note\n";
    }
}

function section($title) {
    echo "
" . C_CYAN . "── $title " . str_repeat('─', max(1, 56 - strlen($title))) . C_RESET . "

";
}

function detectWebUser() {
    $user  = 'www-data';
    $group = 'www-data';

    // Look for non-root worker processes. PHP-FPM is checked first because
    // it's the process that actually runs PHP — its user is what matters for
    // file permissions, even if a different user runs the nginx/httpd frontend.
    $detect_cmds = [
        "ps -eo user,comm --no-headers | awk '\$2 ~ /php-fpm/ && \$1 != \"root\" {print \$1; exit}'",
        "ps -eo user,comm --no-headers | awk '\$2 ~ /apache2|httpd/ && \$1 != \"root\" {print \$1; exit}'",
        "ps -eo user,comm --no-headers | awk '\$2 ~ /nginx/ && \$1 != \"root\" {print \$1; exit}'",
    ];

    foreach ($detect_cmds as $cmd) {
        $output = [];
        @exec($cmd, $output);
        $detected = trim($output[0] ?? '');
        if (!empty($detected)) {
            $user = $detected;
            // Resolve primary group for this user
            if (function_exists('posix_getpwnam')) {
                $pwinfo = posix_getpwnam($user);
                if ($pwinfo !== false) {
                    $grinfo = posix_getgrgid($pwinfo['gid']);
                    if ($grinfo !== false) {
                        $group = $grinfo['name'];
                    }
                }
            } else {
                // Fallback without posix: parse `id` command output
                $id_output = [];
                @exec("id " . escapeshellarg($user) . " 2>/dev/null", $id_output);
                if (!empty($id_output[0]) && preg_match('/gid=\d+\(([^)]+)\)/', $id_output[0], $m)) {
                    $group = $m[1];
                }
            }
            break;
        }
    }

    return ['user' => $user, 'group' => $group];
}

function detectWebServer() {
    static $flavor = null;
    if ($flavor !== null) return $flavor;

    $out = [];
    @exec("ps -eo comm --no-headers 2>/dev/null | sort -u", $out);
    $procs = implode(' ', $out);
    if (preg_match('/\bnginx\b/', $procs))          return $flavor = 'nginx';
    if (preg_match('/\b(apache2|httpd)\b/', $procs)) return $flavor = 'apache';

    // Nothing running (fresh install, or checking before starting the server).
    if (is_dir('/etc/nginx'))                        return $flavor = 'nginx';
    if (is_dir('/etc/httpd') || is_dir('/etc/apache2')) return $flavor = 'apache';
    return $flavor = 'unknown';
}

function webUserIds($web_user, $web_group) {
    static $ids = null;
    if ($ids !== null) return $ids;

    $uid = $gid = null;
    if (function_exists('posix_getpwnam')) {
        $p = @posix_getpwnam($web_user);
        if (is_array($p)) $uid = (int) $p['uid'];
        $g = @posix_getgrnam($web_group);
        if (is_array($g)) $gid = (int) $g['gid'];
    }
    if ($uid === null) {
        $o = [];
        @exec('id -u ' . escapeshellarg($web_user) . ' 2>/dev/null', $o);
        if (!empty($o[0]) && ctype_digit(trim($o[0]))) $uid = (int) trim($o[0]);
    }
    if ($gid === null) {
        $o = [];
        @exec('getent group ' . escapeshellarg($web_group) . ' 2>/dev/null', $o);
        if (!empty($o[0])) {
            $parts = explode(':', $o[0]);
            if (isset($parts[2]) && ctype_digit($parts[2])) $gid = (int) $parts[2];
        }
    }
    return $ids = ['uid' => $uid, 'gid' => $gid];
}

function webCanWrite($path, $web_user, $web_group) {
    $st = @stat($path);
    if ($st === false) return false;

    $mode = $st['mode'];
    $ids  = webUserIds($web_user, $web_group);

    if ($ids['uid'] !== null && $st['uid'] === $ids['uid'] && ($mode & 0200)) return true; // owner
    if ($ids['gid'] !== null && $st['gid'] === $ids['gid'] && ($mode & 0020)) return true; // group
    if ($mode & 0002) return true;                                                         // world
    // Ids unresolvable (no posix, no id/getent): fall back rather than cry wolf.
    if ($ids['uid'] === null && $ids['gid'] === null) return is_writable($path);
    return false;
}

function toolExists($tool) {
    $output = [];
    $ret = 1;
    @exec("which " . escapeshellarg($tool) . " 2>/dev/null", $output, $ret);
    return $ret === 0;
}

function getWebUser() {
    $user  = 'www-data';
    $group = 'www-data';

    if (function_exists('posix_getuid')) {
        $pwinfo = posix_getpwuid(posix_getuid());
        if ($pwinfo !== false) {
            $user = $pwinfo['name'];
        }
        $grinfo = posix_getgrgid(posix_getgid());
        if ($grinfo !== false) {
            $group = $grinfo['name'];
        }
    } else {
        // Fallback without posix: parse `id` command output
        $id_output = [];
        @exec("id 2>/dev/null", $id_output);
        if (!empty($id_output[0])) {
            if (preg_match('/uid=\d+\(([^)]+)\)/', $id_output[0], $m)) {
                $user = $m[1];
            }
            if (preg_match('/gid=\d+\(([^)]+)\)/', $id_output[0], $m)) {
                $group = $m[1];
            }
        }
    }

    return ['user' => $user, 'group' => $group];
}

function toolExists($tool) {
    $output = [];
    $ret = 1;
    @exec("which " . escapeshellarg($tool) . " 2>/dev/null", $output, $ret);
    return $ret === 0;
}

