        // Add PHP files that include this JS file
        if (isset($phpFilesByJsFile[$jsFile])) {
            $func['phpFilesCount'] = count($phpFilesByJsFile[$jsFile]);
            $func['phpFiles'] = $phpFilesByJsFile[$jsFile];
